window.EXAM_QUESTIONS = [{"id": 1, "domain": "primary_care_medicine", "question": "A 52-year-old man has a blood pressure of 148/92 mmHg confirmed on two separate visits. He has no other medical conditions and takes no medications. According to current ACC/AHA guidelines, which classification best describes his blood pressure?", "options": {"A": "Normal blood pressure requiring no intervention at this time.", "B": "Elevated blood pressure requiring lifestyle modifications only.", "C": "Stage 1 hypertension requiring lifestyle modification with possible medication.", "D": "Stage 2 hypertension requiring immediate antihypertensive therapy."}, "correct": "D", "explanation": "Stage 2 hypertension is defined by the ACC/AHA as a systolic blood pressure of 140 mmHg or higher or diastolic of 90 mmHg or higher, confirmed on two separate visits, which this patient meets at 148/92 mmHg. Option A is incorrect because normal blood pressure is defined as below 120/80 mmHg, which this reading clearly exceeds. Option B is incorrect because elevated blood pressure is defined as systolic 120-129 with diastolic below 80 mmHg, and this patient's diastolic is 92 mmHg."}, {"id": 9, "domain": "primary_care_medicine", "question": "A 45-year-old man has a TSH of 0.1 mIU/L and a free T4 of 2.8 ng/dL. These laboratory values are consistent with which thyroid disorder?", "options": {"A": "Primary hypothyroidism with elevated TSH and low free T4.", "B": "Secondary hypothyroidism from pituitary failure.", "C": "Overt hyperthyroidism with suppressed TSH and elevated free T4.", "D": "Subclinical hypothyroidism with elevated TSH and normal free T4."}, "correct": "C", "explanation": "A suppressed TSH of 0.1 mIU/L combined with an elevated free T4 of 2.8 ng/dL is the classic pattern of overt hyperthyroidism, where excess thyroid hormone production suppresses pituitary TSH secretion. Option A is incorrect because primary hypothyroidism presents with elevated TSH and low free T4, the opposite pattern of this patient. Option B is incorrect because secondary hypothyroidism from pituitary failure presents with low or inappropriately normal TSH alongside low free T4."}, {"id": 10, "domain": "primary_care_medicine", "question": "A 72-year-old woman with type 2 diabetes has an estimated GFR of 28 mL/min/1.73m2. Which medication should be discontinued due to risk of lactic acidosis?", "options": {"A": "Empagliflozin, an SGLT-2 inhibitor, should be discontinued.", "B": "Sitagliptin, a DPP-4 inhibitor, should be discontinued.", "C": "Metformin, a biguanide, should be discontinued.", "D": "Glipizide, a sulfonylurea, should be discontinued."}, "correct": "C", "explanation": "Metformin is contraindicated when eGFR falls below 30 mL/min/1.73m2 and should be discontinued at eGFR below 30 due to the risk of lactic acidosis from drug accumulation in renal insufficiency. Option A is incorrect because empagliflozin loses glycemic efficacy at low GFR but does not cause lactic acidosis, and the threshold for discontinuation varies by indication. Option B is incorrect because sitagliptin can be used in CKD with dose adjustment but does not carry a risk of lactic acidosis."}, {"id": 12, "domain": "primary_care_medicine", "question": "A 58-year-old with LDL of 175 mg/dL, 10-year ASCVD risk of 12%, hypertension, and no diabetes or smoking history. Which statin intensity does ACC/AHA recommend?", "options": {"A": "No statin is needed because LDL is below the treatment threshold.", "B": "Low-intensity statin such as pravastatin 10 mg daily.", "C": "Moderate-intensity statin such as atorvastatin 10-20 mg daily.", "D": "High-intensity statin such as rosuvastatin 40 mg daily."}, "correct": "C", "explanation": "A 10-year ASCVD risk of 12% with borderline high LDL and hypertension places this patient in the intermediate-risk category, for which ACC/AHA guidelines recommend a moderate-intensity statin such as atorvastatin 10-20 mg. Option A is incorrect because a 10-year risk of 12% with elevated LDL and hypertension crosses the threshold for statin therapy recommendation. Option B is incorrect because low-intensity statins provide less than 30% LDL reduction and are not sufficient for an intermediate-risk patient with a 12% 10-year risk."}, {"id": 16, "domain": "primary_care_medicine", "question": "A 50-year-old man with type 2 diabetes has an A1c of 9.2%. According to ADA guidelines, what is the recommended A1c target for most non-pregnant adults with diabetes?", "options": {"A": "Less than 6.0% to minimize all microvascular complications.", "B": "Less than 6.5% for all adults regardless of comorbidities.", "C": "Less than 7.0% for most non-pregnant adults with diabetes.", "D": "Less than 8.0% is the universal ADA target for all patients."}, "correct": "C", "explanation": "The ADA recommends an A1c target of less than 7.0% for most non-pregnant adults with diabetes, as this level balances glycemic benefit against the risk of hypoglycemia. Option A is incorrect because a target below 6.0% is associated with increased hypoglycemia risk without clear additional benefit and is not recommended for most patients. Option B is incorrect because a target below 6.5% may be appropriate for selected patients with short disease duration and no hypoglycemia risk but is not the universal ADA target."}, {"id": 21, "domain": "primary_care_medicine", "question": "Which inhaled medication is classified as a long-acting muscarinic antagonist (LAMA) used as maintenance therapy in COPD?", "options": {"A": "Salmeterol, a long-acting beta-2 agonist for COPD maintenance.", "B": "Fluticasone, an inhaled corticosteroid for COPD exacerbations.", "C": "Ipratropium, a short-acting muscarinic antagonist for COPD.", "D": "Tiotropium, a long-acting muscarinic antagonist for COPD."}, "correct": "D", "explanation": "Tiotropium is a long-acting muscarinic antagonist used as maintenance bronchodilator therapy in COPD, working by blocking M3 muscarinic receptors to produce sustained bronchodilation over 24 hours. Option A is incorrect because salmeterol is a long-acting beta-2 agonist, not a muscarinic antagonist, and works through a different receptor mechanism. Option C is incorrect because ipratropium is a short-acting muscarinic antagonist used for acute symptom relief, not long-term maintenance therapy."}, {"id": 25, "domain": "primary_care_medicine", "question": "A 44-year-old woman has had heartburn and regurgitation for six months. Upper endoscopy reveals columnar epithelium replacing squamous epithelium in the lower esophagus. What is this finding?", "options": {"A": "Schatzki ring, a mucosal ring at the gastroesophageal junction.", "B": "Hiatal hernia, a protrusion of the stomach through the diaphragm.", "C": "Esophageal stricture from chronic acid reflux injury.", "D": "Barrett's esophagus, a premalignant metaplastic change."}, "correct": "D", "explanation": "Barrett's esophagus is a premalignant condition in which the normal squamous epithelium of the lower esophagus is replaced by columnar metaplastic epithelium as a result of chronic acid reflux injury. Option A is incorrect because a Schatzki ring is a mucosal ring at the gastroesophageal junction that causes dysphagia to solids and does not involve epithelial metaplasia. Option C is incorrect because an esophageal stricture is a narrowing of the lumen from chronic acid injury but involves fibrosis, not replacement of squamous epithelium with columnar cells."}, {"id": 26, "domain": "primary_care_medicine", "question": "A TSH of 7.2 mIU/L with a normal free T4 is found on routine labs in a 55-year-old woman with fatigue. Which condition does this laboratory pattern indicate?", "options": {"A": "Overt hypothyroidism requiring immediate levothyroxine therapy.", "B": "Subclinical hypothyroidism with borderline elevated TSH.", "C": "Euthyroid sick syndrome from a concurrent illness.", "D": "Central hypothyroidism from pituitary or hypothalamic disease."}, "correct": "B", "explanation": "A TSH of 7.2 mIU/L with a normal free T4 defines subclinical hypothyroidism, where the pituitary releases excess TSH to maintain normal circulating thyroid hormone levels. Option A is incorrect because overt hypothyroidism requires both an elevated TSH and a low free T4, and this patient's free T4 remains normal. Option C is incorrect because euthyroid sick syndrome typically presents with low or normal TSH and low T3, not an isolated elevation in TSH with normal free T4."}, {"id": 32, "domain": "primary_care_medicine", "question": "A 35-year-old man has a positive QuantiFERON-TB Gold test and a normal chest X-ray. He has no symptoms of active TB. Which treatment is recommended?", "options": {"A": "No treatment is needed because chest X-ray is normal.", "B": "Repeat QuantiFERON in 6 months to confirm the positive result.", "C": "Four-drug RIPE regimen for 6 months to treat presumed active TB.", "D": "Isoniazid for 9 months to treat latent tuberculosis infection."}, "correct": "D", "explanation": "A positive QuantiFERON-TB Gold test with a normal chest X-ray and no symptoms indicates latent tuberculosis infection, which is treated with isoniazid for 9 months to prevent progression to active disease. Option A is incorrect because a normal chest X-ray does not exclude latent TB infection, and a positive IGRA in an asymptomatic person still requires treatment to prevent future reactivation. Option C is incorrect because four-drug RIPE therapy is reserved for active tuberculosis with symptoms, positive sputum cultures, or characteristic chest X-ray findings, not latent infection."}, {"id": 36, "domain": "primary_care_medicine", "question": "Which PAD finding on ankle-brachial index testing confirms the diagnosis of peripheral artery disease in a symptomatic patient?", "options": {"A": "ABI of 1.0 to 1.4 indicating normal arterial perfusion.", "B": "ABI of 0.91 to 0.99 indicating borderline arterial disease.", "C": "ABI of 0.90 or less confirming peripheral artery disease.", "D": "ABI greater than 1.4 indicating stiff non-compressible arteries."}, "correct": "C", "explanation": "An ankle-brachial index of 0.90 or less confirms the diagnosis of peripheral artery disease by demonstrating reduced arterial pressure at the ankle relative to the brachial artery. Option A is incorrect because an ABI of 1.0 to 1.4 indicates normal arterial perfusion and does not support a diagnosis of PAD. Option B is incorrect because an ABI of 0.91 to 0.99 is considered borderline and does not meet the diagnostic threshold of 0.90 or less for PAD."}, {"id": 37, "domain": "primary_care_medicine", "question": "A 55-year-old woman with no cardiovascular risk factors has a total cholesterol of 218 mg/dL. Using pooled cohort equations, her 10-year ASCVD risk is 4.5%. What is recommended?", "options": {"A": "High-intensity statin regardless of calculated ASCVD risk score.", "B": "No follow-up needed because total cholesterol is below 240 mg/dL.", "C": "Moderate-intensity statin based solely on total cholesterol level.", "D": "Lifestyle modifications and risk factor reassessment in 4-6 years."}, "correct": "D", "explanation": "With a 10-year ASCVD risk of 4.5% in the low-risk category and no established cardiovascular disease, lifestyle modifications and risk factor reassessment in 4 to 6 years are the appropriate recommendation per ACC/AHA guidelines. Option A is incorrect because high-intensity statins are reserved for patients with established ASCVD, very high LDL levels, or 10-year risk of 20% or greater, not for patients with 4.5% risk. Option C is incorrect because a moderate-intensity statin based solely on total cholesterol level without considering ASCVD risk calculation is not how current guidelines frame treatment decisions."}, {"id": 40, "domain": "primary_care_medicine", "question": "A 58-year-old man has a resting ECG showing irregularly irregular rhythm with absent P waves. Which cardiac rhythm does this pattern most likely represent?", "options": {"A": "Sinus arrhythmia, a normal variation with respiratory cycles.", "B": "Atrial flutter with variable atrioventricular block.", "C": "Atrial fibrillation with chaotic atrial electrical activity.", "D": "Multifocal atrial tachycardia with multiple ectopic foci."}, "correct": "C", "explanation": "Atrial fibrillation produces an irregularly irregular rhythm with absent P waves on ECG due to chaotic, disorganized electrical activity from multiple ectopic foci in the atria. Option A is incorrect because sinus arrhythmia is a normal physiological variation with respiratory cycles that still shows clearly visible P waves and regular QRS morphology. Option B is incorrect because atrial flutter produces a regular sawtooth flutter pattern at about 300 bpm and typically results in a regularly irregular or regular ventricular response, not an irregularly irregular rhythm."}, {"id": 42, "domain": "primary_care_medicine", "question": "A patient with CKD stage 4 has a GFR of 22 mL/min/1.73m2. Which complication is most commonly associated with advanced CKD at this stage?", "options": {"A": "Anemia from reduced erythropoietin production by the kidneys.", "B": "Polycythemia from elevated erythropoietin in renal disease.", "C": "Hypokalemia from excessive potassium wasting by the kidneys.", "D": "Respiratory alkalosis from impaired acid-base compensation."}, "correct": "A", "explanation": "Anemia from reduced erythropoietin production by the kidneys is the most commonly associated complication of advanced CKD stage 4, because the kidneys produce the majority of erythropoietin needed for red blood cell stimulation. Option B is incorrect because polycythemia (excess red blood cells) does not occur in CKD; the opposite occurs because erythropoietin production falls with progressive kidney damage. Option C is incorrect because CKD is associated with hyperkalemia, not hypokalemia, because the failing kidney loses the ability to excrete potassium."}, {"id": 43, "domain": "primary_care_medicine", "question": "A 50-year-old woman with Crohn's disease limited to the terminal ileum has chronic diarrhea and weight loss. Which nutrient deficiency is most specifically associated with terminal ileal disease?", "options": {"A": "Iron deficiency from chronic inflammation and blood loss.", "B": "Vitamin B12 deficiency from impaired ileal absorption.", "C": "Folate deficiency from methotrexate therapy side effects.", "D": "Zinc deficiency from persistent diarrhea and malabsorption."}, "correct": "B", "explanation": "Vitamin B12 is absorbed exclusively in the terminal ileum via intrinsic factor receptors, and Crohn's disease specifically affecting the terminal ileum impairs this absorption, leading to B12 deficiency. Option A is incorrect because iron deficiency can occur in Crohn's disease from blood loss or inflammation but is not specifically linked to terminal ileal disease as the site-specific mechanism. Option C is incorrect because folate deficiency in Crohn's patients is more commonly associated with methotrexate therapy, which is a folate antagonist, rather than terminal ileal location."}, {"id": 45, "domain": "primary_care_medicine", "question": "Which feature differentiates inflammatory bowel disease from irritable bowel syndrome on laboratory evaluation?", "options": {"A": "Elevated fecal calprotectin indicating intestinal inflammation.", "B": "Elevated serum IgE from food allergy-mediated inflammation.", "C": "Low serum albumin as a universal marker of IBD severity.", "D": "Elevated amylase indicating concurrent pancreatic involvement."}, "correct": "A", "explanation": "Elevated fecal calprotectin is a marker of intestinal mucosal inflammation that is characteristically elevated in IBD but normal in IBS, making it a useful differentiating laboratory test. Option B is incorrect because elevated serum IgE is associated with allergic conditions and is not a reliable or specific differentiator between IBD and IBS. Option C is incorrect because low serum albumin reflects protein-losing enteropathy or nutritional deficiency and can be seen in severe IBD but is not a universal or specific marker for IBD versus IBS."}, {"id": 46, "domain": "primary_care_medicine", "question": "A 63-year-old man with HTN, hyperlipidemia, and type 2 diabetes takes atorvastatin. His LDL is 112 mg/dL. His ASCVD risk is 18%. Which management step is most appropriate?", "options": {"A": "Continue current statin dose because LDL is below 130 mg/dL.", "B": "Discontinue statin and use fibrate for comprehensive lipid control.", "C": "Switch to a low-intensity statin to reduce adverse effects.", "D": "Add ezetimibe to further reduce LDL and cardiovascular risk."}, "correct": "D", "explanation": "Adding ezetimibe to statin therapy is the recommended next step when LDL remains above goal in a high-ASCVD-risk patient, as ezetimibe reduces cholesterol absorption and provides additional LDL lowering of approximately 15 to 20%. Option A is incorrect because an LDL of 112 mg/dL in a high-risk patient with 18% 10-year ASCVD risk, diabetes, and hypertension is above the recommended target of below 70 mg/dL for very-high-risk patients on maximally tolerated statin. Option C is incorrect because switching to a low-intensity statin would reduce LDL lowering efficacy and increase cardiovascular risk, which is the opposite of what this high-risk patient needs."}, {"id": 48, "domain": "primary_care_medicine", "question": "A 45-year-old man with no cardiac history complains of exertional chest pain radiating to his left arm that resolves with rest. Which initial diagnostic test is most appropriate?", "options": {"A": "Coronary CT angiography for immediate anatomical assessment.", "B": "Resting ECG and cardiac biomarkers as first-line evaluation.", "C": "Stress testing to evaluate for inducible ischemia.", "D": "Cardiac MRI to assess wall motion abnormalities at rest."}, "correct": "C", "explanation": "In a patient with classic exertional chest pain (stable angina symptoms) and no acute symptoms, stress testing to evaluate for inducible ischemia is the appropriate initial diagnostic step for stable chest pain evaluation. Option A is incorrect because coronary CT angiography is an alternative imaging modality but is generally not the first-line test for stable exertional chest pain in an outpatient setting without intermediate-high pretest probability assessment first. Option B is incorrect because resting ECG and cardiac biomarkers are the first step for acute chest pain evaluation to rule out STEMI or NSTEMI, not for stable exertional symptoms that resolve with rest."}, {"id": 50, "domain": "primary_care_medicine", "question": "Which medication is contraindicated in patients with a sulfa allergy and severe renal impairment due to both allergy and pharmacokinetic concerns?", "options": {"A": "Furosemide, a loop diuretic with sulfonamide structure.", "B": "Hydrochlorothiazide, a thiazide diuretic with sulfa component.", "C": "Metformin, a biguanide requiring adequate renal clearance.", "D": "Trimethoprim-sulfamethoxazole, a sulfa antibiotic."}, "correct": "D", "explanation": "Trimethoprim-sulfamethoxazole is a sulfa-containing antibiotic that is contraindicated in patients with sulfa allergy and is also renally cleared, requiring dose reduction or avoidance in severe renal impairment. Option A is incorrect because furosemide has a sulfonamide chemical structure and carries a theoretical cross-reactivity risk, but the clinical question focuses on the antibiotic with both a direct sulfa allergy risk and pharmacokinetic concern in renal impairment. Option C is incorrect because metformin is contraindicated in severe renal impairment due to lactic acidosis risk but contains no sulfa moiety and is not relevant to sulfa allergy."}, {"id": 51, "domain": "primary_care_medicine", "question": "A 40-year-old man with no medical history has a fasting glucose of 108 mg/dL. According to ADA criteria, this value defines which metabolic state?", "options": {"A": "Normal fasting glucose because the value is below 110 mg/dL.", "B": "Impaired fasting glucose (prediabetes) in the 100-125 mg/dL range.", "C": "Diabetes mellitus requiring immediate pharmacological treatment.", "D": "Borderline glucose intolerance requiring OGTT within one week."}, "correct": "B", "explanation": "A fasting glucose of 108 mg/dL falls within the 100 to 125 mg/dL range that defines impaired fasting glucose, which is the prediabetes category according to ADA criteria. Option A is incorrect because normal fasting glucose is defined as below 100 mg/dL, and this patient's value of 108 mg/dL exceeds that threshold. Option C is incorrect because diabetes mellitus requires a fasting glucose of 126 mg/dL or higher on two separate occasions, and this patient's value of 108 mg/dL does not meet that threshold."}, {"id": 54, "domain": "primary_care_medicine", "question": "A 52-year-old man has systolic blood pressure of 162 mmHg and diastolic of 105 mmHg confirmed on three separate visits. Which ACC/AHA classification applies?", "options": {"A": "Elevated blood pressure in the 120-129/less than 80 range.", "B": "Stage 1 hypertension in the 130-139/80-89 mmHg range.", "C": "Stage 2 hypertension at or above 140/90 mmHg threshold.", "D": "Hypertensive urgency requiring emergency department evaluation."}, "correct": "C", "explanation": "Stage 2 hypertension is defined as systolic blood pressure at or above 140 mmHg or diastolic at or above 90 mmHg, and this patient meets both criteria at 162/105 mmHg confirmed on multiple visits. Option A is incorrect because elevated blood pressure is defined as systolic 120-129 mmHg with diastolic below 80 mmHg, far below this patient's readings. Option B is incorrect because Stage 1 hypertension ranges from 130-139/80-89 mmHg, and this patient's readings of 162/105 mmHg exceed those thresholds."}, {"id": 64, "domain": "primary_care_medicine", "question": "Which risk factor carries the highest point value (2 points) in the CHA2DS2-VASc scoring system for stroke risk in atrial fibrillation?", "options": {"A": "Hypertension contributing 2 points to the CHA2DS2-VASc score.", "B": "Prior stroke or TIA contributing 2 points to the score.", "C": "Age 75 or older contributing 2 points to the score.", "D": "Both prior stroke and age 75 or older contribute 2 points each."}, "correct": "D", "explanation": "Both prior stroke or TIA and age 75 or older each independently contribute 2 points to the CHA2DS2-VASc score, making them the two highest-weighted individual risk factors in the scoring system. Option A is incorrect because hypertension contributes only 1 point to the CHA2DS2-VASc score, not 2 points. Option B is incorrect because while prior stroke or TIA does contribute 2 points, it is not the only factor worth 2 points, and age 75 or older also contributes 2 points."}, {"id": 68, "domain": "primary_care_medicine", "question": "Which GLP-1 receptor agonist has demonstrated cardiovascular mortality reduction in type 2 diabetes patients with established cardiovascular disease in LEADER trial?", "options": {"A": "Exenatide extended-release shown to reduce cardiovascular events.", "B": "Dulaglutide reducing MACE in the REWIND cardiovascular trial.", "C": "Albiglutide proven to reduce myocardial infarction in HARMONY.", "D": "Liraglutide (Victoza) reducing cardiovascular mortality in LEADER."}, "correct": "D", "explanation": "Liraglutide (Victoza) demonstrated a significant reduction in cardiovascular mortality in the LEADER (Liraglutide Effect and Action in Diabetes: Evaluation of Cardiovascular Outcome Results) trial in type 2 diabetes patients with established cardiovascular disease. Option A is incorrect because exenatide extended-release was studied in the EXSCEL trial and did not show a statistically significant reduction in cardiovascular mortality, though it was non-inferior to placebo. Option C is incorrect because albiglutide was studied in the HARMONY Outcomes trial and showed reduction in MACE, but the LEADER trial with liraglutide is the landmark study specifically cited for cardiovascular mortality reduction."}, {"id": 70, "domain": "primary_care_medicine", "question": "A 60-year-old woman with known CAD has an LDL of 88 mg/dL on high-intensity statin. Her 10-year risk is 28%. Which additional therapy is indicated?", "options": {"A": "Add ezetimibe to further reduce LDL below 70 mg/dL.", "B": "Continue current therapy because LDL is below 100 mg/dL.", "C": "Switch to a moderate-intensity statin to maintain this LDL.", "D": "Add fibrate to the statin for combined lipid-lowering therapy."}, "correct": "A", "explanation": "For a patient with established coronary artery disease on high-intensity statin therapy, adding ezetimibe is indicated when LDL remains above 70 mg/dL, as the ACC/AHA recommends an LDL target of below 70 mg/dL for very high-risk patients. Option B is incorrect because LDL of 88 mg/dL in a patient with known CAD and 28% 10-year risk remains above the recommended target of below 70 mg/dL, so continuing current therapy without intensification is insufficient. Option C is incorrect because switching to a moderate-intensity statin would reduce the degree of LDL lowering in a very-high-risk patient who requires maximum lipid reduction."}, {"id": 73, "domain": "primary_care_medicine", "question": "A 50-year-old woman has dyspnea on exertion, orthopnea, and leg edema. Echocardiogram shows EF of 30% with dilated LV. Which BNP level would support a diagnosis of heart failure?", "options": {"A": "BNP greater than 35 pg/mL, the threshold for outpatient HF diagnosis.", "B": "Any BNP above normal range regardless of clinical context.", "C": "BNP greater than 400 pg/mL indicating severe decompensated HF.", "D": "BNP greater than 100 pg/mL in an acutely dyspneic patient."}, "correct": "D", "explanation": "A BNP greater than 100 pg/mL supports the diagnosis of heart failure in an acutely dyspneic patient, and this threshold is widely used in emergency and inpatient settings to differentiate cardiac from non-cardiac causes of dyspnea. Option A is incorrect because BNP greater than 35 pg/mL is the threshold for ruling in heart failure in an outpatient or stable setting, not for diagnosing acute decompensated heart failure. Option C is incorrect because while BNP greater than 400 pg/mL indicates higher likelihood of severe decompensated heart failure, the question asks what level would support the diagnosis, not what level indicates the most severe disease."}, {"id": 74, "domain": "primary_care_medicine", "question": "A 62-year-old man with atrial fibrillation on warfarin has an INR of 5.8 with no active bleeding. What is the most appropriate management?", "options": {"A": "Hold warfarin and give vitamin K 2.5-5 mg orally.", "B": "Continue warfarin at same dose and recheck INR in one week.", "C": "Give fresh frozen plasma to rapidly reverse anticoagulation.", "D": "Switch to a DOAC immediately to avoid INR fluctuations."}, "correct": "A", "explanation": "For a supratherapeutic INR of 5.8 with no active bleeding, the recommended management is to hold warfarin and administer vitamin K 2.5 to 5 mg orally to reverse the coagulopathy without precipitating thrombosis. Option B is incorrect because continuing warfarin at the same dose with an INR of 5.8 increases bleeding risk and does not address the supratherapeutic anticoagulation that requires active management. Option C is incorrect because fresh frozen plasma is reserved for active serious bleeding or emergency procedures requiring immediate reversal, not for a supratherapeutic INR without bleeding."}, {"id": 78, "domain": "primary_care_medicine", "question": "A 48-year-old woman has fatigue, constipation, cold intolerance, and weight gain. TSH is 12 mIU/L and free T4 is 0.6 ng/dL. Which treatment is first-line?", "options": {"A": "Liothyronine (T3) alone is preferred for hypothyroid symptom relief.", "B": "Iodine supplementation to restore thyroid hormone production.", "C": "Combination T3 and T4 is the preferred treatment for all patients.", "D": "Levothyroxine (T4) once daily titrated to normalize TSH level."}, "correct": "D", "explanation": "Levothyroxine (synthetic T4) taken once daily and titrated to normalize the TSH level is the first-line treatment for overt hypothyroidism because it provides stable thyroid hormone replacement with predictable pharmacokinetics. Option A is incorrect because liothyronine (T3) alone results in fluctuating T3 levels due to its short half-life and is not standard first-line therapy for hypothyroidism. Option C is incorrect because combination T3 and T4 therapy is not recommended as standard first-line treatment; levothyroxine monotherapy is preferred for the majority of patients."}, {"id": 87, "domain": "primary_care_medicine", "question": "A 65-year-old woman with HTN and CKD stage 3 has a blood pressure of 152/94 mmHg. What is the blood pressure target for patients with CKD per KDIGO guidelines?", "options": {"A": "Less than 150/90 mmHg for patients over age 60 with CKD.", "B": "Less than 140/90 mmHg as the standard CKD blood pressure target.", "C": "Less than 130/80 mmHg for patients with CKD and albuminuria.", "D": "Less than 120/80 mmHg as the universal CKD target regardless of age."}, "correct": "C", "explanation": "KDIGO guidelines recommend a blood pressure target of less than 130/80 mmHg for patients with CKD and albuminuria, as tighter blood pressure control reduces kidney disease progression and cardiovascular events in this population. Option A is incorrect because a target of less than 150/90 mmHg for patients over 60 with CKD is too permissive and does not reflect current KDIGO recommendations for patients with albuminuria. Option B is incorrect because less than 140/90 mmHg is the general population hypertension target and is not the specific KDIGO target for CKD patients with albuminuria, where tighter control is recommended."}, {"id": 90, "domain": "primary_care_medicine", "question": "A 55-year-old man has epigastric pain that is worse with food. Upper endoscopy shows a gastric ulcer. H. pylori testing is negative. What is the most likely cause?", "options": {"A": "Zollinger-Ellison syndrome with gastrin-secreting pancreatic tumor.", "B": "Stress-related mucosal damage from recent critical illness.", "C": "NSAID use causing prostaglandin inhibition in the gastric mucosa.", "D": "Bile reflux gastritis causing chemical injury to the stomach."}, "correct": "C", "explanation": "NSAID use is the most common non-H. pylori cause of gastric ulcers, as NSAIDs inhibit COX-1-mediated prostaglandin synthesis, impairing gastric mucosal defense mechanisms and leading to ulcer formation. Option A is incorrect because Zollinger-Ellison syndrome is a rare condition caused by a gastrin-secreting tumor that typically presents with multiple ulcers in unusual locations and very high gastric acid output."}, {"id": 93, "domain": "primary_care_medicine", "question": "Which feature is most characteristic of cardiac chest pain from stable angina compared to musculoskeletal chest pain?", "options": {"A": "Reproducible pain with palpation of the chest wall.", "B": "Pain relieved by antacids suggesting esophageal etiology.", "C": "Exertional substernal pressure relieved by rest or nitroglycerin.", "D": "Sharp pleuritic pain worsening with deep inspiration."}, "correct": "C", "explanation": "Classic stable angina presents as exertional substernal pressure or squeezing discomfort that is predictably relieved by rest or nitroglycerin, distinguishing it from musculoskeletal or other non-cardiac chest pain causes. Option A is incorrect because reproducible pain with palpation of the chest wall is a hallmark of musculoskeletal chest pain and essentially rules out cardiac ischemia as the etiology. Option B is incorrect because chest pain relieved by antacids suggests esophageal or gastroesophageal reflux etiology rather than cardiac ischemia."}, {"id": 96, "domain": "primary_care_medicine", "question": "A 62-year-old man with atrial fibrillation started on warfarin has a target INR. What therapeutic INR range is recommended for atrial fibrillation?", "options": {"A": "INR 1.5 to 2.0 for patients with low stroke risk.", "B": "INR 2.0 to 3.0 for atrial fibrillation stroke prevention.", "C": "INR 2.5 to 3.5 for atrial fibrillation with mechanical valve.", "D": "INR 3.0 to 4.0 for all high-risk atrial fibrillation patients."}, "correct": "B", "explanation": "The therapeutic INR range for atrial fibrillation is 2.0 to 3.0, which balances adequate stroke prevention against acceptable bleeding risk for patients on warfarin anticoagulation. Option A is incorrect because an INR of 1.5 to 2.0 provides subtherapeutic anticoagulation that does not adequately reduce stroke risk in atrial fibrillation. Option C is incorrect because an INR of 2.5 to 3.5 is the target range for patients with mechanical heart valves, which requires higher anticoagulation intensity than atrial fibrillation alone."}, {"id": 98, "domain": "primary_care_medicine", "question": "A 42-year-old man with no prior TB exposure lives with someone who just tested positive for active TB. His TST induration is 8 mm. Is this considered positive?", "options": {"A": "No, because 8 mm is below the 10 mm threshold for close contacts.", "B": "Yes, because close contacts use the 5 mm or greater threshold.", "C": "Yes, because household contacts use the 10 mm or greater threshold.", "D": "No, because only BCG-vaccinated persons use the 5 mm threshold."}, "correct": "B", "explanation": "Close contacts of active TB cases use the 5 mm or greater threshold to define a positive tuberculin skin test, because recent exposure with immune sensitization makes even smaller reactions clinically significant for latent infection. Option A is incorrect because the 10 mm threshold applies to other high-risk groups such as recent immigrants, injection drug users, and healthcare workers, but close contacts of active TB cases use the lower 5 mm threshold. Option C is incorrect because while the 10 mm threshold applies to household contacts in some historical guidelines, current CDC guidelines specify that close contacts of active TB use the 5 mm threshold, and an 8 mm induration in a close contact is positive."}, {"id": 106, "domain": "specialty_systems", "question": "A 50-year-old man has had three gout attacks in 12 months and a serum uric acid of 9.8 mg/dL. Which medication is used for urate-lowering therapy as first-line?", "options": {"A": "Colchicine as long-term urate-lowering therapy for gout prevention.", "B": "Indomethacin daily as long-term prevention for recurrent gout.", "C": "Probenecid as first-line ULT regardless of renal function.", "D": "Allopurinol, a xanthine oxidase inhibitor, as first-line ULT."}, "correct": "D", "explanation": "Allopurinol is first-line urate-lowering therapy because it inhibits xanthine oxidase to reduce uric acid synthesis and is preferred over uricosuric agents for most patients. Option A is incorrect because colchicine is used as prophylaxis to prevent flares during initiation of ULT, not as the long-term urate-lowering agent. Option C is incorrect because probenecid is not first-line and is contraindicated in patients with reduced renal function or a history of uric acid nephrolithiasis."}, {"id": 107, "domain": "specialty_systems", "question": "A 38-year-old woman has a throbbing unilateral headache with photophobia, phonophobia, and nausea lasting 18 hours. She has had similar headaches monthly. What is the diagnosis?", "options": {"A": "Tension-type headache with bilateral pressing quality without nausea.", "B": "Cluster headache with unilateral severe pain around the eye.", "C": "Migraine headache with unilateral throbbing pain and nausea.", "D": "Secondary headache from subarachnoid hemorrhage with thunderclap onset."}, "correct": "C", "explanation": "Migraine headache is the correct diagnosis because it presents with unilateral throbbing pain, photophobia, phonophobia, and nausea lasting hours, recurring over months. Option A is incorrect because tension-type headache is typically bilateral, pressing rather than throbbing, and does not cause nausea or photophobia. Option B is incorrect because cluster headache causes severe periorbital pain with autonomic features such as lacrimation, lasting 15 to 180 minutes rather than 18 hours."}, {"id": 108, "domain": "specialty_systems", "question": "Which triptans mechanism of action makes them effective abortive therapy for acute migraine attacks?", "options": {"A": "Selective serotonin 5-HT1B/1D receptor agonism causing vasoconstriction.", "B": "Non-selective serotonin antagonism reducing neurogenic inflammation.", "C": "Dopamine D2 receptor antagonism reducing nausea and vomiting.", "D": "COX-2 inhibition reducing prostaglandin-mediated central sensitization."}, "correct": "A", "explanation": "Triptans act as selective serotonin 5-HT1B/1D receptor agonists, causing cranial vasoconstriction and inhibiting the release of pain-producing neuropeptides to abort migraines. Option B is incorrect because triptans are selective agonists, not non-selective antagonists, and work by vasoconstriction rather than direct anti-inflammatory effects on neurogenic inflammation. Option C is incorrect because dopamine D2 receptor antagonism describes the mechanism of antiemetics such as metoclopramide, not triptans."}, {"id": 115, "domain": "specialty_systems", "question": "A 32-year-old man has recurrent facial flushing, papules, and pustules on his cheeks and nose. He has no comedones. Which diagnosis is most likely?", "options": {"A": "Acne vulgaris with comedonal and inflammatory lesions.", "B": "Perioral dermatitis with small papules around the mouth.", "C": "Seborrheic dermatitis with greasy scales on the face.", "D": "Rosacea with central facial erythema and papulopustular lesions."}, "correct": "D", "explanation": "Rosacea is the correct diagnosis because it presents with central facial erythema, flushing, papules, and pustules without comedones, which differentiates it from acne vulgaris. Option A is incorrect because acne vulgaris is defined by the presence of comedones (open or closed), which are absent in this patient with rosacea. Option C is incorrect because seborrheic dermatitis causes greasy, yellowish scales on the nasolabial folds, eyebrows, and scalp rather than papulopustular lesions."}, {"id": 117, "domain": "specialty_systems", "question": "A 65-year-old man has a pearly, rolled-border nodule with central ulceration on his nose that has been present for six months. What is the most likely diagnosis?", "options": {"A": "Squamous cell carcinoma with irregular borders and ulceration.", "B": "Basal cell carcinoma with rolled pearly border and central ulceration.", "C": "Melanoma with asymmetry, irregular border, and color variation.", "D": "Keratoacanthoma with rapid growth and central keratin plug."}, "correct": "B", "explanation": "Basal cell carcinoma is the correct diagnosis because it classically presents as a pearly, rolled-border nodule with central ulceration on sun-exposed areas like the nose in older adults. Option A is incorrect because squamous cell carcinoma typically presents as an irregular, indurated, scaling plaque or ulcer arising in actinic keratosis on sun-damaged skin rather than a pearly nodule. Option C is incorrect because melanoma presents with the ABCDE features of asymmetry, irregular border, color variation, large diameter, and evolution, not a pearly rolled border."}, {"id": 120, "domain": "specialty_systems", "question": "A 65-year-old man has gradual bilateral peripheral vision loss, increased cup-to-disc ratio on fundoscopy, and intraocular pressure of 26 mmHg. What is the most likely diagnosis?", "options": {"A": "Age-related macular degeneration with central vision loss.", "B": "Open-angle glaucoma with optic nerve damage and peripheral field loss.", "C": "Cataracts causing progressive central vision blurring.", "D": "Retinal detachment with sudden curtain-like visual field loss."}, "correct": "B", "explanation": "Open-angle glaucoma is the correct diagnosis because it causes gradual bilateral peripheral vision loss, optic nerve cupping with increased cup-to-disc ratio, and elevated intraocular pressure. Option A is incorrect because age-related macular degeneration causes central vision loss rather than peripheral field loss and is not associated with elevated IOP or cup-to-disc ratio changes. Option C is incorrect because cataracts cause progressive central vision blurring and glare without peripheral field loss or changes in optic nerve appearance."}, {"id": 123, "domain": "specialty_systems", "question": "A 35-year-old woman has facial pressure, purulent nasal discharge, and symptoms lasting more than 10 days without improvement. Fever is 38.5 degrees Celsius. Which diagnosis applies?", "options": {"A": "Viral rhinosinusitis with symptom duration under 10 days.", "B": "Allergic rhinitis with seasonal symptoms and clear discharge.", "C": "Chronic sinusitis defined by symptoms lasting over 12 weeks.", "D": "Acute bacterial sinusitis meeting Rosenfeld criteria for antibiotics."}, "correct": "D", "explanation": "Acute bacterial sinusitis is the correct diagnosis because symptoms lasting more than 10 days without improvement, purulent discharge, and fever meet the Rosenfeld criteria for diagnosing ABRS and initiating antibiotics. Option A is incorrect because viral rhinosinusitis typically improves within 10 days and would not present with persistent symptoms and fever at this duration. Option C is incorrect because chronic sinusitis is defined by symptoms persisting for 12 weeks or more, not 10 days."}, {"id": 125, "domain": "specialty_systems", "question": "A 70-year-old man has bilateral shoulder girdle pain and morning stiffness lasting two hours. ESR is 88 mm/hr. He has no synovitis on exam. What is the most likely diagnosis?", "options": {"A": "Rheumatoid arthritis with symmetric synovitis and elevated RF.", "B": "Polymyositis with proximal muscle weakness and elevated CK.", "C": "Fibromyalgia with widespread pain and normal inflammatory markers.", "D": "Polymyalgia rheumatica with proximal girdle symptoms and elevated ESR."}, "correct": "D", "explanation": "Polymyalgia rheumatica is the correct diagnosis because it presents in older adults with bilateral proximal shoulder and hip girdle pain, morning stiffness, and a markedly elevated ESR without true synovitis on exam. Option A is incorrect because rheumatoid arthritis causes symmetric synovitis of small joints with positive RF and would not present with isolated girdle symptoms and no synovitis. Option C is incorrect because fibromyalgia causes widespread pain with normal inflammatory markers rather than an elevated ESR of 88 mm/hr."}, {"id": 126, "domain": "specialty_systems", "question": "A 40-year-old woman has cluster headaches. Which feature differentiates cluster headache from migraine?", "options": {"A": "Cluster headache is bilateral while migraine is always unilateral.", "B": "Cluster headache is associated with nausea more often than migraine.", "C": "Cluster headache responds to triptans while migraine does not.", "D": "Cluster headache occurs in bouts with autonomic features like tearing."}, "correct": "D", "explanation": "Cluster headache is differentiated from migraine by its occurrence in bouts lasting weeks to months with associated ipsilateral autonomic features such as lacrimation, nasal congestion, and ptosis. Option A is incorrect because cluster headache is unilateral, not bilateral, and migraine can also be unilateral, so sidedness does not differentiate the two. Option C is incorrect because both cluster headaches and migraines can respond to triptans, and this feature does not reliably differentiate them."}, {"id": 127, "domain": "specialty_systems", "question": "A 72-year-old man with Parkinson's disease is on carbidopa-levodopa. He develops dyskinesias and wearing-off symptoms. Which adjunctive medication is added for motor fluctuations?", "options": {"A": "Entacapone, a COMT inhibitor, to prolong levodopa effect.", "B": "Amantadine for chorea and dyskinesias in Parkinson's disease.", "C": "Benztropine for tremor with anticholinergic properties.", "D": "Selegiline, a MAO-B inhibitor, for early disease only."}, "correct": "A", "explanation": "Entacapone is a COMT inhibitor that prolongs the duration of levodopa effect by blocking its peripheral metabolism, making it effective for wearing-off motor fluctuations in Parkinson's disease. Option B is incorrect because amantadine is used to treat levodopa-induced dyskinesias rather than the wearing-off phenomenon. Option C is incorrect because benztropine is an anticholinergic used primarily for tremor in younger Parkinson's patients and does not address motor fluctuations or wearing-off."}, {"id": 128, "domain": "specialty_systems", "question": "A 30-year-old woman has bilateral hand eczema with pruritic vesicles on her palms and finger sides that worsen with water exposure. What type of eczema is this?", "options": {"A": "Atopic dermatitis with flexural involvement and personal atopy history.", "B": "Nummular eczema with coin-shaped plaques on the extremities.", "C": "Contact dermatitis from allergen exposure with a linear pattern.", "D": "Dyshidrotic eczema with vesicles on palms and sides of fingers."}, "correct": "D", "explanation": "Dyshidrotic eczema is the correct diagnosis because it presents with pruritic vesicles on the palms and sides of the fingers that worsen with water exposure, a pattern characteristic of this condition. Option A is incorrect because atopic dermatitis typically involves flexural areas such as the antecubital and popliteal fossae and is associated with a personal or family history of atopy. Option C is incorrect because contact dermatitis usually follows the pattern of allergen exposure and often appears in a linear or geometric distribution, not bilaterally on the palms."}, {"id": 134, "domain": "specialty_systems", "question": "A 50-year-old man has a rash with grouped vesicles on an erythematous base along his left thoracic dermatome. He reports burning pain. What is the diagnosis?", "options": {"A": "Herpes simplex type 1 with oral-labial vesicular eruption.", "B": "Tinea corporis with ringworm-like pattern on the trunk.", "C": "Contact dermatitis with linear vesicular pattern along belt line.", "D": "Herpes zoster (shingles) from varicella zoster virus reactivation."}, "correct": "D", "explanation": "Herpes zoster (shingles) is the correct diagnosis because grouped vesicles on an erythematous base following a dermatomal distribution with burning pain represents reactivation of the varicella zoster virus in a dorsal root ganglion. Option A is incorrect because herpes simplex type 1 causes oral-labial vesicular eruptions that do not follow a dermatome and recur at the same site rather than in a thoracic distribution. Option C is incorrect because contact dermatitis follows the pattern of allergen or irritant exposure and produces a linear or patchy distribution rather than a strictly dermatomal one with burning prodrome."}, {"id": 137, "domain": "specialty_systems", "question": "A 28-year-old man has painless mucopurulent discharge from his right eye with preauricular lymphadenopathy and no itching. What type of conjunctivitis is this?", "options": {"A": "Allergic conjunctivitis with bilateral itching and watery discharge.", "B": "Chemical conjunctivitis from recent environmental exposure.", "C": "Bacterial conjunctivitis from Staphylococcus or Streptococcus.", "D": "Viral conjunctivitis from adenovirus with follicular tarsal reaction."}, "correct": "D", "explanation": "Viral conjunctivitis from adenovirus is the most likely cause because it presents with unilateral or bilateral mucopurulent discharge, follicular reaction on the tarsal conjunctiva, and preauricular lymphadenopathy. Option A is incorrect because allergic conjunctivitis presents bilaterally with intense itching and watery discharge rather than mucopurulent discharge, and does not cause preauricular lymphadenopathy. Option C is incorrect because bacterial conjunctivitis typically presents with mucopurulent discharge but does not cause preauricular lymphadenopathy, which is a hallmark of viral (adenoviral) conjunctivitis."}, {"id": 139, "domain": "specialty_systems", "question": "A 62-year-old man with gout has a serum uric acid of 10.2 mg/dL and has been on allopurinol 300 mg daily for one year. He continues to have attacks. What is the target serum uric acid?", "options": {"A": "Serum uric acid below 7.0 mg/dL as the minimum acceptable target.", "B": "Serum uric acid below 8.0 mg/dL is acceptable with no symptoms.", "C": "Serum uric acid below 5.0 mg/dL for patients with tophaceous gout.", "D": "Serum uric acid below 6.0 mg/dL as the target for most gout patients."}, "correct": "D", "explanation": "The target serum uric acid for most gout patients on ULT is below 6.0 mg/dL because this level keeps urate below its saturation point and promotes crystal dissolution over time. Option A is incorrect because a target below 7.0 mg/dL is above the physiological saturation threshold and would not reliably prevent crystal formation or dissolution. Option C is incorrect because below 5.0 mg/dL is reserved specifically for patients with tophaceous gout and is a more aggressive target not required for uncomplicated recurrent gout."}, {"id": 145, "domain": "specialty_systems", "question": "A 60-year-old woman has acute ischemic stroke with onset 2.5 hours ago. CT head shows no hemorrhage. What is the appropriate acute treatment?", "options": {"A": "Aspirin 325 mg loading dose only within 4.5-hour window.", "B": "IV tPA (alteplase) within 4.5 hours of symptom onset.", "C": "Heparin infusion for acute cardioembolic ischemic stroke.", "D": "Clopidogrel plus aspirin dual antiplatelet for all acute strokes."}, "correct": "B", "explanation": "IV tPA (alteplase) is the appropriate acute treatment for ischemic stroke within 4.5 hours of symptom onset when CT head shows no hemorrhage, as it improves functional outcomes in eligible patients. Option A is incorrect because aspirin 325 mg alone as a loading dose is not adequate acute reperfusion therapy and is not the treatment within the thrombolytic window. Option C is incorrect because heparin infusion is not recommended as routine acute treatment for ischemic stroke, including cardioembolic strokes, due to lack of benefit and increased bleeding risk."}, {"id": 146, "domain": "specialty_systems", "question": "A 55-year-old woman has rheumatoid arthritis inadequately controlled on methotrexate alone. Which biologic agent class is added as the next step in RA management?", "options": {"A": "Hydroxychloroquine added to methotrexate as conventional DMARD.", "B": "Prednisone added long-term as bridge therapy for RA control.", "C": "Leflunomide added as a second conventional DMARD agent.", "D": "TNF inhibitor such as etanercept added to methotrexate."}, "correct": "D", "explanation": "A TNF inhibitor such as etanercept is the recommended next step when RA is inadequately controlled on methotrexate alone, as biologic DMARDs targeting TNF have strong evidence for reducing disease activity and joint damage. Option A is incorrect because hydroxychloroquine is a conventional DMARD with weaker anti-inflammatory effects than biologics and is typically added early in mild disease rather than as escalation after methotrexate failure. Option C is incorrect because leflunomide is another conventional DMARD that may be added, but when methotrexate has already failed to control disease, biologic therapy is the standard next step."}, {"id": 150, "domain": "specialty_systems", "question": "A 28-year-old woman has a 6-mm melanocytic lesion with border irregularity and two colors. Dermoscopy shows irregular network and blue-white veil. What is the next step?", "options": {"A": "Photograph and monitor with clinical follow-up in 6 months.", "B": "Punch biopsy of the darkest area for partial sampling.", "C": "Shave biopsy of the raised central portion for diagnosis.", "D": "Excisional biopsy with 1-2 mm margins for histological evaluation."}, "correct": "D", "explanation": "Excisional biopsy with 1 to 2 mm margins is the recommended next step for a lesion with high-risk dermoscopic features including irregular network and blue-white veil, which raise concern for melanoma. Option A is incorrect because monitoring a lesion with high-risk dermoscopic features in a 6-mm asymmetric pigmented lesion without biopsy is not appropriate as it delays potential diagnosis of melanoma. Option C is incorrect because shave biopsy of a suspected melanoma is not appropriate as it may transect the lesion and prevent accurate Breslow depth staging."}, {"id": 153, "domain": "specialty_systems", "question": "A 52-year-old man has a skin lesion described as a scaly, erythematous plaque on his forearm that bleeds easily and has been slowly enlarging. He has significant sun damage. What is this?", "options": {"A": "Basal cell carcinoma with a translucent pearly border.", "B": "Squamous cell carcinoma arising from actinic keratosis.", "C": "Melanoma with irregular borders and color variation.", "D": "Seborrheic keratosis with stuck-on waxy appearance."}, "correct": "B", "explanation": "Squamous cell carcinoma is the most likely diagnosis because a slowly enlarging, scaly, erythematous plaque that bleeds easily on significantly sun-damaged skin is a classic presentation of SCC, which arises from actinic keratosis. Option A is incorrect because basal cell carcinoma typically presents as a pearly, translucent nodule with a rolled border and central ulceration rather than a scaly, erythematous plaque. Option C is incorrect because melanoma presents as a pigmented lesion with asymmetry, irregular borders, and color variation, not as a scaly erythematous plaque on sun-damaged skin."}, {"id": 157, "domain": "specialty_systems", "question": "A 58-year-old man has chronic plaque psoriasis unresponsive to topical therapy. He develops joint pain and nail pitting. Which biologic class is approved for both psoriasis and psoriatic arthritis?", "options": {"A": "IL-17 inhibitors such as secukinumab approved for both conditions.", "B": "TNF inhibitors such as etanercept approved for skin only.", "C": "IL-23 inhibitors approved only for psoriatic joint involvement.", "D": "Methotrexate, a biologic, used for psoriasis and psoriatic arthritis."}, "correct": "A", "explanation": "IL-17 inhibitors such as secukinumab are approved by the FDA for both plaque psoriasis and psoriatic arthritis, making them effective for this patient with both skin and joint disease. Option B is incorrect because TNF inhibitors such as etanercept are approved for both psoriasis and psoriatic arthritis, but this option states they are approved for skin only, which is inaccurate. Option C is incorrect because IL-23 inhibitors are approved for both plaque psoriasis and psoriatic arthritis, not exclusively for joint involvement, so this statement is inaccurate."}, {"id": 164, "domain": "women_s_health", "question": "A 32-year-old woman at 34 weeks gestation has blood pressure of 158/102 mmHg and proteinuria of 0.8 g on 24-hour urine collection. What is the diagnosis?", "options": {"A": "Gestational hypertension without proteinuria meeting preeclampsia criteria.", "B": "Preeclampsia with hypertension and significant proteinuria after 20 weeks.", "C": "Chronic hypertension with blood pressure elevated before pregnancy.", "D": "Superimposed preeclampsia requires prior hypertension plus new proteinuria."}, "correct": "B", "explanation": "Preeclampsia is the correct diagnosis because this patient has hypertension above 140/90 mmHg and proteinuria of 0.8 g (greater than 300 mg) on 24-hour urine collection after 20 weeks gestation. Option A is incorrect because gestational hypertension is defined as new hypertension after 20 weeks without proteinuria, and this patient has significant proteinuria meeting preeclampsia criteria. Option C is incorrect because chronic hypertension is defined as blood pressure elevated before pregnancy or before 20 weeks gestation, which is not the case here."}, {"id": 165, "domain": "women_s_health", "question": "A 26-year-old woman at 26 weeks gestation has a 1-hour glucose challenge test result of 148 mg/dL. What is the next appropriate step?", "options": {"A": "Diagnose gestational diabetes and begin dietary intervention immediately.", "B": "No further testing because 148 mg/dL is a borderline normal result.", "C": "Repeat the 1-hour GCT in four weeks to confirm the result.", "D": "Perform a 3-hour 100g oral glucose tolerance test for confirmation."}, "correct": "D", "explanation": "A 3-hour 100g oral glucose tolerance test is required after a 1-hour GCT result of 140 mg/dL or above because the initial screening test alone is insufficient to diagnose gestational diabetes. Option A is incorrect because a single elevated 1-hour GCT result is a screening test, not a diagnostic one, and gestational diabetes cannot be diagnosed without a confirmatory OGTT. Option C is incorrect because repeating the 1-hour screening test rather than proceeding to the diagnostic 3-hour OGTT is not the appropriate next step after a positive screen."}, {"id": 167, "domain": "women_s_health", "question": "A 30-year-old woman has deep dyspareunia, severe dysmenorrhea, and infertility. Pelvic ultrasound shows an ovarian endometrioma. What is the most likely diagnosis?", "options": {"A": "Polycystic ovarian syndrome with enlarged ovaries and anovulation.", "B": "Pelvic inflammatory disease with bilateral adnexal tenderness.", "C": "Adenomyosis with diffuse uterine enlargement and heavy bleeding.", "D": "Endometriosis with ectopic endometrial tissue and ovarian involvement."}, "correct": "D", "explanation": "Endometriosis is the correct diagnosis because deep dyspareunia, severe dysmenorrhea, infertility, and an ovarian endometrioma on ultrasound are hallmark features of ectopic endometrial tissue implanting outside the uterus. Option A is incorrect because PCOS presents with irregular menses, hyperandrogenism, and polycystic ovaries rather than dyspareunia, dysmenorrhea, and endometriomas. Option C is incorrect because adenomyosis causes diffuse uterine enlargement with heavy and painful periods but does not produce ovarian endometriomas or the deep dyspareunia pattern seen here."}, {"id": 168, "domain": "women_s_health", "question": "A 28-year-old woman has irregular periods, hirsutism, and acne. Ultrasound shows polycystic ovaries. She meets 2 of 3 Rotterdam criteria for PCOS. Which three criteria define PCOS?", "options": {"A": "Elevated LH, low FSH, and polycystic ovaries on ultrasound.", "B": "Infertility, irregular menses, and elevated prolactin levels.", "C": "Insulin resistance, elevated testosterone, and bilateral ovarian cysts.", "D": "Hyperandrogenism, oligo/anovulation, and polycystic ovarian morphology."}, "correct": "D", "explanation": "The three Rotterdam criteria for PCOS are hyperandrogenism (clinical or biochemical), oligo- or anovulation, and polycystic ovarian morphology on ultrasound, with two of three required for diagnosis. Option A is incorrect because elevated LH and low FSH are hormonal findings sometimes seen in PCOS but are not part of the Rotterdam diagnostic criteria for PCOS. Option C is incorrect because insulin resistance and elevated testosterone are common features of PCOS but are not the three formal Rotterdam criteria used for diagnosis."}, {"id": 173, "domain": "women_s_health", "question": "A 25-year-old woman meets criteria for pelvic inflammatory disease with uterine tenderness and cervical motion tenderness. She is not pregnant and has no severe illness. What is the treatment?", "options": {"A": "Outpatient ceftriaxone 500 mg IM plus doxycycline plus metronidazole.", "B": "Inpatient IV cefoxitin plus doxycycline for all PID presentations.", "C": "Azithromycin 1 g single dose covering all PID organisms.", "D": "Penicillin G as primary treatment for N. gonorrhoeae in PID."}, "correct": "A", "explanation": "Outpatient treatment with ceftriaxone 500 mg IM plus doxycycline 100 mg twice daily for 14 days plus metronidazole is the CDC-recommended regimen for mild to moderate PID in non-pregnant patients who can be treated as outpatients. Option B is incorrect because inpatient IV therapy is reserved for severe PID, patients who cannot tolerate oral medications, failed outpatient therapy, or those with surgical emergencies such as tubo-ovarian abscess. Option C is incorrect because azithromycin alone as a single dose does not provide adequate coverage for the multiple organisms involved in PID, including anaerobes."}, {"id": 179, "domain": "women_s_health", "question": "A 55-year-old woman with hot flashes, no uterus (prior hysterectomy), and no contraindications wants hormone therapy. Which regimen is most appropriate?", "options": {"A": "Combined estrogen-progestin therapy to prevent endometrial cancer.", "B": "Estrogen-only therapy is safe and appropriate without a uterus.", "C": "Progestin-only therapy for women who have had hysterectomy.", "D": "Bioidentical progesterone is required even after hysterectomy."}, "correct": "B", "explanation": "Estrogen-only therapy is safe and appropriate for women who have had a hysterectomy because there is no uterine endometrium at risk for endometrial cancer, removing the need for progestin opposition. Option A is incorrect because combined estrogen-progestin therapy is prescribed to protect the endometrium in women who still have their uterus, which does not apply to a patient who has had a hysterectomy. Option C is incorrect because progestin-only therapy does not provide the same vasomotor symptom relief as estrogen and is not the preferred regimen for women without a uterus seeking menopausal hormone therapy."}, {"id": 181, "domain": "women_s_health", "question": "A 24-year-old woman has primary syphilis with a painless genital ulcer. VDRL is reactive. What is the treatment?", "options": {"A": "Doxycycline 100 mg twice daily for 14 days for primary syphilis.", "B": "Ceftriaxone 1 g IM daily for 10 days for primary syphilis.", "C": "Azithromycin 2 g single oral dose for all stages of syphilis.", "D": "Penicillin G benzathine 2.4 million units IM as a single dose."}, "correct": "D", "explanation": "Penicillin G benzathine 2.4 million units IM as a single dose is the CDC-recommended first-line treatment for primary syphilis, providing sustained treponemicidal penicillin levels. Option A is incorrect because doxycycline 100 mg twice daily for 14 days is an alternative treatment for primary syphilis in patients who cannot receive penicillin, not the first-line therapy. Option C is incorrect because azithromycin 2 g single dose is not reliably effective for syphilis due to macrolide resistance in some Treponema pallidum strains and is not a recommended first-line treatment."}, {"id": 182, "domain": "women_s_health", "question": "A 30-year-old woman at risk for HIV asks about PrEP. Which medication is FDA-approved for HIV pre-exposure prophylaxis in adults?", "options": {"A": "Efavirenz plus lamivudine as a two-drug PrEP regimen.", "B": "Tenofovir disoproxil fumarate plus emtricitabine (Truvada) for PrEP.", "C": "Abacavir plus lamivudine is the preferred PrEP combination.", "D": "Zidovudine plus didanosine was the first approved PrEP regimen."}, "correct": "B", "explanation": "Tenofovir disoproxil fumarate plus emtricitabine (Truvada) is FDA-approved for HIV pre-exposure prophylaxis and has demonstrated high efficacy when taken daily as directed. Option A is incorrect because efavirenz plus lamivudine is an antiretroviral treatment regimen, not an FDA-approved PrEP combination, and efavirenz is not indicated for pre-exposure prophylaxis. Option C is incorrect because abacavir plus lamivudine (Epzicom) is used as a component of HIV treatment regimens and is not an FDA-approved PrEP combination."}, {"id": 184, "domain": "women_s_health", "question": "A 52-year-old postmenopausal woman has vaginal dryness, dyspareunia, and recurrent UTIs. She refuses systemic hormone therapy. Which treatment is appropriate?", "options": {"A": "Systemic estrogen is the only option for genitourinary syndrome.", "B": "Ospemifene requires systemic absorption and is equivalent to estrogen.", "C": "Lubricants alone are equivalent to estrogen for treating dyspareunia.", "D": "Low-dose topical vaginal estrogen cream or ring for local therapy."}, "correct": "D", "explanation": "Low-dose topical vaginal estrogen cream or ring provides local treatment for genitourinary syndrome of menopause including vaginal dryness, dyspareunia, and recurrent UTIs with minimal systemic absorption, making it appropriate for women who decline systemic therapy. Option A is incorrect because systemic estrogen is not the only option for genitourinary syndrome of menopause, and topical low-dose vaginal estrogen is an effective and safe alternative. Option C is incorrect because lubricants provide symptomatic relief but do not reverse the atrophic changes causing recurrent UTIs and dyspareunia the way topical estrogen does."}, {"id": 186, "domain": "women_s_health", "question": "A 38-year-old woman at 28 weeks gestation has a 3-hour 100g OGTT with values: fasting 98 mg/dL, 1-hour 192 mg/dL, 2-hour 168 mg/dL, 3-hour 140 mg/dL. How many values are abnormal?", "options": {"A": "One abnormal value does not meet gestational diabetes diagnostic criteria.", "B": "Two or more abnormal values meet the Carpenter-Coustan criteria for GDM.", "C": "Three abnormal values indicate severe GDM requiring insulin immediately.", "D": "All four values must be abnormal to diagnose gestational diabetes."}, "correct": "B", "explanation": "Two or more abnormal values on the 3-hour 100g OGTT meet the Carpenter-Coustan criteria for gestational diabetes mellitus, and this patient has two values above the thresholds (1-hour at 192 vs. cutoff of 180, and 2-hour at 168 vs. cutoff of 155)."}, {"id": 188, "domain": "women_s_health", "question": "A 22-year-old woman has vulvovaginal candidiasis. She is not pregnant. She has had four episodes in the past year. Which treatment plan is recommended for recurrent VVC?", "options": {"A": "Single-dose fluconazole for each episode as needed without suppression.", "B": "Long-course topical clotrimazole for 14 days then monthly therapy.", "C": "Boric acid vaginal suppositories as monotherapy for recurrent VVC.", "D": "Fluconazole induction then weekly suppressive therapy for six months."}, "correct": "D", "explanation": "Fluconazole induction followed by weekly suppressive therapy for six months is the recommended treatment for recurrent vulvovaginal candidiasis (four or more episodes per year) to reduce recurrence rates. Option A is incorrect because treating each episode individually with single-dose fluconazole does not break the cycle of recurrent VVC and fails to provide the suppressive benefit needed for recurrence prevention. Option C is incorrect because boric acid vaginal suppositories are used for non-albicans Candida species or azole-resistant infections, not as monotherapy for typical recurrent VVC."}, {"id": 189, "domain": "women_s_health", "question": "A 50-year-old woman has moderate menopausal hot flashes affecting her quality of life. She has a history of breast cancer. Which non-hormonal treatment is evidence-based?", "options": {"A": "Low-dose oral estrogen is safe in breast cancer survivors after five years.", "B": "Gabapentin is not recommended for hot flashes in breast cancer survivors.", "C": "Black cohosh is the most effective non-hormonal option available.", "D": "SSRIs or SNRIs such as venlafaxine or escitalopram for hot flash reduction."}, "correct": "D", "explanation": "SSRIs or SNRIs such as venlafaxine or escitalopram are evidence-based non-hormonal options for reducing hot flash frequency and severity in breast cancer survivors for whom hormonal therapy is contraindicated. Option A is incorrect because oral estrogen is contraindicated in most breast cancer survivors due to the risk of stimulating estrogen receptor-positive tumor recurrence. Option C is incorrect because black cohosh has limited and inconsistent evidence for reducing hot flashes and is not considered the most effective non-hormonal option available."}, {"id": 196, "domain": "women_s_health", "question": "A 40-year-old woman has secondary syphilis with a diffuse rash including palms and soles. She is allergic to penicillin. Which treatment is recommended?", "options": {"A": "Azithromycin 2 g single oral dose for secondary syphilis.", "B": "Penicillin desensitization then penicillin G benzathine treatment.", "C": "Ceftriaxone 2 g daily for 10-14 days for secondary syphilis.", "D": "Doxycycline 100 mg twice daily for 14 days for secondary syphilis."}, "correct": "D", "explanation": "Doxycycline 100 mg twice daily for 14 days is the CDC-recommended treatment for secondary syphilis in patients with penicillin allergy who cannot receive first-line benzathine penicillin G. Option A is incorrect because azithromycin 2 g single dose is not reliable for syphilis treatment due to macrolide resistance in some Treponema pallidum strains and is not a CDC-recommended alternative for penicillin-allergic patients. Option C is incorrect because ceftriaxone 2 g daily for 10 to 14 days is an option for neurosyphilis and selected cases, but doxycycline is the preferred oral alternative for secondary syphilis in penicillin-allergic patients."}, {"id": 202, "domain": "mental_health", "question": "A 35-year-old woman has major depressive disorder without psychotic features. She has no contraindications to medication. Which class is first-line pharmacological treatment?", "options": {"A": "Tricyclic antidepressants such as amitriptyline as first-line MDD therapy.", "B": "Benzodiazepines such as clonazepam as first-line for MDD.", "C": "MAO inhibitors such as phenelzine as the safest first-line choice.", "D": "Selective serotonin reuptake inhibitors as first-line antidepressants."}, "correct": "D", "explanation": "Selective serotonin reuptake inhibitors are first-line pharmacological treatment for major depressive disorder due to their favorable safety and tolerability profile. Option A is wrong because tricyclic antidepressants like amitriptyline are associated with significant anticholinergic and cardiac toxicity, making them second or third-line agents. Option C is wrong because MAO inhibitors like phenelzine carry serious dietary restrictions and dangerous drug interactions, making them far from the safest first-line choice."}, {"id": 210, "domain": "mental_health", "question": "A 32-year-old woman with schizophrenia has positive symptoms including hallucinations and delusions. She has not responded to two adequate trials of first-line antipsychotics. Which medication is indicated?", "options": {"A": "Haloperidol at higher doses as a third-generation antipsychotic option.", "B": "Electroconvulsive therapy as the next step in treatment-resistant schizophrenia.", "C": "Lithium augmentation for schizophrenia with mood-incongruent features.", "D": "Clozapine for treatment-resistant schizophrenia after two failed trials."}, "correct": "D", "explanation": "Clozapine is indicated for treatment-resistant schizophrenia, defined as inadequate response to at least two adequate antipsychotic trials at appropriate doses and duration. Option A is wrong because haloperidol is a first-generation antipsychotic, not a third-generation agent, and increasing the dose does not address true treatment resistance. Option C is wrong because lithium augmentation is used in bipolar disorder and mood disorders, not as a standard treatment for treatment-resistant schizophrenia."}, {"id": 211, "domain": "mental_health", "question": "A 25-year-old woman on clozapine has a WBC count of 2,800 cells/mm3 with ANC of 900 cells/mm3. What should be done?", "options": {"A": "Continue clozapine and recheck CBC in one week.", "B": "Add G-CSF to stimulate white cell production while continuing clozapine.", "C": "Reduce clozapine dose by 50% and monitor CBC weekly.", "D": "Immediately discontinue clozapine due to agranulocytosis risk."}, "correct": "D", "explanation": "An ANC below 1,000 cells/mm3 on clozapine requires immediate discontinuation because of the serious risk of life-threatening agranulocytosis associated with this medication. Option A is wrong because continuing clozapine with only a weekly recheck would risk progression to severe agranulocytosis, which can be fatal if the drug is not stopped promptly. Option C is wrong because reducing the dose does not eliminate the bone marrow suppression risk when the ANC has fallen to a dangerously low level requiring drug cessation."}, {"id": 216, "domain": "mental_health", "question": "A 6-year-old boy has ADHD. According to AAP guidelines, which treatment approach is recommended as first-line for children ages 4 to 5 years?", "options": {"A": "Stimulant medication as first-line for all ADHD at any age.", "B": "Parent training in behavior management as the first-line therapy.", "C": "Combination of stimulant and behavioral therapy simultaneously.", "D": "Watchful waiting without treatment until school-age evaluation."}, "correct": "B", "explanation": "For children ages 4 to 5 years with ADHD, AAP guidelines recommend parent training in behavior management as the first-line treatment before considering stimulant medication. Option A is wrong because stimulant medication is recommended first-line for school-age children (6 and older) but not for preschool children, where behavioral interventions are prioritized first. Option C is wrong because the combination of stimulant and behavioral therapy simultaneously is the approach for school-age children, not the recommended first step for preschoolers."}, {"id": 218, "domain": "mental_health", "question": "A 52-year-old woman with MDD has not responded to two adequate SSRI trials. She has no contraindications. Which augmentation strategy is evidence-based?", "options": {"A": "Adding a benzodiazepine for anxiety-related treatment resistance.", "B": "Adding methylphenidate as dopamine-enhancing augmentation.", "C": "Switching to a different SSRI within the same class.", "D": "Adding atypical antipsychotic aripiprazole or quetiapine augmentation."}, "correct": "D", "explanation": "Adding an atypical antipsychotic such as aripiprazole or quetiapine as augmentation to an SSRI is a well-supported evidence-based strategy for treatment-resistant MDD after two adequate SSRI trials. Option A is wrong because benzodiazepines treat anxiety and insomnia but do not augment antidepressant response and carry risks of dependence, making them inappropriate as a primary augmentation strategy. Option C is wrong because switching within the same SSRI class does not constitute a meaningful augmentation strategy after two failed SSRI trials; a different approach or mechanism is needed."}, {"id": 222, "domain": "mental_health", "question": "A 40-year-old man on methadone maintenance therapy for OUD has a QTc of 520 ms. What is the concern with methadone at elevated doses?", "options": {"A": "Methadone causes hepatotoxicity requiring LFT monitoring monthly.", "B": "Methadone prolongs QT interval and raises risk of torsades de pointes.", "C": "Methadone causes serotonin syndrome with concurrent SSRI use.", "D": "Methadone causes irreversible peripheral neuropathy with prolonged use."}, "correct": "B", "explanation": "Methadone prolongs the QT interval by blocking cardiac potassium channels, and a QTc of 520 ms places this patient at significant risk for torsades de pointes and sudden cardiac death. Option A is wrong because while methadone does require LFT monitoring in some contexts, the primary safety concern at elevated doses is QT prolongation and cardiac arrhythmia, not hepatotoxicity. Option C is wrong because methadone does not cause serotonin syndrome; serotonin syndrome requires serotonergic drug combinations, and methadone primarily acts at opioid receptors."}, {"id": 224, "domain": "mental_health", "question": "A 38-year-old man has ADHD and is started on methylphenidate. Which cardiovascular monitoring is required before starting stimulant therapy?", "options": {"A": "Echocardiogram to exclude structural cardiac abnormalities.", "B": "Blood pressure and heart rate measurement before initiation.", "C": "24-hour Holter monitor to rule out arrhythmia.", "D": "Exercise stress test to screen for exertional arrhythmia."}, "correct": "B", "explanation": "Before starting stimulant therapy for ADHD, blood pressure and heart rate should be measured because stimulants increase both and can be problematic in patients with underlying cardiovascular conditions. Option A is wrong because an echocardiogram is not routinely required before starting stimulant therapy in otherwise healthy individuals without known structural heart disease or significant cardiac symptoms. Option C is wrong because a 24-hour Holter monitor is not a standard pre-stimulant requirement; it is used when arrhythmias are already suspected based on history or clinical findings."}, {"id": 227, "domain": "mental_health", "question": "A 35-year-old man with schizophrenia has tardive dyskinesia after years on haloperidol. Which medication is FDA-approved for treating tardive dyskinesia?", "options": {"A": "Benztropine, an anticholinergic, for acute and tardive movement symptoms.", "B": "Switching to clozapine immediately reverses all tardive dyskinesia.", "C": "Diazepam for muscle relaxation in tardive dyskinesia episodes.", "D": "Valbenazine (Ingrezza), a VMAT2 inhibitor for tardive dyskinesia."}, "correct": "D", "explanation": "Valbenazine (Ingrezza) is a VMAT2 inhibitor that reduces vesicular monoamine storage and has FDA approval specifically for the treatment of tardive dyskinesia. Option A is wrong because benztropine is an anticholinergic used for acute extrapyramidal symptoms like drug-induced parkinsonism and dystonia, not for tardive dyskinesia, which it can actually worsen. Option C is wrong because diazepam provides muscle relaxation but is not FDA-approved for tardive dyskinesia and does not target the dopaminergic imbalance underlying this movement disorder."}, {"id": 231, "domain": "mental_health", "question": "A 48-year-old man has persistent depressive disorder (dysthymia) with depressed mood most days for three years. He has no history of MDD episodes. Which treatment is recommended?", "options": {"A": "Antidepressants alone without psychotherapy for dysthymia.", "B": "Psychotherapy alone without medication for all dysthymia.", "C": "Combined antidepressant pharmacotherapy and psychotherapy.", "D": "Watchful waiting because dysthymia resolves without treatment."}, "correct": "C", "explanation": "For persistent depressive disorder (dysthymia), the combination of antidepressant pharmacotherapy and psychotherapy has the strongest evidence for sustained remission and is recommended over either treatment alone. Option A is wrong because antidepressants alone without psychotherapy are less effective for dysthymia than combined treatment, since the chronic nature of the disorder often requires cognitive and behavioral skill-building alongside medication. Option B is wrong because psychotherapy alone without medication is also less effective than the combined approach for persistent depressive disorder in most clinical trials."}, {"id": 233, "domain": "mental_health", "question": "A 35-year-old woman with MDD and anxiety is started on an SSRI. What timeframe should patients be counseled to expect for antidepressant response?", "options": {"A": "Within 24-48 hours, similar to stimulant medication effects.", "B": "Within one to two weeks for full antidepressant response.", "C": "Four to eight weeks for a meaningful antidepressant response.", "D": "Three to six months for all antidepressant effects to emerge."}, "correct": "C", "explanation": "Patients should be counseled that antidepressants typically require four to eight weeks to produce a meaningful clinical response, and partial improvement may be seen earlier but full response takes several weeks. Option A is wrong because SSRIs do not work within 24-48 hours like stimulants; they require time to produce changes in receptor sensitivity and neuroplasticity that underlie their antidepressant effect. Option B is wrong because one to two weeks is too short for a full antidepressant response; patients may notice some sleep improvement early, but significant mood improvement takes longer."}, {"id": 239, "domain": "mental_health", "question": "A 50-year-old man is assessed with the Columbia Suicide Severity Rating Scale (C-SSRS). What does this scale specifically assess?", "options": {"A": "Depression severity including vegetative and cognitive symptoms.", "B": "Suicidal ideation intensity, behavior, and lethality of prior attempts.", "C": "Anxiety severity and panic frequency in the past week.", "D": "Bipolar cycling speed and manic episode severity."}, "correct": "B", "explanation": "The Columbia Suicide Severity Rating Scale (C-SSRS) specifically assesses suicidal ideation intensity, the presence of suicidal behavior, and the lethality of prior attempts to stratify acute suicide risk. Option A is wrong because depression severity including vegetative and cognitive features is measured by tools such as the PHQ-9 or Hamilton Depression Rating Scale, not the C-SSRS, which focuses on suicidality. Option C is wrong because anxiety severity and panic frequency are assessed by tools such as the GAD-7 or Hamilton Anxiety Scale, which are distinct from the C-SSRS."}, {"id": 245, "domain": "pediatric_care", "question": "A 3-year-old child develops a barking cough, inspiratory stridor, and low-grade fever. Neck X-ray shows a steeple sign. Which diagnosis does this represent?", "options": {"A": "Epiglottitis with thumb sign and high fever requiring airway protection.", "B": "Foreign body aspiration with unilateral wheezing and air trapping.", "C": "Bacterial tracheitis with high fever and pseudomembrane formation.", "D": "Croup (viral laryngotracheobronchitis) with subglottic swelling."}, "correct": "D", "explanation": "Croup (viral laryngotracheobronchitis), most commonly caused by parainfluenza virus, presents with a barking cough, inspiratory stridor, and the steeple sign on anteroposterior neck X-ray from subglottic narrowing. Option A is wrong because epiglottitis presents with a thumb sign on lateral neck X-ray, high fever, drooling, and a toxic-appearing child who sits upright, which is a different and more emergent clinical picture than described. Option C is wrong because bacterial tracheitis is a rare, more severe infection with high fever and a pseudomembranous obstruction that does not produce the typical steeple sign and clinical picture of croup."}, {"id": 250, "domain": "pediatric_care", "question": "A 15-year-old girl has breast budding (thelarche) and pubic hair growth. Her height velocity has increased. Which Tanner stage best describes these findings?", "options": {"A": "Tanner stage 1 representing prepubertal baseline in all parameters.", "B": "Tanner stage 2 representing early puberty with initial breast budding.", "C": "Tanner stage 3 representing continued breast development and pubic hair.", "D": "Tanner stage 4 representing near-adult breast and pubic hair development."}, "correct": "B", "explanation": "Tanner stage 2 represents the earliest signs of puberty including breast budding (thelarche) and initial pubic hair growth, along with the beginning of the pubertal growth velocity increase. Option A is wrong because Tanner stage 1 represents the prepubertal baseline with no breast development, no pubic hair, and a childhood growth rate without a pubertal growth spurt. Option C is wrong because Tanner stage 3 represents continued and more visible breast development beyond budding and denser pubic hair, representing a more advanced stage than what is described."}, {"id": 252, "domain": "pediatric_care", "question": "A 16-year-old girl has BMI of 16, amenorrhea for six months, lanugo, and parotid hypertrophy. She denies purging. What is the most likely diagnosis?", "options": {"A": "Bulimia nervosa with purging behaviors causing parotid hypertrophy.", "B": "Functional hypothalamic amenorrhea without weight changes.", "C": "Avoidant restrictive food intake disorder without body image distortion.", "D": "Anorexia nervosa with restriction causing low weight and amenorrhea."}, "correct": "D", "explanation": "Anorexia nervosa presents with extreme food restriction leading to low body weight, amenorrhea from hypothalamic suppression, lanugo from cold intolerance, and parotid swelling can occur without purging. Option A is wrong because bulimia nervosa involves binge-purge cycles and typically presents at normal or near-normal body weight; a BMI of 16 with amenorrhea points to anorexia rather than bulimia. Option C is wrong because avoidant restrictive food intake disorder (ARFID) does not involve body image distortion or fear of weight gain; patients restrict due to sensory aversions or fear of choking, not to control body weight."}, {"id": 263, "domain": "pediatric_care", "question": "A 14-year-old boy has scrotal swelling with a positive cremasteric reflex on the left. Ultrasound shows a bag-of-worms appearance above the left testicle. What is the diagnosis?", "options": {"A": "Testicular torsion requiring emergent surgical exploration.", "B": "Hydrocele from patent processus vaginalis fluid accumulation.", "C": "Epididymo-orchitis from bacterial infection of the epididymis.", "D": "Varicocele from dilated pampiniform plexus veins."}, "correct": "D", "explanation": "A varicocele presents as a bag-of-worms appearance on ultrasound from dilated pampiniform plexus veins, most commonly on the left side, with a positive cremasteric reflex confirming the testicle is not torsed. Option A is wrong because testicular torsion presents with acute severe scrotal pain, absent cremasteric reflex, and ultrasound showing absent or reduced blood flow, not the bag-of-worms appearance described. Option C is wrong because epididymo-orchitis presents with fever, dysuria, and tender epididymis, typically in sexually active adolescents or men with urinary tract infection, and ultrasound shows increased blood flow."}, {"id": 268, "domain": "pediatric_care", "question": "A 1-year-old is due for well-child vaccines. Which vaccine is only recommended starting at 12 months of age and not given earlier in healthy children?", "options": {"A": "PCV13 (pneumococcal conjugate) first given at 2 months.", "B": "Rotavirus vaccine given at 2, 4, and 6 months of age.", "C": "Hepatitis B first given at birth in the delivery room.", "D": "MMR first given at 12-15 months per the routine schedule."}, "correct": "D", "explanation": "MMR vaccine is first administered at 12-15 months of age as part of the routine childhood immunization schedule because maternal antibodies that can interfere with the vaccine's effectiveness have waned by this age. Option A is wrong because PCV13 (pneumococcal conjugate vaccine) is started at 2 months of age as part of the early infant series, well before the 12-month visit. Option C is wrong because hepatitis B vaccine is first given at birth in the delivery room as part of universal hepatitis B birth-dose programming to prevent vertical transmission."}, {"id": 271, "domain": "pediatric_care", "question": "A 9-month-old infant has been exclusively formula-fed since birth. Which nutrient supplementation is recommended for exclusively formula-fed infants?", "options": {"A": "Vitamin D drops because formula does not contain vitamin D.", "B": "Iron drops because formula is not fortified with adequate iron.", "C": "No supplementation is needed because formula is nutritionally complete.", "D": "Vitamin C drops because formula lacks adequate ascorbic acid."}, "correct": "C", "explanation": "Standard commercial infant formulas are fortified with vitamin D, iron, and other nutrients to meet infant nutritional requirements, so no additional supplementation is needed for formula-fed infants. Option A is wrong because iron-fortified formula provides adequate vitamin D; vitamin D supplementation is recommended for breastfed infants, not formula-fed infants receiving adequate formula volumes. Option B is wrong because commercial iron-fortified infant formula contains sufficient iron to meet infant daily requirements; iron drops are recommended for breastfed infants after 4-6 months, not for formula-fed infants."}, {"id": 275, "domain": "professional_practice", "question": "According to USPSTF guidelines, at what age should colorectal cancer screening begin in average-risk adults without a family history or prior polyps?", "options": {"A": "Age 40 using colonoscopy as the preferred initial screening method.", "B": "Age 45 for all average-risk adults through age 75.", "C": "Age 50 for all average-risk adults regardless of race or ethnicity.", "D": "Age 55 because colorectal cancer risk increases significantly after menopause."}, "correct": "B", "explanation": "USPSTF recommends colorectal cancer screening beginning at age 45 for all average-risk adults through age 75 using any of the recommended screening methods. Option A is wrong because age 40 is not the current USPSTF recommendation for average-risk colorectal cancer screening; the 2021 guidelines updated the starting age from 50 to 45. Option C is wrong because age 50 was the previous USPSTF recommendation, which was lowered to age 45 in 2021 to capture earlier-onset colorectal cancers in younger adults."}, {"id": 280, "domain": "professional_practice", "question": "USPSTF recommends screening for prediabetes and type 2 diabetes in adults beginning at what age with no symptoms?", "options": {"A": "Age 35 in overweight or obese adults per current USPSTF guidelines.", "B": "Age 40 for all adults regardless of weight or risk factors.", "C": "Age 45 for all adults regardless of weight as a universal screen.", "D": "Age 50 for overweight adults with one or more diabetes risk factors."}, "correct": "A", "explanation": "USPSTF recommends screening for prediabetes and type 2 diabetes in adults aged 35 to 70 who are overweight or obese, having lowered the starting age from 40 to 35 in the 2021 update. Option B is wrong because age 40 for all adults regardless of weight was a previous iteration of guidance, but the current USPSTF recommendation is age 35 and specifically targets overweight or obese individuals rather than the entire adult population. Option C is wrong because age 45 for all adults regardless of weight is not the USPSTF recommendation; the guideline targets overweight and obese adults beginning at age 35 rather than applying universally by age alone."}, {"id": 281, "domain": "professional_practice", "question": "Which adult immunization is recommended annually for all persons aged 6 months and older without contraindications?", "options": {"A": "Pneumococcal vaccine recommended annually for all adults.", "B": "Influenza vaccine recommended annually for all adults.", "C": "Tdap booster recommended annually for all adults over 65.", "D": "MMR vaccine recommended annually for immunocompromised adults."}, "correct": "B", "explanation": "Annual influenza vaccination is recommended for all persons aged 6 months and older without contraindications to reduce seasonal influenza illness, hospitalization, and death. Option A is wrong because pneumococcal vaccine is not given annually; it is administered on a schedule based on age, health conditions, and prior vaccination history, not repeated every year. Option C is wrong because Tdap booster is not recommended annually for all adults; it is given once as an adult booster and then every 10 years as Td, with Tdap recommended in each pregnancy."}, {"id": 282, "domain": "professional_practice", "question": "A Tdap vaccine was administered to a 30-year-old patient five years ago. She is now pregnant at 32 weeks. When should Tdap be given in pregnancy?", "options": {"A": "Tdap should be deferred until after delivery to protect the newborn.", "B": "Tdap is contraindicated in pregnancy and should be given postpartum.", "C": "Tdap is given only at the first prenatal visit regardless of gestational age.", "D": "Tdap is recommended during each pregnancy between 27-36 weeks gestation."}, "correct": "D", "explanation": "Tdap is recommended during every pregnancy between 27 and 36 weeks gestation to maximize transplacental antibody transfer to the infant before birth, regardless of prior Tdap history. Option A is wrong because deferring Tdap until after delivery reduces the transplacental protection to the newborn; the optimal window is during pregnancy to allow antibody transfer to the fetus. Option C is wrong because Tdap should be given in the 27-36 week window for maximum benefit, not simply at the first prenatal visit which may be well before this optimal gestational period."}, {"id": 286, "domain": "professional_practice", "question": "Schedule II controlled substances such as oxycodone have which prescribing restriction compared to Schedule III-V substances?", "options": {"A": "Schedule II prescriptions may have up to five refills within six months.", "B": "Schedule II prescriptions require renewal every 30 days without exception.", "C": "Schedule II prescriptions allow up to three refills within three months.", "D": "Schedule II prescriptions may not be refilled and require a new prescription."}, "correct": "D", "explanation": "Schedule II controlled substances such as oxycodone, amphetamines, and fentanyl may not be refilled; a new written prescription is required for each dispensing, which is a key federal DEA restriction. Option A is wrong because Schedule II prescriptions have no refills permitted; up to five refills within six months applies to Schedule III-V substances, not Schedule II. Option C is wrong because Schedule II prescriptions allow zero refills, not three refills; the no-refill rule is a defining restriction that distinguishes Schedule II from less strictly controlled substance schedules."}, {"id": 292, "domain": "professional_practice", "question": "A durable power of attorney for healthcare designates a person to make medical decisions when the patient is incapacitated. What does this legal document authorize?", "options": {"A": "Management of financial affairs and property during incapacitation.", "B": "Legal guardianship over the patient's children during hospitalization.", "C": "Authorization for the designee to consent to surgery on behalf of providers.", "D": "Healthcare decision-making authority when the patient cannot decide."}, "correct": "D", "explanation": "A durable power of attorney for healthcare (healthcare proxy) authorizes a designated person to make medical decisions on behalf of the patient when that patient lacks the capacity to decide for themselves. Option A is wrong because a durable power of attorney for finances or property is a separate legal document; a healthcare durable power of attorney specifically covers medical decisions, not financial or estate matters. Option C is wrong because the designated healthcare proxy provides consent on behalf of the patient to providers; it does not authorize the designee to perform medical procedures themselves."}, {"id": 298, "domain": "professional_practice", "question": "A 72-year-old man with multiple chronic conditions wants to complete a POLST form. What does a POLST form primarily address?", "options": {"A": "Financial management and estate planning during end-of-life care.", "B": "Medical orders for life-sustaining treatment preferences.", "C": "Designation of a healthcare proxy in case of incapacity.", "D": "Legal authorization for organ and tissue donation after death."}, "correct": "B", "explanation": "A POLST (Physician Orders for Life-Sustaining Treatment) form contains actual medical orders regarding resuscitation, intubation, hospitalization, and artificial nutrition that are immediately actionable by healthcare providers. Option A is wrong because financial management and estate planning are handled through separate legal instruments such as a durable power of attorney for finances or a will, not a POLST form. Option C is wrong because designation of a healthcare proxy is accomplished through a durable power of attorney for healthcare or healthcare proxy designation form, not a POLST, which focuses on specific medical treatment orders."}, {"id": 301, "domain": "professional_practice", "question": "A 68-year-old patient takes warfarin. She reports using a daily aspirin. How does the combination of warfarin and aspirin affect bleeding risk?", "options": {"A": "Aspirin reduces warfarin absorption and lowers bleeding risk.", "B": "Aspirin and warfarin are routinely combined without increased risk.", "C": "Aspirin decreases warfarin metabolism and reduces anticoagulant effect.", "D": "Aspirin increases bleeding risk via antiplatelet and GI mucosal effects."}, "correct": "D", "explanation": "Aspirin increases bleeding risk when combined with warfarin through two mechanisms: its antiplatelet effect reduces platelet-mediated clot formation, and its gastric mucosal injury increases GI bleeding risk. Option A is wrong because aspirin does not reduce warfarin absorption; in fact, the combination increases bleeding risk rather than lowering it, and the mechanism involves pharmacodynamic interactions, not absorption interference. Option C is wrong because aspirin does not decrease warfarin metabolism or reduce anticoagulant effect; at high doses it may displace warfarin from protein binding, which would increase rather than reduce anticoagulant effect."}, {"id": 302, "domain": "professional_practice", "question": "A 45-year-old male patient requests a letter for work disability. Which principle requires the NP to provide objective, accurate information?", "options": {"A": "Beneficence, requiring the NP to advocate for the patient's needs.", "B": "Autonomy, respecting the patient's request for documentation.", "C": "Justice, requiring equal access to disability benefits for all patients.", "D": "Veracity, requiring truthful and accurate communication in documentation."}, "correct": "D", "explanation": "Veracity is the ethical principle requiring healthcare providers to communicate truthful, accurate, and objective information in all clinical documentation, including disability letters. Option A is wrong because beneficence involves actions that promote the patient's well-being, but writing an inaccurate or exaggerated disability letter to advocate for the patient's interests would violate the principle of veracity. Option C is wrong because justice addresses equitable distribution of resources across populations and does not specifically govern the accuracy of individual clinical documentation or disability assessments."}, {"id": 303, "domain": "professional_practice", "question": "Which USPSTF recommendation addresses screening for intimate partner violence (IPV) in women of reproductive age?", "options": {"A": "Grade D: USPSTF recommends against screening for IPV in all women.", "B": "Grade B: USPSTF recommends screening women of reproductive age for IPV.", "C": "Grade C: USPSTF recommends selective screening based on risk factors.", "D": "Grade I: Insufficient evidence to assess IPV screening in all women."}, "correct": "B", "explanation": "USPSTF gives a Grade B recommendation for screening women of reproductive age for intimate partner violence and referring those who screen positive to ongoing support services. Option A is wrong because a Grade D recommendation means USPSTF recommends against screening, which is the opposite of the actual Grade B recommendation for IPV screening in women of reproductive age. Option C is wrong because Grade C indicates selective use of a preventive service only for certain individuals; USPSTF's Grade B indicates that the recommendation applies broadly to women of reproductive age, not just those with specific risk factors."}, {"id": 313, "domain": "pharmacology", "question": "Which antibiotic class is associated with QT interval prolongation and an increased risk of torsades de pointes when combined with other QT-prolonging agents?", "options": {"A": "Penicillins, which have no significant QT prolongation risk.", "B": "Fluoroquinolones such as ciprofloxacin and levofloxacin.", "C": "Aminoglycosides such as gentamicin with nephrotoxicity risk.", "D": "Carbapenems such as meropenem with seizure risk at high doses."}, "correct": "B", "explanation": "Fluoroquinolones such as ciprofloxacin and levofloxacin are associated with QT interval prolongation through cardiac potassium channel blockade, increasing the risk of torsades de pointes especially when combined with other QT-prolonging agents. Option A is wrong because penicillins such as amoxicillin and ampicillin do not cause QT prolongation; they work by inhibiting bacterial cell wall synthesis and have no significant cardiac channel effects. Option C is wrong because aminoglycosides are associated with nephrotoxicity and ototoxicity rather than QT prolongation; they are not a drug class known for causing torsades de pointes."}, {"id": 315, "domain": "pharmacology", "question": "Which medication is classified as FDA Pregnancy Category X (now high risk under PLLR) due to well-documented teratogenicity?", "options": {"A": "Acetaminophen, generally considered safe at standard doses in pregnancy.", "B": "Warfarin, which causes fetal warfarin syndrome with first-trimester use.", "C": "Penicillin, which has an excellent safety profile throughout pregnancy.", "D": "Methyldopa, historically used and considered safe in pregnant women."}, "correct": "B", "explanation": "Warfarin is teratogenic and causes fetal warfarin syndrome when used during the first trimester, including nasal hypoplasia, bone stippling, and central nervous system abnormalities, warranting its Category X (high risk) classification in pregnancy. Option A is wrong because acetaminophen is generally considered safe at standard therapeutic doses during pregnancy and does not carry the same teratogenic risk that warrants a Category X classification. Option C is wrong because penicillin has an excellent safety record throughout pregnancy with no documented teratogenic effects, making it one of the most commonly used antibiotics in pregnant patients."}, {"id": 317, "domain": "pharmacology", "question": "A patient with severe renal impairment (GFR 20 mL/min) requires antibiotic therapy. Which antibiotic requires the most significant dose reduction in renal failure?", "options": {"A": "Azithromycin, which is primarily hepatically metabolized without renal adjustment.", "B": "Moxifloxacin, which is not significantly renally cleared.", "C": "Doxycycline, which is primarily biliarily excreted without renal adjustment.", "D": "Vancomycin, which is 90% renally excreted and requires dose adjustment."}, "correct": "D", "explanation": "Vancomycin is approximately 90% renally excreted and accumulates significantly in patients with renal impairment, requiring dose adjustment based on pharmacokinetic monitoring to avoid nephrotoxicity and ototoxicity. Option A is wrong because azithromycin is primarily metabolized hepatically and excreted in bile with minimal renal elimination, so it requires no significant dose adjustment in patients with reduced GFR. Option C is wrong because doxycycline is primarily eliminated through biliary and fecal routes rather than renal excretion, making it one of the few antibiotics that does not require dose adjustment in renal failure."}, {"id": 323, "domain": "pharmacology", "question": "Which medication requires adjustment of dosing interval in patients with impaired renal function due to risk of lactic acidosis accumulation?", "options": {"A": "Sitagliptin, a DPP-4 inhibitor requiring dose reduction in renal impairment.", "B": "Metformin, a biguanide contraindicated when GFR falls below 30.", "C": "Glipizide, a sulfonylurea with renal clearance requiring dose reduction.", "D": "Pioglitazone, a thiazolidinedione not significantly renally cleared."}, "correct": "B", "explanation": "Metformin is contraindicated when GFR falls below 30 mL/min/1.73m2 because impaired renal clearance leads to metformin accumulation and increased risk of potentially fatal lactic acidosis. Option A is wrong because sitagliptin does require dose reduction in renal impairment, but the question asks about the drug that requires adjustment specifically due to lactic acidosis accumulation risk, which is uniquely associated with metformin. Option C is wrong because glipizide does have some active metabolites that are renally cleared and carries a risk of hypoglycemia in renal impairment, but lactic acidosis is not the mechanism of toxicity for sulfonylureas."}, {"id": 324, "domain": "pharmacology", "question": "A 45-year-old man on warfarin starts taking St. John's Wort for depression. What pharmacokinetic effect should the provider anticipate?", "options": {"A": "St. John's Wort inhibits CYP enzymes increasing warfarin levels.", "B": "St. John's Wort induces CYP3A4 and P-gp reducing warfarin levels.", "C": "St. John's Wort has no significant interaction with warfarin metabolism.", "D": "St. John's Wort displaces warfarin from plasma proteins increasing effect."}, "correct": "B", "explanation": "St. John's Wort is a potent inducer of CYP3A4 and P-glycoprotein, significantly increasing warfarin metabolism and reducing its plasma levels, which can lead to subtherapeutic anticoagulation and thromboembolic risk. Option A is wrong because St."}, {"id": 326, "domain": "pharmacology", "question": "A patient taking phenytoin is started on a new medication that inhibits CYP2C9. What effect is expected on phenytoin levels?", "options": {"A": "Phenytoin levels decrease due to enhanced CYP2C9 substrate competition.", "B": "Phenytoin levels decrease due to increased protein binding displacement.", "C": "Phenytoin levels are unaffected because CYP2C9 is not its primary pathway.", "D": "Phenytoin levels increase because its metabolism is inhibited."}, "correct": "D", "explanation": "Phenytoin is primarily metabolized by CYP2C9, so co-administration of a CYP2C9 inhibitor reduces phenytoin clearance, causing levels to rise and increasing the risk of phenytoin toxicity including nystagmus, ataxia, and mental status changes. Option A is wrong because CYP2C9 inhibition decreases metabolism of phenytoin as a substrate, causing levels to rise rather than fall; the inhibitor reduces competitive clearance of the drug it metabolizes. Option C is wrong because CYP2C9 is indeed the primary metabolic pathway for phenytoin; stating it is unaffected by CYP2C9 inhibition is factually incorrect and clinically dangerous."}, {"id": 327, "domain": "pharmacology", "question": "Which NSAID is preferred in patients with mild-to-moderate pain and a high cardiovascular risk due to its platelet-sparing mechanism compared to other NSAIDs?", "options": {"A": "Ibuprofen because it is the safest NSAID in cardiovascular disease.", "B": "Celecoxib, a selective COX-2 inhibitor with lower platelet effects.", "C": "Naproxen because it has the most favorable cardiovascular risk profile.", "D": "Diclofenac because its anti-inflammatory effect outweighs cardiac risk."}, "correct": "C", "explanation": "Naproxen has the most favorable cardiovascular risk profile among traditional NSAIDs, with studies suggesting it does not increase cardiovascular event risk as significantly as other NSAIDs like diclofenac or high-dose ibuprofen. Option A is wrong because ibuprofen at high doses has been shown to have cardiovascular risks including increased myocardial infarction risk, and it can also interfere with the antiplatelet effect of aspirin when taken together. Option B is wrong because celecoxib is a selective COX-2 inhibitor with lower GI bleeding risk and platelet effects, but it carries similar or potentially higher cardiovascular risk compared to non-selective NSAIDs in high-risk patients."}, {"id": 328, "domain": "pharmacology", "question": "A 32-year-old woman with epilepsy on carbamazepine starts combined oral contraceptives. Which pharmacokinetic concern should be addressed?", "options": {"A": "COCs inhibit carbamazepine metabolism increasing seizure risk.", "B": "Carbamazepine induces CYP3A4 reducing COC efficacy and raising pregnancy risk.", "C": "COCs and carbamazepine have no clinically significant drug interaction.", "D": "Carbamazepine inhibits COC absorption through gastric motility effects."}, "correct": "B", "explanation": "Carbamazepine is a potent CYP3A4 inducer that significantly increases the metabolism of combined oral contraceptives, reducing their plasma levels and potentially causing contraceptive failure with unintended pregnancy. Option A is wrong because COCs do not inhibit carbamazepine metabolism; the pharmacokinetic interaction is unidirectional, with carbamazepine inducing the enzymes that metabolize contraceptive hormones. Option C is wrong because there is a well-documented and clinically significant drug interaction between carbamazepine and oral contraceptives; providers must recommend additional or alternative contraception methods to women taking this antiepileptic drug."}, {"id": 329, "domain": "pharmacology", "question": "A patient with a GFR of 25 mL/min needs pain management. Which opioid is preferred because its active metabolites accumulate less in renal failure?", "options": {"A": "Morphine.", "B": "Oxycodone.", "C": "Hydromorphone at reduced doses because renal clearance is impaired.", "D": "Fentanyl."}, "correct": "D", "explanation": "Fentanyl is the preferred opioid in patients with significant renal impairment because it has no active renally-cleared metabolites, making it less likely to accumulate and cause toxicity in kidney disease. Option A is wrong because morphine produces an active metabolite called morphine-6-glucuronide (M6G) that accumulates significantly in renal failure, causing prolonged respiratory depression and sedation, making morphine a poor choice in this patient. Option B is wrong because oxycodone has active metabolites including oxymorphone that are renally cleared and can accumulate in renal failure, increasing the risk of opioid toxicity with repeated dosing."}, {"id": 331, "domain": "pharmacology", "question": "A 60-year-old man on warfarin is started on ciprofloxacin. Which monitoring recommendation applies?", "options": {"A": "No monitoring needed because fluoroquinolones do not affect warfarin.", "B": "Increase warfarin dose empirically when starting ciprofloxacin.", "C": "Monitor INR closely because ciprofloxacin may increase warfarin effect.", "D": "Switch to LMWH whenever any antibiotic is added to warfarin therapy."}, "correct": "C", "explanation": "Ciprofloxacin can inhibit CYP1A2 and other enzymatic pathways affecting warfarin metabolism, and it may also disrupt gut flora involved in vitamin K synthesis, both of which can increase the anticoagulant effect and raise INR. Option A is wrong because fluoroquinolones including ciprofloxacin do interact with warfarin through metabolic and pharmacodynamic mechanisms; monitoring the INR when adding ciprofloxacin to warfarin is a recognized clinical recommendation. Option B is wrong because empirically increasing the warfarin dose when starting ciprofloxacin would risk over-anticoagulation and bleeding; the appropriate action is close INR monitoring and dose adjustment based on measured response."}, {"id": 334, "domain": "pharmacology", "question": "A patient on amiodarone is also taking warfarin. Which dosing recommendation applies when this combination is used?", "options": {"A": "Warfarin dose should be increased because amiodarone reduces its effect.", "B": "Warfarin dose should be reduced because amiodarone inhibits CYP2C9.", "C": "No dose adjustment is needed because amiodarone is renally cleared.", "D": "Warfarin should be discontinued and replaced with apixaban instead."}, "correct": "B", "explanation": "Amiodarone inhibits CYP2C9 (and CYP3A4), which is the primary enzyme metabolizing warfarin, leading to reduced warfarin clearance and elevated INR that typically requires a warfarin dose reduction of 30-50%. Option A is wrong because amiodarone inhibits, not induces, warfarin metabolism, so increasing the warfarin dose would cause over-anticoagulation and serious bleeding risk rather than correcting it. Option C is wrong because amiodarone has a significant and well-documented pharmacokinetic interaction with warfarin through CYP2C9 inhibition; stating no dose adjustment is needed would be a clinically dangerous error."}, {"id": 338, "domain": "primary_care_medicine", "question": "A 66-year-old man with a 10-year cardiovascular risk of 12% has an LDL of 128 mg/dL and no prior cardiovascular events. He is otherwise healthy. What is the most appropriate next step?", "options": {"A": "Initiate moderate-intensity statin therapy to reduce cardiovascular risk.", "B": "Recommend lifestyle modifications and recheck lipids in 12 months.", "C": "Initiate high-intensity statin therapy targeting LDL below 70 mg/dL.", "D": "Add a fibrate to target triglycerides and raise HDL cholesterol."}, "correct": "A", "explanation": "A 10-year cardiovascular risk of 12% places this patient in the intermediate risk category, where guidelines recommend a moderate-intensity statin to reduce cardiovascular events. Lifestyle modifications alone are insufficient at this risk level when LDL is elevated, so lifestyle changes without a statin would not fully address the risk. High-intensity statin therapy targeting LDL below 70 is reserved for very high-risk patients such as those with prior heart attacks or established cardiovascular disease."}, {"id": 340, "domain": "primary_care_medicine", "question": "A 70-year-old woman with COPD and a history of two exacerbations in the past year remains symptomatic on a long-acting bronchodilator alone. What is the best next step in her management?", "options": {"A": "Add a short-acting beta-agonist for rescue use only as needed.", "B": "Switch to an inhaled corticosteroid monotherapy to reduce inflammation.", "C": "Add an inhaled corticosteroid plus a second long-acting bronchodilator.", "D": "Start oral prednisone taper to reduce airway inflammation acutely."}, "correct": "C", "explanation": "Adding an inhaled corticosteroid and a second long-acting bronchodilator is the recommended escalation for COPD patients with frequent exacerbations who remain symptomatic on a single long-acting bronchodilator. A short-acting beta-agonist for rescue use alone does not address the underlying inflammation or prevent future exacerbations. Switching to inhaled corticosteroid monotherapy is not recommended in COPD as it should be combined with a long-acting bronchodilator for adequate symptom control."}, {"id": 343, "domain": "primary_care_medicine", "question": "A 34-year-old man presents to the clinic with acute severe asthma exacerbation. He is speaking in phrases, using accessory muscles, and his peak flow is 45% of predicted. What is the priority intervention?", "options": {"A": "Administer systemic corticosteroids and repeat albuterol nebulizations.", "B": "Prescribe a short oral steroid burst and have him use his inhaler at home.", "C": "Start ipratropium nebulization alone and reassess in 30 minutes.", "D": "Order a chest X-ray to exclude pneumonia before starting treatment."}, "correct": "A", "explanation": "Systemic corticosteroids combined with repeated albuterol nebulizations are the priority interventions in a severe asthma exacerbation with accessory muscle use and a peak flow of 45% predicted. Sending the patient home with a steroid burst and inhaler is inappropriate because he is using accessory muscles and has a severely reduced peak flow requiring urgent treatment. Ipratropium alone is insufficient for a severe attack; it is used as an add-on to albuterol, not as single-agent therapy."}, {"id": 344, "domain": "primary_care_medicine", "question": "A 45-year-old woman with hypothyroidism on levothyroxine 75 mcg daily has a TSH of 8.2 mIU/L at her follow-up visit. She reports fatigue and cold intolerance. What is the most appropriate adjustment?", "options": {"A": "Add liothyronine to her regimen to supplement T3 levels immediately.", "B": "Increase levothyroxine dose by 12.5 to 25 mcg and recheck TSH in 6 weeks.", "C": "Switch to desiccated thyroid extract as she is not responding to levothyroxine.", "D": "Recheck TSH in 6 months as TSH fluctuation is expected and self-limiting."}, "correct": "B", "explanation": "A TSH of 8.2 with symptoms of hypothyroidism means the current levothyroxine dose is inadequate, so increasing by 12.5 to 25 mcg and rechecking TSH in 6 weeks is the standard approach. Adding liothyronine is not standard first-line management for undertreated hypothyroidism and can cause erratic T3 levels. Switching to desiccated thyroid extract is not warranted when simple dose adjustment of levothyroxine is the appropriate next step."}, {"id": 348, "domain": "primary_care_medicine", "question": "A 31-year-old woman presents with six months of bloody diarrhea, tenesmus, and urgency. Colonoscopy shows continuous mucosal inflammation from the rectum to the splenic flexure. What is the most appropriate initial treatment?", "options": {"A": "Initiate mesalamine rectally and orally as first-line therapy.", "B": "Start a high-fiber diet and probiotics to reduce bowel inflammation.", "C": "Start prednisone 60 mg daily until symptoms fully resolve.", "D": "Refer for surgical evaluation as this extent of disease requires colectomy."}, "correct": "A", "explanation": "Mesalamine given both rectally and orally is the first-line treatment for mild to moderate ulcerative colitis with disease extending to the splenic flexure. A high-fiber diet and probiotics are not evidence-based treatments for active ulcerative colitis and will not adequately control the mucosal inflammation. High-dose prednisone is used for moderate to severe refractory ulcerative colitis, not as first-line therapy for an initial presentation with continuous distal disease."}, {"id": 349, "domain": "primary_care_medicine", "question": "A 52-year-old unvaccinated man needs to start the hepatitis B vaccine series. He has no history of liver disease or prior immunization. What is the standard adult vaccination schedule?", "options": {"A": "One dose only, as adults require less immunization than children.", "B": "Two-dose series given one month apart using the higher-dose formulation.", "C": "Three-dose series at 0, 1, and 6 months using the standard adult formulation.", "D": "Three doses at 0, 2, and 4 months using the pediatric low-dose formulation."}, "correct": "C", "explanation": "The standard adult hepatitis B vaccine series is three doses given at 0, 1, and 6 months using the adult formulation to provide adequate immunity. A single dose is not sufficient and does not provide durable protection against hepatitis B. The two-dose series using a higher-dose formulation is available but is a newer alternative, and the classic three-dose schedule is the established standard for unvaccinated adults."}, {"id": 352, "domain": "primary_care_medicine", "question": "A 59-year-old man has a 6 mm pulmonary nodule found incidentally on a CT of the chest done for another reason. He has a 30 pack-year smoking history. What is the most appropriate next step?", "options": {"A": "Reassure the patient and repeat CT in 12 months as a routine follow-up.", "B": "Refer immediately for surgical resection given his high-risk smoking history.", "C": "Perform CT-guided biopsy now to obtain tissue diagnosis before any other step.", "D": "Repeat low-dose CT in 3 to 6 months per high-risk nodule surveillance guidelines."}, "correct": "D", "explanation": "A 6 mm pulmonary nodule in a high-risk patient such as a heavy smoker requires repeat low-dose CT in 3 to 6 months per Fleischner Society guidelines for high-risk patients. Reassurance with a 12-month CT is appropriate for low-risk patients with small nodules but not for a heavy smoker with a 6 mm nodule. Immediate surgical resection is not warranted without tissue diagnosis or evidence of growth, as many nodules in smokers are benign."}, {"id": 358, "domain": "primary_care_medicine", "question": "A 50-year-old man with no prior cardiovascular events has an LDL of 165 mg/dL, a 10-year ASCVD risk of 8%, hypertension, and a family history of early MI. What is the best next step?", "options": {"A": "Lifestyle counseling only; his 10-year risk does not yet meet statin threshold.", "B": "Initiate a high-intensity statin targeting LDL below 55 mg/dL immediately.", "C": "Use a risk-enhancing factor discussion to guide shared decision for statin therapy.", "D": "Order a coronary calcium score; if zero, no statin is needed at this time."}, "correct": "C", "explanation": "When a patient has a 10-year risk between 7.5% and 10% and risk-enhancing factors such as family history of early MI and hypertension, guidelines recommend a shared decision-making discussion about statin therapy rather than automatic initiation or exclusion. Lifestyle counseling alone is insufficient given the risk-enhancing features that push this patient toward statin benefit. High-intensity statin targeting LDL below 55 is reserved for very high-risk patients with established cardiovascular disease or diabetes."}, {"id": 363, "domain": "primary_care_medicine", "question": "A 42-year-old woman with Crohn's disease is maintained on azathioprine. She presents with a right lower quadrant mass and persistent pain. CT shows a fistula. What is the most appropriate next step?", "options": {"A": "Increase the azathioprine dose and add prednisone for acute flare management.", "B": "Start metronidazole and ciprofloxacin for the fistula and reassess in four weeks.", "C": "Refer to gastroenterology and surgery for evaluation of fistula management.", "D": "Order a barium enema to delineate fistula anatomy before any intervention."}, "correct": "C", "explanation": "A fistula in Crohn's disease with a right lower quadrant mass is a complex complication requiring evaluation by both gastroenterology and surgery to determine whether medical therapy, biologic agents, or surgical management is most appropriate. Increasing azathioprine and adding prednisone alone does not adequately address a fistula, which may require biologic therapy or surgical intervention. Antibiotics such as metronidazole and ciprofloxacin may be used as adjuncts but are not sufficient as primary management for a complex fistula with a palpable mass."}, {"id": 375, "domain": "primary_care_medicine", "question": "A 35-year-old man presents with painless hematuria. He is a non-smoker with no urinary symptoms. Urinalysis shows 15 RBCs per high-power field and no protein. What is the most appropriate next step?", "options": {"A": "Repeat urinalysis in six weeks; hematuria in young men is almost always benign.", "B": "Start antibiotics empirically for presumed urinary tract infection.", "C": "Order cystoscopy and CT urogram to evaluate the urinary tract for pathology.", "D": "Refer to nephrology for a kidney biopsy to rule out glomerulonephritis."}, "correct": "C", "explanation": "Painless hematuria without obvious cause in a non-smoker requires cystoscopy and CT urogram to evaluate the entire urinary tract for malignancy, stones, or structural pathology. Repeating the urinalysis in six weeks is inappropriate because significant hematuria of 15 RBCs per high-power field in an adult requires formal evaluation of the urinary tract. Starting antibiotics empirically for presumed UTI is incorrect because there are no symptoms of infection and hematuria alone requires further investigation."}, {"id": 381, "domain": "primary_care_medicine", "question": "A 47-year-old man with no prior cardiac history has a new diagnosis of hypertension at 155/98 mmHg. He has no comorbidities. Which medication is the most appropriate first-line choice?", "options": {"A": "Metoprolol tartrate, given its good tolerability as a first-line agent.", "B": "Spironolactone, which is preferred for uncomplicated hypertension in adults.", "C": "Lisinopril, amlodipine, or chlorthalidone as equivalent first-line options.", "D": "Hydralazine, which is safe and effective for non-urgent hypertension management."}, "correct": "C", "explanation": "For uncomplicated hypertension without specific comorbidities, guidelines recognize lisinopril, amlodipine, and chlorthalidone as equivalent first-line options with strong evidence for reducing cardiovascular events. Metoprolol tartrate is not a first-line agent for uncomplicated hypertension because beta-blockers are generally reserved for patients with specific indications like heart failure or post-MI. Spironolactone is used for resistant hypertension or specific conditions like primary hyperaldosteronism, not as a routine first-line agent for uncomplicated hypertension."}, {"id": 383, "domain": "primary_care_medicine", "question": "A 72-year-old man with heart failure and reduced ejection fraction of 35% has a blood pressure of 110/72 mmHg and heart rate of 88 bpm. He is not on a beta-blocker. What is the most appropriate action?", "options": {"A": "Beta-blockers are contraindicated in heart failure; avoid starting them.", "B": "Start ivabradine immediately to control heart rate in heart failure.", "C": "Start a low-dose beta-blocker and titrate up slowly over weeks to months.", "D": "Hold all new medications until his ejection fraction improves above 40%."}, "correct": "C", "explanation": "Beta-blockers such as carvedilol or metoprolol succinate are indicated and mortality-reducing in stable heart failure with reduced ejection fraction, and should be started at low doses and titrated up slowly. The belief that beta-blockers are contraindicated in heart failure is outdated; they are a cornerstone of HFrEF therapy when the patient is stable. Ivabradine is used only when beta-blockers are not tolerated or heart rate remains above 70 despite a maximally tolerated beta-blocker dose."}, {"id": 387, "domain": "primary_care_medicine", "question": "A 63-year-old man with CKD stage 4 has an eGFR of 22 mL/min and is on metformin 1,000 mg twice daily. His last creatinine is 3.6 mg/dL. What action is most appropriate regarding his metformin?", "options": {"A": "Continue current dose; metformin is safe at any stage of CKD.", "B": "Reduce metformin to 500 mg twice daily and recheck creatinine monthly.", "C": "Discontinue metformin due to risk of lactic acidosis at this level of renal function.", "D": "Switch to metformin extended-release, which is safer in advanced CKD."}, "correct": "C", "explanation": "Metformin is contraindicated when eGFR falls below 30 mL/min due to the risk of lactic acidosis from drug accumulation in severe renal impairment, and this patient has an eGFR consistent with stage 4 CKD. Continuing metformin at any dose when eGFR is this low poses an unacceptable risk of lactic acidosis, a potentially fatal complication. Reducing the dose does not eliminate the risk at this level of renal impairment; the drug should be stopped."}, {"id": 394, "domain": "primary_care_medicine", "question": "A 52-year-old man with long-standing GERD reports continued symptoms on omeprazole 20 mg once daily. He has no dysphagia or weight loss. What is the most appropriate adjustment?", "options": {"A": "Switch to a different PPI and increase the dose to twice daily taken before meals.", "B": "Add a histamine-2 receptor blocker at bedtime to provide additional acid suppression.", "C": "Refer for endoscopy to rule out Barrett's esophagus before any medication change.", "D": "Add sucralfate to coat the esophagus and provide additional mucosal protection."}, "correct": "A", "explanation": "When GERD symptoms persist on once-daily PPI at a low dose, switching to twice-daily dosing of a PPI taken 30 to 60 minutes before meals is the appropriate escalation for better acid suppression. Adding an H2 blocker at bedtime may provide some benefit but is not the primary escalation step when the PPI dose itself can be optimized first. Referring for endoscopy is important if there are alarm symptoms like dysphagia or weight loss, which are not present in this case."}, {"id": 396, "domain": "primary_care_medicine", "question": "A 76-year-old woman with atrial fibrillation, hypertension, and diabetes is on apixaban. Her renal function shows a creatinine of 1.9 mg/dL and eGFR of 28 mL/min. What adjustment is needed?", "options": {"A": "Reduce apixaban to 2.5 mg twice daily if two of three dosing criteria are met.", "B": "Switch to warfarin as it is safer than DOACs in advanced kidney disease.", "C": "Stop apixaban due to contraindication in any level of renal impairment.", "D": "No dose adjustment needed as apixaban is safe at standard doses in CKD."}, "correct": "A", "explanation": "Apixaban dose should be reduced to 2.5 mg twice daily when two of three criteria are met: age 80 or older, weight 60 kg or less, or creatinine 1.5 mg/dL or greater; this patient meets two criteria, so the dose reduction applies. Switching to warfarin is not recommended because DOACs including apixaban are generally preferred over warfarin even in reduced renal function, unless eGFR falls below 15. Stopping apixaban entirely is not warranted as apixaban can be used with dose adjustment in patients with CKD who meet dosing criteria."}, {"id": 398, "domain": "primary_care_medicine", "question": "A 70-year-old man with COPD, heart failure, and hypertension needs blood pressure control. His blood pressure is 145/88 mmHg and he is already on a diuretic. Which additional antihypertensive is most appropriate?", "options": {"A": "Metoprolol succinate, which benefits both heart failure and hypertension management.", "B": "Atenolol, which reduces heart rate and blood pressure without cardiac benefit.", "C": "Verapamil, a calcium channel blocker with negative inotropic properties in HF.", "D": "Clonidine, which has a good safety profile in older patients with comorbidities."}, "correct": "A", "explanation": "Metoprolol succinate is a cardioselective beta-blocker that provides proven survival benefit in heart failure with reduced ejection fraction and also lowers blood pressure, addressing both of this patient's conditions. Atenolol lowers blood pressure but is not recommended for heart failure because it lacks the mortality benefit evidence that carvedilol and metoprolol succinate have in HFrEF. Verapamil has negative inotropic effects and is contraindicated in heart failure with reduced ejection fraction because it can worsen cardiac function."}, {"id": 400, "domain": "primary_care_medicine", "question": "A 58-year-old man with a 15-year smoking history and no current symptoms is at the clinic for a routine annual visit. What lung cancer screening is recommended for this patient?", "options": {"A": "Annual chest X-ray to screen for lung cancer given his smoking history.", "B": "Sputum cytology annually combined with a clinical exam every six months.", "C": "Annual low-dose CT chest screening given his age and smoking history.", "D": "No screening is recommended as he has no respiratory symptoms currently."}, "correct": "C", "explanation": "A 58-year-old man with a 15-year smoking history meets the USPSTF criteria for annual low-dose CT lung cancer screening for adults aged 50 to 80 with at least a 20 pack-year history who currently smoke or quit within the past 15 years. Annual chest X-ray is not recommended for lung cancer screening because it does not reduce lung cancer mortality and is an inferior screening tool compared to low-dose CT. Sputum cytology is not a recommended screening strategy for lung cancer in asymptomatic individuals."}, {"id": 405, "domain": "primary_care_medicine", "question": "A 39-year-old man has an acute episode of gout in his right knee. This is his third attack this year. His uric acid is 9.2 mg/dL. After treating the acute attack, what is the most appropriate long-term plan?", "options": {"A": "Start allopurinol for long-term urate-lowering therapy after the acute attack resolves.", "B": "Recommend a low-purine diet only and recheck uric acid in six months.", "C": "Start probenecid during the acute attack to begin lowering uric acid levels.", "D": "No urate-lowering therapy is needed if acute attacks are managed with NSAIDs."}, "correct": "A", "explanation": "Starting allopurinol for long-term urate-lowering therapy is indicated after the acute attack resolves in a patient with recurrent gout three times a year, a high uric acid level, and visible tophi. Dietary modification alone is insufficient when the patient already has tophi and three attacks per year, which meet clear indications for pharmacologic urate lowering. Starting probenecid during an acute attack can prolong the flare by mobilizing urate crystals and is not recommended until the acute attack has resolved."}, {"id": 412, "domain": "primary_care_medicine", "question": "A 61-year-old man with CKD and hypertension has a persistent dry cough on lisinopril. He is unable to tolerate the cough. What is the most appropriate substitution?", "options": {"A": "Switch to amlodipine as it has renal protective effects similar to ACE inhibitors.", "B": "Switch to an ARB such as losartan, which blocks angiotensin without causing cough.", "C": "Continue lisinopril and add dextromethorphan to suppress the cough.", "D": "Switch to a thiazide diuretic to preserve renal blood flow without a cough."}, "correct": "B", "explanation": "An ARB such as losartan provides the same RAAS blockade and renal protection as ACE inhibitors but does not cause the bradykinin-mediated cough that ACE inhibitors produce, making it the ideal switch. Amlodipine is a calcium channel blocker that does not have renal-protective effects comparable to RAAS inhibition and is not the best substitute in CKD. Adding dextromethorphan to suppress the cough does not fix the underlying cause and the patient remains on a medication causing an intolerable side effect."}, {"id": 420, "domain": "primary_care_medicine", "question": "A 52-year-old man presents with crushing substernal chest pain at rest lasting 45 minutes. ECG shows no ST changes but there is a new left bundle branch block. Troponin is elevated. What is the diagnosis and priority action?", "options": {"A": "NSTEMI; admit, anticoagulate, and plan for cardiac catheterization.", "B": "Stable angina; discharge with nitrates and arrange stress testing.", "C": "Pericarditis; treat with NSAIDs and colchicine for six weeks.", "D": "Aortic dissection; order CT angiography before any intervention."}, "correct": "A", "explanation": "An elevated troponin with a new left bundle branch block and prolonged chest pain is consistent with NSTEMI, which requires admission, anticoagulation, and cardiac catheterization. Stable angina does not cause troponin elevation and is not treated with urgent cardiac catheterization. Pericarditis typically causes positional chest pain relieved by leaning forward and diffuse ST elevation on ECG, not a new LBBB with elevated troponin."}, {"id": 422, "domain": "primary_care_medicine", "question": "A 71-year-old man with peripheral artery disease and hypertension has a resting ankle-brachial index of 0.72. He experiences calf pain with walking two blocks. What is the most appropriate management?", "options": {"A": "Order urgent vascular surgery referral for revascularization of his lower extremities.", "B": "Prescribe aspirin, a statin, ACE inhibitor, and a supervised exercise program.", "C": "Start cilostazol only after revascularization to maintain patency.", "D": "Recommend bed rest and leg elevation to reduce arterial demand."}, "correct": "B", "explanation": "Peripheral artery disease with claudication is managed first with medical therapy including aspirin for antiplatelet effect, a statin for atherosclerosis management, an ACE inhibitor for vascular protection, and a supervised exercise program which improves walking distance. Urgent vascular surgery referral for revascularization is not the first step in a patient with claudication at two blocks who has not yet had a trial of medical and exercise therapy. Cilostazol can be used for claudication symptoms but is not the first intervention and is not restricted to post-revascularization use."}, {"id": 423, "domain": "primary_care_medicine", "question": "A 59-year-old woman with type 2 diabetes, hypertension, and CKD stage 3 has a urine albumin-to-creatinine ratio of 450 mg/g. She is on an ACE inhibitor. Which additional medication has the strongest evidence to slow CKD progression?", "options": {"A": "Finerenone, a non-steroidal mineralocorticoid antagonist for CKD in diabetes.", "B": "An ARB to block the renin-angiotensin system more completely with dual blockade.", "C": "Spironolactone, which lowers aldosterone and reduces proteinuria in CKD.", "D": "A beta-blocker to reduce renin release and slow CKD progression."}, "correct": "A", "explanation": "Finerenone is a non-steroidal mineralocorticoid antagonist with strong clinical trial evidence showing reduction in CKD progression and cardiovascular events in patients with diabetic nephropathy and significant albuminuria on ACE inhibitor therapy. Dual RAAS blockade with an ACE inhibitor and ARB together is no longer recommended because clinical trials showed it increased the risk of hyperkalemia and kidney injury without reducing cardiovascular outcomes. Spironolactone may reduce proteinuria but carries significant hyperkalemia risk in CKD and does not have the same level of evidence as finerenone in diabetic CKD."}, {"id": 424, "domain": "primary_care_medicine", "question": "A 47-year-old man with a family history of colon cancer in his father at age 52 asks about colonoscopy screening. He has no symptoms. What is the appropriate starting age for his first colonoscopy?", "options": {"A": "Age 45 per standard population-based screening guidelines.", "B": "Age 40, which is 10 years before his father's cancer diagnosis at 52.", "C": "Age 42, which is 10 years before his father's diagnosis age of 52.", "D": "Age 50, as family history only modifies frequency not starting age."}, "correct": "C", "explanation": "Guidelines recommend starting colonoscopy 10 years before the age of the youngest first-degree relative diagnosed with colorectal cancer, so the patient should start at age 42, which is 10 years before his father's diagnosis at age 52. Age 45 is the recommended starting age for average-risk individuals without family history and is not appropriate given the familial risk factor. Age 40 would be appropriate if the father was diagnosed at age 50, which is the threshold for the 10-year rule, but the father was diagnosed at 52 making 42 the correct start age."}, {"id": 429, "domain": "primary_care_medicine", "question": "A 62-year-old woman with type 2 diabetes and a BMI of 38 kg/m2 has an HbA1c of 8.7%. She wants to lose weight. Which medication addresses both her diabetes and weight?", "options": {"A": "Insulin glargine to provide better glucose control with weight-neutral effect.", "B": "Pioglitazone to improve insulin sensitivity while promoting weight reduction.", "C": "Semaglutide, a GLP-1 agonist with proven glucose and weight reduction benefit.", "D": "Sitagliptin, a DPP-4 inhibitor that lowers HbA1c with mild weight reduction."}, "correct": "C", "explanation": "Semaglutide is a GLP-1 receptor agonist with proven significant reductions in HbA1c and body weight, making it the ideal choice for a patient with both poorly controlled diabetes and obesity. Insulin glargine effectively lowers glucose but tends to cause weight gain, which is counterproductive in a patient who is already obese and wants to lose weight. Pioglitazone improves insulin sensitivity but causes weight gain and fluid retention, both of which are undesirable in this patient."}, {"id": 434, "domain": "primary_care_medicine", "question": "A 69-year-old man with a 40 pack-year history of smoking has a new pulmonary nodule of 8 mm on low-dose CT chest. He has no prior CT for comparison. What is the most appropriate follow-up?", "options": {"A": "Biopsy the nodule now given his smoking history and nodule size.", "B": "Refer to thoracic surgery for resection given high malignancy risk.", "C": "Repeat low-dose CT in 3 months given the high-risk nature of this nodule.", "D": "Repeat CT in 12 months as nodules under 10 mm are always benign."}, "correct": "C", "explanation": "An 8 mm nodule in a high-risk patient such as a heavy smoker without a prior CT for comparison should be followed with a repeat low-dose CT in 3 months per high-risk nodule management guidelines. Biopsy is not the first step for an 8 mm nodule without evidence of growth because many small nodules in smokers are benign and biopsy carries procedural risk. Surgical resection without tissue diagnosis or evidence of growth or size progression is premature for an 8 mm nodule."}, {"id": 441, "domain": "specialty_systems", "question": "A 70-year-old man presents to the emergency department with sudden onset left-sided weakness and facial droop that started 90 minutes ago. CT head is negative for hemorrhage. What is the most appropriate treatment?", "options": {"A": "Administer IV alteplase within the three to four and a half hour window.", "B": "Administer aspirin 325 mg immediately as it is safer than thrombolytics in elderly.", "C": "Admit for observation and start anticoagulation with heparin infusion.", "D": "Order MRI brain before initiating any therapy to confirm ischemic stroke."}, "correct": "A", "explanation": "IV alteplase is indicated for ischemic stroke when it can be given within 4.5 hours of symptom onset, the CT shows no hemorrhage, and there are no contraindications, and this patient qualifies at 90 minutes. Aspirin alone is inferior to thrombolysis for acute ischemic stroke when the patient is within the treatment window and has no contraindications. Heparin anticoagulation is not first-line for acute ischemic stroke and does not replace thrombolysis in eligible patients."}, {"id": 442, "domain": "specialty_systems", "question": "A 65-year-old man presents with right-sided weakness and aphasia that started two hours ago and resolved fully within 20 minutes before his arrival. CT head is negative. What is the most appropriate workup?", "options": {"A": "Admit for urgent stroke workup including MRI, carotid imaging, and cardiac monitoring.", "B": "Discharge with aspirin and schedule a neurology appointment within one month.", "C": "Start anticoagulation immediately as TIA is equivalent to a completed stroke.", "D": "Order an EEG to differentiate between a transient ischemic attack and seizure."}, "correct": "A", "explanation": "A TIA is a medical emergency with high short-term stroke risk, requiring urgent hospital admission for brain MRI, carotid imaging to evaluate for stenosis, and cardiac monitoring to detect atrial fibrillation or other embolic sources. Discharging with aspirin and a one-month neurology appointment would miss the narrow window during which the stroke risk is highest and intervention is most effective. Starting anticoagulation immediately without establishing the diagnosis or mechanism is premature; anticoagulation is appropriate if a cardioembolic source such as atrial fibrillation is found."}, {"id": 445, "domain": "specialty_systems", "question": "A 45-year-old woman presents with tingling and numbness in her thumb, index, and middle fingers that worsens at night. Tinel's sign and Phalen's maneuver are positive. What is the most appropriate next step?", "options": {"A": "Refer immediately to hand surgery for surgical decompression of the carpal tunnel.", "B": "Order nerve conduction studies and EMG to confirm carpal tunnel syndrome.", "C": "Start with wrist splinting at night and NSAIDs before any further workup.", "D": "Order cervical spine MRI to rule out a C6 radiculopathy first."}, "correct": "C", "explanation": "Carpal tunnel syndrome with classic nocturnal symptoms and positive provocative tests should be initially managed conservatively with wrist splinting at night and NSAIDs for pain relief before pursuing confirmatory testing or surgical referral. Immediate surgical referral without a trial of conservative management is premature for early carpal tunnel syndrome without severe weakness or thenar atrophy. Nerve conduction studies can confirm the diagnosis but are not required before starting conservative management in a patient with a classic clinical presentation."}, {"id": 452, "domain": "specialty_systems", "question": "A 55-year-old man presents with a two-week history of resting tremor in his right hand. Examination reveals cogwheel rigidity and bradykinesia. He walks with a shuffling gait. Which is the most appropriate initial treatment?", "options": {"A": "Prescribe carbidopa-levodopa as the most effective dopaminergic therapy.", "B": "Start a dopamine agonist such as pramipexole given his younger age relative to elderly.", "C": "Prescribe amantadine to treat tremor and rigidity in early Parkinson's disease.", "D": "Refer to neurology before initiating any treatment for suspected Parkinson's disease."}, "correct": "D", "explanation": "Parkinson's disease should be evaluated and initially managed by a neurologist to confirm the diagnosis, choose appropriate therapy, and establish a long-term treatment plan, as misdiagnosis and premature treatment can cause harm. Carbidopa-levodopa is the most effective dopaminergic therapy but is associated with motor complications over time and is generally initiated under neurologist guidance. Dopamine agonists are used in younger patients to delay levodopa-related motor complications but should be started after a neurologist confirms the diagnosis."}, {"id": 454, "domain": "specialty_systems", "question": "A 35-year-old woman has recurrent migraines with nausea. She takes sumatriptan but vomits before it can be absorbed. What modification to her acute migraine regimen is most appropriate?", "options": {"A": "Switch to oral rizatriptan 10 mg, which is better absorbed than sumatriptan.", "B": "Add oral ondansetron before the sumatriptan to prevent vomiting.", "C": "Switch to sumatriptan nasal spray or subcutaneous injection to bypass the gut.", "D": "Add metoclopramide to promote gastric emptying before taking oral sumatriptan."}, "correct": "C", "explanation": "Switching to sumatriptan nasal spray or subcutaneous injection bypasses gastrointestinal absorption entirely, allowing the medication to reach therapeutic levels even when the patient is vomiting. Switching to oral rizatriptan would still require gastrointestinal absorption and would be vomited up just as easily as oral sumatriptan. Adding oral ondansetron before sumatriptan may help prevent vomiting but does not guarantee absorption if nausea is severe enough to limit oral intake."}, {"id": 457, "domain": "specialty_systems", "question": "A 57-year-old woman has had widespread joint pain, fatigue, and sleep disturbance for six months. Tender points are found at 13 of 18 standard locations. Labs and X-rays are normal. What is the most appropriate management?", "options": {"A": "Refer to rheumatology for immunosuppressive therapy of presumed connective tissue disease.", "B": "Order ANA, RF, and anti-CCP to rule out early rheumatoid arthritis or lupus.", "C": "Start duloxetine, pregabalin, or milnacipran and recommend exercise and CBT.", "D": "Start opioids for pain management given the severity and duration of her symptoms."}, "correct": "C", "explanation": "Fibromyalgia presenting with widespread pain, fatigue, sleep disturbance, and multiple tender points with normal labs and imaging is best managed with FDA-approved agents such as duloxetine, pregabalin, or milnacipran combined with graded exercise and cognitive behavioral therapy. Immunosuppressive therapy is inappropriate for fibromyalgia because it is a central sensitization syndrome, not an inflammatory or autoimmune condition. Ordering ANA, RF, and anti-CCP is reasonable to rule out connective tissue disease but the normal labs and X-rays already make these unlikely; management for fibromyalgia should not be delayed for additional testing in a classic presentation."}, {"id": 460, "domain": "specialty_systems", "question": "A 66-year-old man presents with progressive proximal muscle weakness in his thighs and shoulders. He has difficulty rising from a chair. CK is 3,200 U/L and ANA is positive. What is the most appropriate next step?", "options": {"A": "Order MRI of the muscles and refer to rheumatology for probable inflammatory myopathy.", "B": "Start prednisone 60 mg immediately without further workup as CK confirms myositis.", "C": "Order a muscle biopsy in the office before referring to any specialist.", "D": "Reassure the patient as elevated CK in elderly men is almost always benign."}, "correct": "A", "explanation": "Progressive proximal muscle weakness, significantly elevated CK, and a positive ANA raise strong concern for an inflammatory myopathy such as polymyositis or dermatomyositis, requiring MRI of affected muscles and rheumatology referral for further evaluation and treatment. Starting prednisone without further workup risks treating the wrong diagnosis if the elevated CK is from another cause, such as statin myopathy or hypothyroidism, which should be ruled out first. Performing a muscle biopsy in the office is not appropriate; this requires coordination with neurology or rheumatology and proper biopsy technique."}, {"id": 465, "domain": "specialty_systems", "question": "A 40-year-old man has hyperuricemia with a uric acid of 8.8 mg/dL but no history of gout attacks or tophi. What is the recommended management?", "options": {"A": "Start allopurinol immediately to prevent future gout attacks.", "B": "Asymptomatic hyperuricemia does not require urate-lowering treatment.", "C": "Start a low-purine diet and recheck in six months to assess response.", "D": "Order a joint X-ray to evaluate for subclinical gout before any treatment."}, "correct": "B", "explanation": "Asymptomatic hyperuricemia without gout attacks, tophi, or kidney stones does not require pharmacologic urate-lowering treatment because the risk-benefit ratio does not support treating an elevated uric acid level alone. Starting allopurinol immediately for an asymptomatic elevation contradicts current guidelines that reserve urate-lowering therapy for patients with clinical gout, tophi, or uric acid nephrolithiasis. Dietary changes and follow-up are reasonable to discuss but asymptomatic hyperuricemia itself is not a condition that requires drug treatment."}, {"id": 472, "domain": "specialty_systems", "question": "A 29-year-old woman with a long history of Raynaud phenomenon develops finger swelling, tightening of the skin over her hands, and new heartburn. ANA is positive with anti-Scl-70 antibodies. What is the most appropriate referral?", "options": {"A": "Refer to rheumatology for evaluation and management of systemic sclerosis.", "B": "Refer to gastroenterology for evaluation of the esophageal symptoms.", "C": "Start a calcium channel blocker and reassess Raynaud symptoms in three months.", "D": "Refer to dermatology for skin biopsy to confirm the diagnosis."}, "correct": "A", "explanation": "Progressive skin tightening, Raynaud phenomenon, finger swelling, and positive anti-Scl-70 antibodies are diagnostic of systemic sclerosis, a multisystem connective tissue disease requiring rheumatology for comprehensive evaluation and management. Gastroenterology referral alone would address the esophageal symptoms but would miss the systemic disease requiring coordinated rheumatologic care. Starting a calcium channel blocker manages Raynaud symptoms but does not address the underlying systemic sclerosis, which requires a specialist's involvement."}, {"id": 474, "domain": "specialty_systems", "question": "A 52-year-old man with type 2 diabetes presents with swelling and redness of his right foot. Temperature is 38.8 C and he has a wound with visible bone on probing. What is the most appropriate next step?", "options": {"A": "Order an MRI foot to evaluate for osteomyelitis and admit to hospital.", "B": "Start empiric oral antibiotics and follow up in one week.", "C": "Perform wound debridement in the clinic and apply a topical antibiotic.", "D": "Refer to podiatry for routine diabetic foot care and offloading."}, "correct": "A", "explanation": "Visible bone on probing, fever, and foot swelling in a diabetic patient are signs of osteomyelitis, which requires MRI of the foot for accurate diagnosis and hospital admission for IV antibiotics and surgical evaluation. Empiric oral antibiotics and outpatient follow-up are inadequate for suspected osteomyelitis, which requires IV therapy and often surgical debridement. Wound debridement with topical antibiotics in the clinic does not address the underlying bone infection and is insufficient management."}, {"id": 480, "domain": "specialty_systems", "question": "A 63-year-old woman presents with new onset bilateral leg weakness, gait instability, and urinary urgency. MRI shows cervical cord compression at C4-C5. What is the most appropriate next step?", "options": {"A": "Start physical therapy for cervical myelopathy and reassess in three months.", "B": "Refer urgently to neurosurgery for evaluation of cervical myelopathy.", "C": "Order EMG and nerve conduction studies to confirm the level of compression.", "D": "Start high-dose IV methylprednisolone and reassess neurologic function."}, "correct": "B", "explanation": "Cervical cord compression causing progressive bilateral leg weakness, gait instability, and urinary urgency is cervical myelopathy, which requires urgent neurosurgical referral because surgical decompression can prevent further neurologic deterioration and potentially reverse deficits. Physical therapy alone is not appropriate for cord compression causing myelopathy; it can be used adjunctively after decompression but not as primary management. EMG and nerve conduction studies evaluate peripheral nerve function and are not the appropriate next step when MRI has already confirmed cord compression at C4-C5."}, {"id": 482, "domain": "specialty_systems", "question": "A 30-year-old man presents with acute monoarticular arthritis of the right knee. Aspiration shows cloudy fluid with 60,000 WBCs. Gram stain is pending. He is sexually active. What is the most appropriate empiric treatment?", "options": {"A": "Start allopurinol as hyperuricemia is the most common cause in young men.", "B": "Drain the joint and administer intra-articular corticosteroid for acute arthritis.", "C": "Hold all antibiotics until Gram stain results are available before treating.", "D": "Start ceftriaxone empirically to cover Neisseria gonorrhoeae as the most likely pathogen."}, "correct": "D", "explanation": "A sexually active young man with an acute monoarthritis and 60,000 WBCs in the joint fluid must be treated empirically for septic arthritis from Neisseria gonorrhoeae, which is the most common cause of septic arthritis in this age group. Starting allopurinol is completely wrong; this is a potentially infectious arthritis requiring urgent antibiotic therapy, not a gout attack requiring urate-lowering treatment. Withholding antibiotics until Gram stain results are available is not appropriate when septic arthritis from gonorrhea is clinically suspected, because delays worsen joint destruction."}, {"id": 483, "domain": "specialty_systems", "question": "A 44-year-old man with a history of childhood asthma presents with recurrent sinusitis, nasal polyps, and wheezing triggered by aspirin. What is the most likely diagnosis and management?", "options": {"A": "Allergic rhinitis with coincidental asthma; prescribe nasal corticosteroids only.", "B": "Aspirin-exacerbated respiratory disease; avoid all NSAIDs and manage each condition.", "C": "Churg-Strauss syndrome; order ANCA antibodies and refer to rheumatology.", "D": "Reactive airway disease; prescribe a short-acting beta-agonist for symptoms."}, "correct": "B", "explanation": "The triad of nasal polyps, asthma, and aspirin-triggered wheezing is the classic presentation of Aspirin-Exacerbated Respiratory Disease (AERD), which requires strict avoidance of NSAIDs and aspirin and management of each condition individually. Allergic rhinitis with coincidental asthma would not explain the specific aspirin-triggered wheezing component of this syndrome. Churg-Strauss syndrome involves eosinophilic vasculitis with asthma and sinusitis, and ANCA testing is appropriate if vasculitis is suspected, but AERD is a far more common diagnosis in this clinical picture."}, {"id": 490, "domain": "specialty_systems", "question": "A 59-year-old woman with osteoporosis has been on alendronate for five years. She now has severe hip pain. X-ray shows a transverse fracture of the subtrochanteric femur. What is the most appropriate response?", "options": {"A": "Discontinue alendronate given the suspected atypical femur fracture.", "B": "Continue alendronate and add calcium and vitamin D to prevent further fractures.", "C": "Switch to denosumab immediately and refer for orthopedic evaluation.", "D": "Order a DXA scan to reassess bone density before making any changes."}, "correct": "A", "explanation": "A transverse subtrochanteric fracture in a patient on long-term bisphosphonate therapy is an atypical femur fracture, a known complication of prolonged bisphosphonate use, and the drug should be discontinued. Continuing alendronate would risk a complete fracture of the contralateral femur and would not be appropriate when the drug may have caused this complication. Switching to denosumab immediately after an atypical fracture is not the recommended approach; a drug holiday from anti-resorptive therapy is advised."}, {"id": 495, "domain": "women_s_health", "question": "A 28-year-old woman with migraines with aura asks about contraceptive options. She smokes half a pack per day and is otherwise healthy. Which contraceptive method is most appropriate?", "options": {"A": "Combined oral contraceptive pills containing ethinyl estradiol and progestin.", "B": "Combination patch as it contains a lower estrogen dose than oral pills.", "C": "A progestin-only pill given her contraindication to estrogen-containing methods.", "D": "Vaginal ring as it avoids first-pass metabolism and reduces migraine triggers."}, "correct": "C", "explanation": "A patient with migraines with aura who also smokes has two absolute contraindications to estrogen-containing contraceptives, making a progestin-only pill the safest appropriate option. Combined oral contraceptive pills containing estrogen are contraindicated in women with migraine with aura due to a significantly increased risk of ischemic stroke. The combined patch contains the same estrogen as the pill and carries the same contraindication in migraine with aura."}, {"id": 499, "domain": "women_s_health", "question": "A 35-year-old woman's Pap returns as high-grade squamous intraepithelial lesion. She has no prior colposcopy. What is the most appropriate next step?", "options": {"A": "Refer for colposcopy and biopsy to determine grade of cervical intraepithelial neoplasia.", "B": "Repeat Pap in six months as HSIL often regresses without treatment in young women.", "C": "Perform LEEP excision immediately as HSIL always requires immediate treatment.", "D": "Order a pelvic MRI to evaluate for invasive cervical cancer before colposcopy."}, "correct": "A", "explanation": "High-grade squamous intraepithelial lesion on Pap smear requires colposcopy and biopsy to determine the grade of cervical intraepithelial neoplasia because the Pap result alone cannot confirm CIN 2, CIN 3, or invasive cancer. Repeating the Pap in six months is not appropriate for HSIL, as the risk of significant pathology is too high to defer colposcopy. Immediate LEEP without colposcopy violates the principle of treating known disease, not Pap results; colposcopy and biopsy are needed to confirm CIN grade before excision."}, {"id": 500, "domain": "women_s_health", "question": "A 38-year-old woman has irregular heavy periods, pelvic pressure, and a uterus at 14 weeks size on exam. Pelvic ultrasound confirms multiple intramural fibroids. She has completed childbearing. What is the most appropriate next step?", "options": {"A": "Start oral contraceptives to reduce heavy bleeding and slow fibroid growth.", "B": "Refer to gynecology for discussion of surgical options including hysterectomy.", "C": "Start GnRH agonist therapy immediately for long-term fibroid management.", "D": "Reassure and repeat ultrasound in one year to monitor fibroid size."}, "correct": "B", "explanation": "A patient with symptomatic fibroids, a uterus enlarged to 14 weeks size, and completed childbearing should be referred to gynecology for discussion of definitive surgical options including hysterectomy. Oral contraceptives can reduce heavy bleeding temporarily but do not shrink large fibroids and do not address the pelvic pressure from a uterus this size. GnRH agonists shrink fibroids temporarily but cause menopausal side effects and are not suitable for long-term management; they are used as a bridge to surgery."}, {"id": 503, "domain": "women_s_health", "question": "A 31-year-old woman at 28 weeks of gestation fails her one-hour 50 g glucose challenge test with a value of 164 mg/dL. What is the next appropriate step?", "options": {"A": "Perform a three-hour 100 g oral glucose tolerance test to confirm diagnosis.", "B": "Diagnose gestational diabetes and start insulin therapy immediately.", "C": "Recommend diet and exercise and retest with the two-hour challenge at 36 weeks.", "D": "Order a fasting glucose; if below 95 mg/dL no further testing is needed."}, "correct": "A", "explanation": "A one-hour glucose challenge value of 164 mg/dL is a positive screening result that requires confirmation with a three-hour 100 gram OGTT before diagnosing gestational diabetes and initiating treatment. Diagnosing gestational diabetes and starting insulin immediately after only a screening test is premature; the diagnostic test must be performed first. Diet and exercise followed by retesting later skips the necessary diagnostic confirmation step that the three-hour OGTT provides."}, {"id": 506, "domain": "women_s_health", "question": "A 42-year-old woman has a total hysterectomy for uterine fibroids. Both ovaries are intact. What cervical cancer screening is appropriate going forward?", "options": {"A": "Continue routine Pap smears every three years at the vaginal cuff.", "B": "Annual vaginal Pap smears indefinitely given her prior history of fibroids.", "C": "No further cervical cancer screening is needed after hysterectomy for benign disease.", "D": "Pap smear and HPV co-testing every five years at the vaginal cuff."}, "correct": "C", "explanation": "Following hysterectomy for benign disease such as fibroids in a woman who has no history of cervical dysplasia, cervical cancer screening is no longer recommended because there is no cervix to screen. Continuing Pap smears at the vaginal cuff every three years is only appropriate for women who had hysterectomy for cervical cancer or dysplasia, not for benign disease. Annual vaginal Pap smears indefinitely after hysterectomy for fibroids is unnecessary and not supported by screening guidelines."}, {"id": 510, "domain": "women_s_health", "question": "A 36-year-old woman at 12 weeks of gestation presents with heavy vaginal bleeding and an open cervical os. Ultrasound shows no fetal cardiac activity. What is the appropriate management?", "options": {"A": "Expectant management with repeat ultrasound in one week.", "B": "Prescribe misoprostol and discharge with follow-up in 48 hours.", "C": "Proceed with uterine evacuation via suction curettage or medical management.", "D": "Admit for observation and blood transfusion before any intervention."}, "correct": "C", "explanation": "An incomplete abortion with an open cervical os, active bleeding, and no fetal cardiac activity requires uterine evacuation through suction curettage or medical management to safely complete the process and prevent infection or hemorrhage. Expectant management with a repeat ultrasound in one week is not appropriate when the cervix is open and bleeding is active, indicating the miscarriage is already in progress. Prescribing misoprostol and discharging is a form of medical management but alone without close follow-up may be insufficient given the active bleeding and open os requiring more immediate attention."}, {"id": 515, "domain": "women_s_health", "question": "A 22-year-old woman who is 10 weeks pregnant presents with unilateral pelvic pain. Transvaginal ultrasound confirms an intrauterine pregnancy and a 4 cm corpus luteum cyst on the right ovary. What is the most appropriate management?", "options": {"A": "Laparoscopic cystectomy immediately to prevent torsion in the first trimester.", "B": "Schedule a repeat ultrasound at 16 weeks to confirm resolution of the cyst.", "C": "Reassure the patient as corpus luteum cysts are normal in early pregnancy.", "D": "Prescribe oral progesterone to support the corpus luteum and reduce cyst size."}, "correct": "C", "explanation": "A corpus luteum cyst in early pregnancy is a normal physiologic finding because the corpus luteum produces progesterone to support the pregnancy until the placenta takes over, and it typically resolves by 12 to 16 weeks. Laparoscopic cystectomy is not indicated for a corpus luteum cyst unless there is evidence of torsion or rupture, which are not described here. A repeat ultrasound at 16 weeks can confirm resolution but reassurance is the most appropriate immediate management for a normal physiologic finding."}, {"id": 519, "domain": "women_s_health", "question": "A 27-year-old woman at 20 weeks of gestation has a hemoglobin of 9.8 g/dL, MCV of 72 fL, and serum ferritin of 6 ng/mL. What is the most appropriate treatment?", "options": {"A": "Start IV iron infusion immediately as oral iron is inadequate in pregnancy.", "B": "Prescribe prenatal vitamins with iron and recheck CBC in six weeks.", "C": "Prescribe oral ferrous sulfate 325 mg one to three times daily and recheck in four weeks.", "D": "Recommend dietary iron-rich foods and recheck hemoglobin at the 28-week visit."}, "correct": "C", "explanation": "Iron deficiency anemia in pregnancy with a hemoglobin of 9.8 and low ferritin is treated with oral ferrous sulfate 325 mg one to three times daily, which effectively replaces iron stores when taken consistently. IV iron infusion is reserved for patients who cannot tolerate oral iron, have malabsorption, or need rapid repletion; it is not the first-line for mild to moderate anemia in pregnancy. Prenatal vitamins alone contain insufficient iron to adequately treat established iron deficiency anemia; therapeutic doses of supplemental iron are required."}, {"id": 520, "domain": "women_s_health", "question": "A 38-year-old woman at 16 weeks gestation had a prior fetal loss at 20 weeks and another at 22 weeks. Cervical length is 2.3 cm on transvaginal ultrasound. What is the most appropriate intervention?", "options": {"A": "Pelvic rest and modified activity only; no intervention is indicated at this time.", "B": "Hospitalize and administer betamethasone for fetal lung maturity now.", "C": "Cerclage placement to reduce risk of preterm delivery or pregnancy loss.", "D": "Start oral progesterone and recheck cervical length in two weeks."}, "correct": "C", "explanation": "A cervical length of 2.3 cm at 16 weeks in a patient with two prior late second-trimester pregnancy losses suggests cervical insufficiency, and cerclage placement is the appropriate intervention to reduce the risk of further pregnancy loss or preterm delivery. Pelvic rest and activity modification alone are insufficient when the cervix is short and the patient has a history of recurrent midtrimester losses suggesting cervical insufficiency. Betamethasone for fetal lung maturity is given at 24 to 34 weeks when preterm delivery is imminent, not as a preventive measure at 16 weeks."}, {"id": 523, "domain": "women_s_health", "question": "A 32-year-old woman at 10 weeks of gestation is found to have hypothyroidism with a TSH of 5.8 mIU/L. She is not currently on thyroid medication. What is the most appropriate action?", "options": {"A": "Start levothyroxine with a target TSH below 2.5 mIU/L in the first trimester.", "B": "Monitor only; TSH up to 10 is acceptable during the first trimester of pregnancy.", "C": "Start methimazole to prevent fetal thyroid abnormalities from high maternal TSH.", "D": "Repeat TSH in four weeks; thyroid function normalizes naturally in many pregnancies."}, "correct": "A", "explanation": "Hypothyroidism in the first trimester of pregnancy requires levothyroxine treatment with a TSH target below 2.5 mIU/mL because inadequate thyroid hormone during early pregnancy impairs fetal neurological development. Monitoring only with a TSH up to 10 acceptable in pregnancy is incorrect; guidelines recommend tighter control with a lower TSH threshold in the first trimester. Methimazole is used to treat hyperthyroidism, not hypothyroidism, and would worsen this patient's already low thyroid function."}, {"id": 526, "domain": "women_s_health", "question": "A 23-year-old woman at 32 weeks gestation has a positive glucose challenge test at 154 mg/dL and then a positive three-hour OGTT. She is counseled on diet. After two weeks, fasting glucose is 102 mg/dL and post-meal glucose is 148 mg/dL. What is the most appropriate next step?", "options": {"A": "Continue dietary management; the two-week trial is insufficient for assessment.", "B": "Start metformin as it is the preferred oral agent for gestational diabetes.", "C": "Start insulin therapy as her glucose targets are not being met with diet alone.", "D": "Refer to maternal-fetal medicine as her case exceeds NP scope of practice."}, "correct": "C", "explanation": "Fasting glucose consistently above 95 mg/dL and post-meal glucose above 120 mg/dL despite two weeks of dietary management indicates that pharmacotherapy is needed, and insulin therapy is the preferred agent in gestational diabetes that fails diet control. Continuing dietary management and considering the two-week trial insufficient does not align with guidelines; two weeks of dietary failure with elevated fasting glucose is the standard threshold for initiating pharmacotherapy. Metformin crosses the placenta and has uncertain long-term fetal effects, so insulin is the preferred first pharmacologic choice."}, {"id": 528, "domain": "women_s_health", "question": "A 30-year-old woman has her first Pap smear, which returns as HSIL. She has never had prior cervical testing. What is the most appropriate management?", "options": {"A": "Repeat Pap smear in 6 months; HSIL in young women often regresses.", "B": "Perform immediate LEEP excision without colposcopy first.", "C": "Refer for colposcopy with biopsy to determine degree of CIN.", "D": "Start topical imiquimod and retest in three months."}, "correct": "C", "explanation": "HSIL on a first Pap smear requires colposcopy with biopsy to determine the degree of cervical intraepithelial neoplasia and guide appropriate management, as the Pap result alone does not provide histologic diagnosis. Repeating the Pap in 6 months is inappropriate for HSIL because the risk of CIN 2 or 3 is high enough to require immediate colposcopic evaluation. Immediate LEEP without colposcopy and biopsy first violates the principle of histologic confirmation before excisional treatment; colposcopy must precede LEEP."}, {"id": 536, "domain": "mental_health", "question": "A 45-year-old man with bipolar I disorder is stable on lithium but develops new-onset polyuria and polydipsia. Urine specific gravity is persistently 1.001. TSH is normal. What is the most likely cause and next step?", "options": {"A": "New-onset diabetes mellitus; order fasting glucose and HbA1c.", "B": "Lithium-induced nephrogenic diabetes insipidus; reduce dose or switch mood stabilizer.", "C": "SIADH from lithium toxicity; obtain lithium level and renal function tests.", "D": "Psychogenic polydipsia; refer to psychiatry for behavioral intervention."}, "correct": "B", "explanation": "Polyuria and polydipsia with persistently dilute urine and a low specific gravity in a patient on lithium is classic for lithium-induced nephrogenic diabetes insipidus, requiring dose reduction or consideration of switching mood stabilizers. New-onset diabetes mellitus would cause dilute urine with glucose, not without glucose, and the clinical context of lithium use makes lithium-induced ADH insensitivity far more likely. SIADH causes concentrated urine and hyponatremia, not dilute urine with low specific gravity, so it is not consistent with this presentation."}, {"id": 537, "domain": "mental_health", "question": "A 52-year-old man with a history of alcohol use disorder presents to the clinic. His last drink was 18 hours ago and he is now having tremors and diaphoresis. His CIWA-Ar score is 16. What is the most appropriate management?", "options": {"A": "Prescribe oral lorazepam for outpatient alcohol withdrawal management.", "B": "Hospitalize for monitored withdrawal management with benzodiazepines.", "C": "Prescribe gabapentin alone as it is now first-line for alcohol withdrawal.", "D": "Reassure the patient and schedule follow-up in 24 hours if symptoms persist."}, "correct": "B", "explanation": "A CIWA-Ar score of 16 indicates moderate alcohol withdrawal requiring hospitalization for monitored withdrawal management with scheduled or symptom-triggered benzodiazepines to prevent seizures and delirium tremens. Prescribing oral lorazepam for outpatient management is not appropriate at a CIWA score of 16 with tremors and diaphoresis, as the patient needs continuous monitoring and access to escalating doses. Gabapentin alone is an emerging option for mild alcohol withdrawal but is not established as first-line for moderate withdrawal scoring at 16."}, {"id": 540, "domain": "mental_health", "question": "A 4-year-old boy is brought in by his parents for hyperactivity, impulsivity, and inability to focus during preschool activities. Symptoms are present in all settings. What is the most appropriate first-line management for ADHD at this age?", "options": {"A": "Behavioral therapy and parent training are first-line treatment at age 4.", "B": "Start low-dose methylphenidate immediately given the severity of symptoms.", "C": "Start amphetamine salts as they are FDA-approved for preschool ADHD.", "D": "Prescribe guanfacine as it has fewer side effects than stimulants in young children."}, "correct": "A", "explanation": "For children aged 4 to 5 with ADHD, the American Academy of Pediatrics recommends behavior therapy and parent training as the primary first-line treatment before considering stimulant medications. Starting methylphenidate at age 4 without first attempting behavioral therapy is not the recommended approach for this age group. Amphetamine salts are FDA-approved for children 3 and older but stimulant medications are not first-line for preschool-aged children."}, {"id": 542, "domain": "mental_health", "question": "A 58-year-old man on lithium 900 mg daily for bipolar disorder develops a coarse tremor, confusion, and diarrhea. His lithium level is 2.4 mEq/L. What is the most appropriate action?", "options": {"A": "Reduce the lithium dose by half and recheck a level in 24 hours.", "B": "Hold lithium, increase fluid intake, and recheck level in 48 hours.", "C": "Discontinue lithium immediately and transfer to the emergency department.", "D": "Start propranolol for the tremor and continue lithium at a reduced dose."}, "correct": "C", "explanation": "A lithium level of 2.4 mEq/L with symptoms of toxicity including coarse tremor, confusion, and diarrhea represents severe lithium toxicity requiring immediate discontinuation and emergency department transfer for IV fluids and possible dialysis. Reducing the lithium dose and rechecking in 24 hours is dangerously inadequate for a toxic level with clinical symptoms of severe lithium toxicity. Holding lithium and increasing fluids at home is also insufficient at this level; the patient requires urgent evaluation and treatment including renal function testing and monitoring for worsening neurologic status."}, {"id": 543, "domain": "mental_health", "question": "A 29-year-old woman at 16 weeks gestation is being treated for major depression on escitalopram 20 mg daily. She is concerned about fetal risks. What is the most appropriate counseling and action?", "options": {"A": "Discontinue escitalopram immediately as all SSRIs are teratogenic in pregnancy.", "B": "Taper escitalopram by 5 mg per month to wean off before the third trimester.", "C": "Switch to bupropion as it is classified as safer than SSRIs in pregnancy.", "D": "Continue escitalopram as untreated depression poses greater risk than the medication."}, "correct": "D", "explanation": "The risks of untreated depression during pregnancy, including preterm birth, poor prenatal care adherence, and postpartum depression, generally outweigh the modest risks of continued SSRI therapy, so continuing escitalopram is the most appropriate recommendation. Discontinuing all SSRIs as teratogenic is incorrect; SSRIs are not classical teratogens and the risk of stopping treatment in a patient with major depression is significant. Bupropion is not classified as safer than SSRIs in pregnancy and has its own risk profile including possible cardiac defects at higher doses."}, {"id": 544, "domain": "mental_health", "question": "A 35-year-old veteran presents with nightmares, hypervigilance, avoidance of public places, and emotional numbing following combat deployment. Symptoms have persisted for eight months. What is the most appropriate first-line pharmacotherapy?", "options": {"A": "Benzodiazepines to reduce hyperarousal and improve sleep quality.", "B": "Prazosin to specifically target nightmare frequency in PTSD patients.", "C": "An SSRI such as sertraline or paroxetine, which are FDA-approved for PTSD.", "D": "A mood stabilizer such as valproate to reduce emotional dysregulation."}, "correct": "C", "explanation": "Sertraline and paroxetine are the two SSRIs with FDA approval specifically for PTSD and are considered first-line pharmacotherapy for this condition. Benzodiazepines are not recommended for PTSD because they do not target the core symptoms, can worsen depression, and carry risks of dependence and respiratory depression. Prazosin is used specifically for PTSD-related nightmares and hyperarousal but is not the first-line pharmacotherapy for the full PTSD syndrome."}, {"id": 550, "domain": "mental_health", "question": "A 66-year-old man with Alzheimer's disease is agitated in the evenings and yells at his caregiver. Non-pharmacologic measures have failed. Which medication is the most appropriate and has the least anticholinergic risk?", "options": {"A": "Diphenhydramine 25 mg at night to sedate and reduce agitation in dementia.", "B": "Haloperidol 1 mg twice daily as it has the lowest dementia-related side effects.", "C": "Low-dose quetiapine after discussion of black box risks in elderly with dementia.", "D": "Lorazepam 0.5 mg at night as it has fewer cognitive effects than antipsychotics."}, "correct": "C", "explanation": "Low-dose quetiapine is a commonly used option for dementia-related agitation when non-pharmacologic measures have failed because it has less anticholinergic burden than many alternatives and should be prescribed with informed discussion of the black box warning for dementia. Diphenhydramine has significant anticholinergic properties that worsen cognitive function, cause urinary retention, and increase fall risk in elderly patients with dementia. Haloperidol has a high dopamine blockade profile with extrapyramidal side effects including parkinsonism and is not the lowest-risk option in elderly patients with dementia-related agitation."}, {"id": 551, "domain": "mental_health", "question": "A 17-year-old girl with anorexia nervosa has a BMI of 15.4 kg/m2 and has lost 12 kg in the past four months. She is medically stable but refusing to eat adequate calories. What is the most appropriate next step?", "options": {"A": "Outpatient cognitive behavioral therapy with family-based treatment approach.", "B": "Refer to a higher level of care such as residential or inpatient eating disorder treatment.", "C": "Start olanzapine to increase appetite and improve weight gain in anorexia.", "D": "Start a selective serotonin reuptake inhibitor to treat the depression underlying anorexia."}, "correct": "B", "explanation": "A BMI of 15.4 with a 12 kg weight loss and failure to eat adequate calories is severely underweight and requires a higher level of care such as residential or inpatient eating disorder treatment for medically supervised refeeding and intensive therapy. Outpatient CBT with family-based treatment is the first-line approach for anorexia at a higher weight with less severity; at a BMI of 15.4, the patient's nutritional status is too compromised for outpatient management alone. Olanzapine may be used as an adjunct in severe anorexia to promote weight gain but does not replace the need for a higher level of care in a severely malnourished patient."}, {"id": 554, "domain": "mental_health", "question": "A 40-year-old woman on sertraline 100 mg daily for MDD has been stable for 18 months and now wants to discontinue. She had two previous depressive episodes. What is the most appropriate counseling?", "options": {"A": "She can stop sertraline abruptly as she has been stable for over one year.", "B": "Switch to a lower-dose SSRI before tapering to reduce discontinuation symptoms.", "C": "Continue sertraline indefinitely as two prior episodes indicate chronic MDD.", "D": "Taper sertraline slowly and discuss higher recurrence risk with prior episodes."}, "correct": "D", "explanation": "After two prior depressive episodes, the risk of recurrence is high, so the patient should be counseled about this risk and the antidepressant should be tapered slowly rather than stopped abruptly to prevent discontinuation syndrome. Stopping sertraline abruptly risks discontinuation syndrome with flu-like symptoms, dizziness, and irritability, and also does not account for the high recurrence risk with two prior episodes. Continuing sertraline indefinitely may be the appropriate recommendation for some patients with multiple prior episodes, but this should be a shared decision-making discussion rather than an automatic decision without the patient's input."}, {"id": 557, "domain": "mental_health", "question": "A 30-year-old woman with generalized anxiety disorder is started on escitalopram. At her two-week follow-up she reports increased anxiety and jitteriness. What is the most appropriate management?", "options": {"A": "Discontinue escitalopram as she is having an allergic reaction to the medication.", "B": "Reassure her that early activation is common and consider a low-dose start or slow titration.", "C": "Switch immediately to a benzodiazepine as SSRIs do not work for anxiety disorders.", "D": "Add buspirone to counteract the activating effects of escitalopram at onset."}, "correct": "B", "explanation": "Early activating symptoms such as increased anxiety and jitteriness are common when starting SSRIs for anxiety disorders and typically resolve within the first two weeks; the appropriate response is reassurance and consideration of a slower titration or lower starting dose. Discontinuing escitalopram and calling it an allergic reaction is incorrect; this is a known transient side effect of SSRIs at initiation, not an allergic reaction. Switching to a benzodiazepine abandons an effective first-line treatment based on an expected and temporary side effect that typically resolves with continued use."}, {"id": 563, "domain": "mental_health", "question": "A 35-year-old woman with PTSD from childhood trauma takes sertraline 150 mg daily and participates in therapy. She continues to have severe nightmares and insomnia. What pharmacologic addition is most evidence-based for this specific symptom?", "options": {"A": "Add quetiapine at bedtime for both sleep initiation and nightmare reduction.", "B": "Add zolpidem at bedtime to improve sleep onset and maintenance.", "C": "Add prazosin at bedtime specifically to reduce PTSD-related nightmares.", "D": "Add clonazepam nightly to manage hyperarousal and nightmare frequency."}, "correct": "C", "explanation": "Prazosin, an alpha-1 adrenergic blocker, has the strongest specific evidence for reducing PTSD-related nightmares and is the recommended pharmacologic addition for this specific symptom when the patient is already on an SSRI. Quetiapine at bedtime may improve sleep and reduce nightmares as a secondary effect but is not the most evidence-based specific agent for nightmare reduction in PTSD. Zolpidem improves sleep onset but does not specifically reduce nightmare frequency and is associated with parasomnias including complex sleep behaviors."}, {"id": 566, "domain": "mental_health", "question": "A 29-year-old woman on bupropion for depression also uses nicotine patches and is trying to quit smoking. She develops a new generalized tonic-clonic seizure. What is the most important medication consideration?", "options": {"A": "Bupropion lowers seizure threshold and the dose or drug may need to be changed.", "B": "The nicotine patch is the most likely cause of her new-onset seizure.", "C": "Neither medication is associated with seizures; order MRI to find the cause.", "D": "Taper the bupropion slowly over four weeks to prevent further seizure activity."}, "correct": "A", "explanation": "Bupropion lowers the seizure threshold in a dose-dependent manner, and the development of a new seizure in a patient on bupropion requires evaluation of whether the dose should be reduced or the drug changed to an alternative antidepressant with lower seizure risk. The nicotine patch is not associated with seizures and is not the cause of a new generalized tonic-clonic seizure in this context. Claiming neither medication is associated with seizures is incorrect; bupropion has a well-established association with lowering seizure threshold."}, {"id": 568, "domain": "mental_health", "question": "A 58-year-old man with dementia and Parkinson's disease develops visual hallucinations and paranoid delusions. His caregiver is distressed. Which antipsychotic is safest in Parkinson's disease?", "options": {"A": "Haloperidol as it provides the strongest dopamine D2 blockade for psychosis.", "B": "Risperidone as it is the best-studied antipsychotic in older adults with dementia.", "C": "Pimavanserin or quetiapine as they carry the lowest risk of worsening parkinsonism.", "D": "Olanzapine as it is effective and has a favorable side effect profile in PD."}, "correct": "C", "explanation": "Pimavanserin is a serotonin 5-HT2A inverse agonist that specifically treats Parkinson's disease psychosis without worsening motor symptoms, and quetiapine has low D2 blockade making it another relatively safer option in this population. Haloperidol is a potent D2 blocker that significantly worsens parkinsonism and is strongly contraindicated in Parkinson's disease psychosis. Risperidone has moderate to high D2 receptor affinity and will worsen motor symptoms in a patient with Parkinson's disease."}, {"id": 570, "domain": "mental_health", "question": "A 37-year-old woman with bipolar II disorder wants to start lithium but is trying to conceive. What is the key counseling point regarding lithium and pregnancy?", "options": {"A": "Lithium is associated with Ebstein anomaly; risk-benefit discussion is needed.", "B": "Lithium is absolutely contraindicated throughout pregnancy with no exceptions.", "C": "Lithium is considered safe in pregnancy as it does not cross the placenta.", "D": "Lithium should be started at the lowest dose after the first trimester."}, "correct": "A", "explanation": "Lithium is associated with Ebstein anomaly, a rare cardiac malformation affecting the tricuspid valve, when taken during early pregnancy, and a thorough risk-benefit discussion is required before continuing lithium in a patient trying to conceive. Calling lithium absolutely contraindicated throughout pregnancy is too absolute; it can sometimes be continued with appropriate monitoring, fetal echocardiography, and a careful risk-benefit assessment. Lithium does cross the placenta and fetal lithium levels approach maternal levels, so the claim that it does not cross the placenta is incorrect."}, {"id": 573, "domain": "mental_health", "question": "A 68-year-old woman with moderate Alzheimer's disease has progressive cognitive decline and her family asks about medication. She has no behavioral disturbance. What is the most appropriate pharmacologic management?", "options": {"A": "Start donepezil and memantine; combination is appropriate for moderate AD.", "B": "Start memantine alone as donepezil is only indicated for mild AD.", "C": "No pharmacotherapy is beneficial in moderate AD; focus on caregiver support.", "D": "Start an antipsychotic to prevent future behavioral disturbances."}, "correct": "A", "explanation": "Combination therapy with donepezil and memantine is appropriate for moderate Alzheimer's disease because they work through different mechanisms and clinical trials support their combined use in this stage. Starting memantine alone and reserving donepezil only for mild disease is incorrect; guidelines support donepezil across all stages of AD from mild through severe. Saying no pharmacotherapy is beneficial in moderate AD ignores the evidence that both donepezil and memantine slow functional and cognitive decline in moderate disease."}, {"id": 584, "domain": "pediatric_care", "question": "A 15-year-old girl presents with a BMI of 14.5 kg/m2, amenorrhea for four months, and lanugo on her arms. She denies binge-purge behavior. Her heart rate is 46 bpm. What is the most appropriate management?", "options": {"A": "Admit to inpatient medical stabilization given bradycardia and severe malnutrition.", "B": "Start outpatient family-based treatment for anorexia nervosa immediately.", "C": "Prescribe fluoxetine and refer to an outpatient therapist for eating disorder therapy.", "D": "Order a pituitary MRI to evaluate for a structural cause of amenorrhea."}, "correct": "A", "explanation": "A heart rate of 46 bpm, BMI of 14.5, and 4 months of amenorrhea in an adolescent with anorexia represent medical instability requiring inpatient medical stabilization for cardiac monitoring, nutritional rehabilitation, and prevention of refeeding syndrome. Outpatient family-based treatment is appropriate for medically stable anorexia nervosa, not for a patient with bradycardia and severe malnutrition who requires close monitoring. Fluoxetine and outpatient therapy are not effective at low body weights and do not address the immediate medical emergency of bradycardia."}, {"id": 585, "domain": "pediatric_care", "question": "A 5-year-old child who received no prior vaccines is brought in for a wellness visit. The mother is now willing to vaccinate. Which vaccines are recommended to begin the catch-up schedule today?", "options": {"A": "Initiate catch-up vaccination per the ACIP schedule starting with all age-appropriate vaccines.", "B": "Begin with MMR and varicella only; all other vaccines can wait until school age.", "C": "Administer only two vaccines today to avoid overwhelming the immune system.", "D": "Defer until the child is seen by a pediatric allergist to test for vaccine hypersensitivity."}, "correct": "A", "explanation": "An unvaccinated 5-year-old should begin the catch-up vaccination schedule per the ACIP guidelines, which means starting all age-appropriate vaccines today in the appropriate sequence without deferring any for later. Starting only MMR and varicella delays other important vaccines and does not follow the comprehensive catch-up schedule that protects the child from multiple preventable diseases. Limiting to two vaccines today to avoid overwhelming the immune system is not evidence-based; the immune system can safely handle multiple vaccines simultaneously."}, {"id": 590, "domain": "pediatric_care", "question": "A 2-year-old boy has a second episode of otitis media with effusion in the past eight months. He shows no language delay and has no hearing loss. What is the most appropriate next step?", "options": {"A": "Watchful waiting with follow-up in three months as bilat MEE without sequelae.", "B": "Refer for immediate placement of pressure equalization tubes.", "C": "Prescribe a prophylactic antibiotic until the effusion clears.", "D": "Start an antihistamine to reduce congestion and clear the middle ear effusion."}, "correct": "A", "explanation": "A 2-year-old with two episodes of otitis media with effusion in 8 months without hearing loss or language delay should be managed with watchful waiting because guidelines support observation for bilateral MEE without sequelae before pursuing surgical intervention. Immediate PE tube placement is not indicated without evidence of hearing loss, speech delay, or persistent effusion beyond 3 months. Prophylactic antibiotics for OME are not recommended because OME is not an acute infectious process and antibiotic overuse increases resistance without improving outcomes."}, {"id": 591, "domain": "pediatric_care", "question": "A 13-year-old boy is diagnosed with moderate persistent asthma. He uses albuterol daily and his symptoms are poorly controlled. He is on low-dose inhaled corticosteroid alone. What is the most appropriate management step?", "options": {"A": "Increase ICS to medium dose and add a long-acting beta-agonist.", "B": "Switch the ICS to oral prednisone for better systemic anti-inflammatory effect.", "C": "Replace the ICS with a leukotriene receptor antagonist to avoid steroid side effects.", "D": "Add theophylline to his regimen for additional bronchodilation."}, "correct": "A", "explanation": "Poor asthma control with daily albuterol use in a child on low-dose ICS requires stepping up therapy by increasing ICS to a medium dose and adding a long-acting beta-agonist, which is the guideline-recommended escalation for moderate persistent asthma. Switching ICS to oral prednisone for systemic effect is inappropriate because oral steroids carry significant long-term side effects and inhaled therapy has not yet been maximized. Replacing ICS with a leukotriene receptor antagonist is a step sideways to a less effective agent and does not represent appropriate step-up therapy for uncontrolled moderate asthma."}, {"id": 600, "domain": "pediatric_care", "question": "A 6-year-old boy is diagnosed with ADHD and starts methylphenidate 5 mg daily. After three weeks, his teacher reports improvement. His father asks whether the medication needs to be stopped in the summer. What is the most appropriate response?", "options": {"A": "Medication holidays may be considered if ADHD primarily affects school performance.", "B": "Yes, all children with ADHD must take drug holidays every summer.", "C": "ADHD medications must be taken year-round to prevent symptom rebound.", "D": "Summer holidays are not recommended as they increase risk of substance use."}, "correct": "A", "explanation": "Medication holidays during the summer may be considered for children with ADHD when the primary impact is on academic performance, since social and recreational activities may not require the same level of sustained attention during the school year. It is not true that all children with ADHD must take drug holidays every summer; the decision is individualized based on whether symptoms affect function outside of school. ADHD medications do not need to be taken year-round in all cases; the appropriateness of medication holidays depends on the child's specific needs and how much the ADHD affects all domains of functioning."}, {"id": 601, "domain": "pediatric_care", "question": "A 3-year-old girl is up to date on all vaccines except for varicella. She was in close contact with a sibling who developed chickenpox yesterday. She has no prior varicella vaccine or known infection. What is the most appropriate intervention?", "options": {"A": "Administer varicella immunoglobulin only as vaccination is not effective post-exposure.", "B": "Start acyclovir prophylaxis for five days to prevent clinical varicella from developing.", "C": "No intervention is needed as varicella in toddlers is always mild.", "D": "Administer varicella vaccine within 3 to 5 days of exposure to prevent or attenuate disease."}, "correct": "D", "explanation": "Varicella vaccine given within 3 to 5 days of exposure can prevent or significantly reduce the severity of chickenpox and is the preferred post-exposure prophylaxis for healthy unvaccinated children. Varicella immunoglobulin is reserved for immunocompromised individuals or pregnant women who cannot receive the live vaccine. Doing nothing is inappropriate because the unvaccinated child is at high risk of developing chickenpox, and vaccination within the window period is both safe and effective."}, {"id": 606, "domain": "pediatric_care", "question": "A 4-year-old boy has had three episodes of bronchiolitis in his first two years of life. He now presents with recurrent nighttime cough, wheezing with activity, and exercise intolerance. What is the most appropriate assessment?", "options": {"A": "Reassure the family; recurrent bronchiolitis does not predict asthma development.", "B": "Order a spirometry test immediately to confirm an asthma diagnosis.", "C": "Diagnose asthma clinically and initiate a low-dose inhaled corticosteroid.", "D": "Order a chest CT to evaluate for structural airway abnormality causing symptoms."}, "correct": "C", "explanation": "Recurrent nighttime cough, wheezing with activity, and exercise intolerance after a history of recurrent bronchiolitis in a 4-year-old is a classic presentation of childhood asthma, which should be diagnosed clinically at this age since spirometry is not reliable under age 5, and low-dose ICS should be initiated. Reassurance without treatment ignores the pattern of symptoms that meet criteria for asthma and would leave the child undertreated. Spirometry at age 4 is not developmentally reliable and is not the diagnostic tool used in this age group for asthma."}, {"id": 607, "domain": "pediatric_care", "question": "A 12-year-old boy with known sickle cell disease presents with severe pain in his back, arms, and legs along with fever of 38.5 C. Hemoglobin is 7.1 g/dL, which is his baseline. What is the most appropriate initial management?", "options": {"A": "Send to the emergency department for IV fluids, analgesia, and sepsis workup.", "B": "Reassure and prescribe oral NSAIDs and increased oral hydration at home.", "C": "Transfuse packed red blood cells immediately in the clinic.", "D": "Start oral hydroxyurea in the clinic as this is a preventable complication."}, "correct": "A", "explanation": "A sickle cell patient with severe pain and fever requires emergency department evaluation for IV fluids, analgesia, and sepsis workup because fever in sickle cell disease can indicate life-threatening bacteremia, and vaso-occlusive crises require IV management. Oral NSAIDs and home hydration are inadequate for severe pain and fever in sickle cell disease, which is a medical emergency. Transfusing packed red blood cells in the clinic is not the appropriate setting for this intervention and is not the first step; the priority is emergency evaluation for sepsis and pain management."}, {"id": 610, "domain": "professional_practice", "question": "A 65-year-old woman presents for an annual visit. She has never received a pneumococcal vaccine. Which pneumococcal vaccine schedule is currently recommended by ACIP for immunocompetent adults age 65 and older?", "options": {"A": "PCV15 followed by PPSV23 one year later, or PCV20 alone as a single dose.", "B": "PPSV23 only, given once at age 65 to all adults without prior vaccination.", "C": "PCV13 followed by PPSV23 given simultaneously on the same day.", "D": "Two doses of PCV20 given six months apart for complete protection."}, "correct": "A", "explanation": "The current ACIP recommendation for adults aged 65 and older who have never received pneumococcal vaccine is to receive PCV15 followed by PPSV23 at least one year later, or PCV20 alone as a single-dose alternative. PPSV23 only was the older recommendation but has been replaced by the updated ACIP guidance recommending a higher-valency PCV vaccine. PCV13 followed by PPSV23 on the same day is not the recommended schedule; they should not be given simultaneously."}, {"id": 611, "domain": "professional_practice", "question": "A nurse practitioner in a restricted-practice state wants to prescribe Schedule II controlled substances independently. She does not have a collaborative agreement with a physician. What is the most appropriate action?", "options": {"A": "Prescribe as needed; NP prescribing authority is federally protected under DEA registration.", "B": "Apply for a restricted NP DEA waiver that exempts her from state requirements.", "C": "Refer all Schedule II prescribing to a physician only to avoid legal liability.", "D": "Establish a collaborative practice agreement with a physician as required in that state."}, "correct": "D", "explanation": "In a restricted-practice state, a nurse practitioner must have a collaborative practice agreement with a physician to prescribe Schedule II controlled substances because state law governs prescribing authority in restricted-practice states regardless of DEA registration. Prescribing independently based on DEA registration alone is not valid in restricted-practice states because state law must also permit the practice. Referring all Schedule II prescribing to a physician is overly restrictive and not required; the NP can prescribe with the appropriate collaborative agreement in place."}, {"id": 615, "domain": "professional_practice", "question": "A 69-year-old man presents for his annual wellness visit. He has never been screened for abdominal aortic aneurysm. He has a 40 pack-year smoking history. What is the recommended one-time screening test?", "options": {"A": "CT angiography of the aorta is the gold standard for AAA screening.", "B": "Abdominal X-ray to look for calcification in the aortic wall.", "C": "One-time abdominal ultrasound for men aged 65 to 75 who have ever smoked.", "D": "Annual abdominal ultrasound every year starting at age 65 for all smokers."}, "correct": "C", "explanation": "The USPSTF recommends one-time abdominal ultrasound for AAA screening in men aged 65 to 75 who have ever smoked, as this is the evidence-based strategy shown to reduce AAA-related mortality. CT angiography is more detailed but carries radiation and contrast risks and is not the recommended screening modality; ultrasound is the first-line non-invasive screening test. Abdominal X-ray may show aortic calcification but is not a sensitive or specific screening tool for AAA and is not the recommended modality."}, {"id": 616, "domain": "professional_practice", "question": "A 52-year-old woman with a 30 pack-year history of smoking is currently smoking. What lung cancer screening is recommended per USPSTF guidelines?", "options": {"A": "Chest X-ray annually as it is more accessible than low-dose CT screening.", "B": "Annual low-dose CT of the chest for adults aged 50 to 80 with a 20 pack-year history.", "C": "No screening is recommended until she quits smoking for at least five years.", "D": "Sputum cytology annually combined with LDCT every two years."}, "correct": "B", "explanation": "The USPSTF recommends annual low-dose CT of the chest for adults aged 50 to 80 who have a 20 pack-year smoking history and currently smoke or have quit within the past 15 years. Chest X-ray does not reduce lung cancer mortality and is not the recommended screening modality; low-dose CT is the only evidence-based screening tool. There is no requirement to quit smoking before becoming eligible for screening; current or recent smokers meeting the criteria should be screened."}, {"id": 618, "domain": "professional_practice", "question": "A 71-year-old man presents for a routine visit. He has hypertension and received tetanus-diphtheria vaccine seven years ago. Which additional vaccine should be recommended today?", "options": {"A": "Repeat tetanus-diphtheria booster now as adults need it every five years.", "B": "Td booster plus shingles vaccine with recombinant zoster vaccine two-dose series.", "C": "No vaccines are needed; his tetanus is up to date and shingles is optional.", "D": "Shingles vaccine only; tetanus booster is not due for three more years."}, "correct": "D", "explanation": "The tetanus booster given 7 years ago is still within the 10-year interval and does not need to be repeated yet, but the shingles vaccine with the two-dose recombinant zoster vaccine series is recommended for all adults 50 and older. Repeating the tetanus booster now would be premature since it has only been 7 years and the interval is 10 years; the tetanus is still current. A Td booster plus shingles vaccine is close but the Td booster is not due for 3 more years; only the shingles vaccine is indicated at this visit."}, {"id": 620, "domain": "professional_practice", "question": "A 40-year-old man has a normal colonoscopy today. He has no family history of colon cancer and no IBD. When should the next colonoscopy be scheduled?", "options": {"A": "In five years because he had no polyps at this time.", "B": "Never again as a normal colonoscopy at 40 confers lifelong protection.", "C": "In three years as all adults over 40 require more frequent surveillance.", "D": "In ten years per standard screening guidelines for average-risk adults."}, "correct": "D", "explanation": "A normal colonoscopy in an average-risk adult without polyps or family history requires repeat colonoscopy in 10 years per standard colorectal cancer screening guidelines. Repeating in 5 years is not indicated when the colonoscopy was completely normal with no adenomatous polyps found. Three-year intervals are recommended for patients with high-risk adenomas such as large polyps or multiple polyps, not for a completely normal exam."}, {"id": 624, "domain": "professional_practice", "question": "A nurse practitioner bills a level 4 office visit for a 30-year-old established patient with a simple medication refill and no new problems. The note documents a problem-focused history and a limited exam. What is the most appropriate concern?", "options": {"A": "Level 4 billing is always appropriate for established patients regardless of complexity.", "B": "Refill visits can be billed at higher levels to compensate for time spent reviewing records.", "C": "The documentation does not support a level 4 visit; upcoding may constitute fraud.", "D": "The billing is appropriate if the total encounter time exceeded 30 minutes."}, "correct": "C", "explanation": "Billing a level 4 office visit for a simple medication refill with a problem-focused history and limited exam does not meet the documentation requirements for that billing level, and this practice constitutes upcoding, which is a form of healthcare fraud. Level 4 billing is not automatically appropriate for established patients; the documentation must support the complexity level that is billed regardless of patient history. Charging higher levels to compensate for time reviewing records is upcoding if the documentation does not support the level billed; billing must reflect the actual complexity of the encounter."}, {"id": 628, "domain": "professional_practice", "question": "An NP is using the PDSA cycle to improve HbA1c control in her diabetic patients. After the Plan and Do phases, she reviews data showing no improvement. What is the most appropriate next step?", "options": {"A": "Stop the project as the lack of improvement indicates the intervention has failed.", "B": "Study the data to identify barriers and modify the intervention before re-testing.", "C": "Implement the intervention clinic-wide as small sample data is not meaningful.", "D": "Assign a new team to repeat the Do phase with no modifications to the plan."}, "correct": "B", "explanation": "The Study phase of the PDSA cycle involves analyzing the data collected during the Do phase to identify barriers, understand why the intervention did not work as expected, and modify the plan before the next Act and re-test cycle. Stopping the project because of lack of improvement misunderstands the iterative nature of quality improvement; the purpose of the Study phase is to learn from failures and refine the approach. Implementing the intervention clinic-wide based on small negative data would spread an ineffective intervention and could harm patients or waste resources."}, {"id": 631, "domain": "professional_practice", "question": "A 30-year-old woman asks about osteoporosis screening. She has no fractures and no risk factors. What is the appropriate recommendation per USPSTF guidelines?", "options": {"A": "No osteoporosis screening is recommended for women under age 65 without risk factors.", "B": "Order a DEXA scan now as women should be screened starting at age 30.", "C": "Order a DEXA scan at age 40 as a baseline for future comparison.", "D": "Screen now using the FRAX score to calculate her fracture risk."}, "correct": "A", "explanation": "The USPSTF recommends osteoporosis screening beginning at age 65 for women without risk factors; no screening is recommended for a 30-year-old with no risk factors or fractures. Ordering a DEXA scan at age 30 is not supported by any major guideline for low-risk women and would result in unnecessary testing and potential overdiagnosis. Ordering a DEXA at age 40 as a baseline is also not recommended by USPSTF for women without risk factors; screening begins at 65 in average-risk women."}, {"id": 632, "domain": "professional_practice", "question": "A 55-year-old man is concerned about prostate cancer. He asks his NP whether he should have a PSA test. Per USPSTF guidelines, what is the most appropriate counseling?", "options": {"A": "PSA testing is not recommended at any age as harms outweigh benefits.", "B": "For men aged 55 to 69, PSA screening is an individual decision after discussion of harms and benefits.", "C": "Annual PSA screening is recommended for all men over 50 without exception.", "D": "PSA testing is only recommended for Black men and those with a family history."}, "correct": "B", "explanation": "The USPSTF recommends that for men aged 55 to 69, PSA-based screening for prostate cancer is an individual decision made after a shared discussion between the clinician and patient about the potential benefits and harms. PSA testing is not categorically rejected for all ages; the USPSTF gives it a C recommendation for men 55 to 69 and recommends against it for men 70 and older. Annual PSA screening for all men over 50 without exception reflects older and more aggressive guidelines, not the current evidence-based USPSTF recommendation."}, {"id": 636, "domain": "professional_practice", "question": "A 70-year-old man has never received the influenza vaccine and is presenting for a wellness visit in October. He has no egg allergy and is immunocompetent. What is the most appropriate recommendation?", "options": {"A": "Administer the standard-dose inactivated influenza vaccine as in all adults.", "B": "Administer the high-dose or adjuvanted influenza vaccine preferred for adults over 65.", "C": "Defer influenza vaccine until the patient is under 65 to avoid reduced efficacy.", "D": "Administer the live attenuated nasal spray vaccine for maximum immune response."}, "correct": "B", "explanation": "For adults aged 65 and older, ACIP and USPSTF prefer the high-dose or adjuvanted influenza vaccine because it produces a stronger immune response in older adults whose immune systems respond less effectively to standard doses. The standard-dose inactivated influenza vaccine is inferior to high-dose or adjuvanted formulations for adults over 65 and is not the preferred option in this age group. Deferring influenza vaccine until the patient is under 65 is not a coherent clinical recommendation; age 65 and older is precisely when the high-dose formulation is most important."}, {"id": 637, "domain": "professional_practice", "question": "A newly hired NP is asked to provide care for patients in a specialty area where she has no training or experience. Her employer tells her that her NP license covers all specialty areas. What is the most appropriate response?", "options": {"A": "Comply with the employer's request as an NP license is unrestricted in scope.", "B": "Decline to practice beyond her competency and seek training or appropriate referral.", "C": "Consult the state board of nursing before accepting any specialty assignment.", "D": "Accept the assignment but add a disclaimer to each note that she lacks specialty training."}, "correct": "B", "explanation": "NP scope of practice is defined by competency as well as state law; accepting assignments beyond one's training is unethical and potentially dangerous to patients, regardless of what the employer says about licensure scope. Complying because an NP license is unrestricted ignores the competency standard that governs ethical practice; licensure establishes the legal framework but not clinical proficiency in every area. Consulting the state board of nursing would be informative but does not resolve the clinical competency issue in the immediate term; the appropriate action is to decline and seek training or appropriate referral."}, {"id": 638, "domain": "professional_practice", "question": "An NP is evaluating a 28-year-old man with suicidal ideation. He has a gun at home. His risk is assessed as moderate. What is the most effective risk-reduction intervention at this visit?", "options": {"A": "Hospitalize him immediately as any firearm access makes him high risk.", "B": "Prescribe a sedative to reduce impulsivity and schedule follow-up in two days.", "C": "Counsel on means restriction and arrange for temporary removal of the firearm.", "D": "Have him sign a no-suicide contract and document it in the medical record."}, "correct": "C", "explanation": "Counseling on means restriction and arranging temporary removal of the firearm is one of the most evidence-based interventions for suicide risk reduction, as access to lethal means is a major risk factor for completed suicide. Hospitalization may be appropriate for high-risk patients but for a moderate-risk patient, means restriction is a critical and evidence-based intervention that directly reduces the opportunity for a fatal suicide attempt. Prescribing a sedative does not address the access to a firearm and may reduce inhibitions in some patients, increasing rather than decreasing risk."}, {"id": 639, "domain": "professional_practice", "question": "A 68-year-old woman asks about hepatitis C screening. She has never been tested and is otherwise healthy. She was born between 1945 and 1965. What is the appropriate recommendation?", "options": {"A": "One-time hepatitis C antibody screening is recommended for all adults born 1945 to 1965.", "B": "Screening is only recommended if she has a history of IV drug use or blood transfusion.", "C": "Screen only with HCV RNA PCR as antibody testing is unreliable in older adults.", "D": "Hepatitis C screening is not recommended after age 65 as treatment is not effective."}, "correct": "A", "explanation": "The USPSTF recommends one-time hepatitis C antibody screening for all adults born between 1945 and 1965, regardless of risk factors, because this birth cohort has a much higher prevalence of HCV infection. Restricting screening to those with risk factors would miss a large proportion of infected baby boomers who were exposed before risk awareness was established. HCV RNA PCR is used to confirm active infection after a positive antibody test but is not the appropriate first-line screening tool."}, {"id": 640, "domain": "professional_practice", "question": "A 40-year-old man comes in for a preventive visit. He has no symptoms and no cardiovascular risk factors. Which USPSTF recommendation applies to hypertension screening?", "options": {"A": "Measure blood pressure only if the patient complains of headaches or palpitations.", "B": "Screen for hypertension annually in adults aged 18 and older using office blood pressure.", "C": "Screen for hypertension every five years for adults under 50 without risk factors.", "D": "Screen for hypertension starting at age 45 per standard cardiovascular risk guidelines."}, "correct": "B", "explanation": "The USPSTF recommends blood pressure screening for all adults aged 18 and older at every clinical encounter, as hypertension is a common and often asymptomatic condition where early detection and treatment significantly reduce cardiovascular events. Measuring blood pressure only when symptoms are present would miss the vast majority of hypertensive patients, since hypertension is typically asymptomatic. Screening every five years for adults under 50 without risk factors is not consistent with current recommendations for routine blood pressure measurement in all adult patients."}, {"id": 642, "domain": "pharmacology", "question": "A 65-year-old woman with heart failure and atrial fibrillation is started on amiodarone. She is also on digoxin 0.25 mg daily. What is the most important medication adjustment needed?", "options": {"A": "No adjustment needed; amiodarone and digoxin are commonly used together safely.", "B": "Increase digoxin to compensate for reduced absorption caused by amiodarone.", "C": "Reduce digoxin dose by 50% and monitor levels as amiodarone increases digoxin levels.", "D": "Discontinue digoxin immediately as it is contraindicated with amiodarone."}, "correct": "C", "explanation": "Amiodarone inhibits the metabolism and renal clearance of digoxin, causing digoxin levels to rise substantially; when amiodarone is added, the digoxin dose should be reduced by approximately 50% and levels monitored closely. No adjustment is needed is incorrect; failure to reduce the digoxin dose when amiodarone is started risks digoxin toxicity, which can cause life-threatening arrhythmias. Increasing digoxin to compensate for reduced absorption is the opposite of what is needed; amiodarone raises, not lowers, digoxin levels."}, {"id": 643, "domain": "pharmacology", "question": "A 70-year-old woman with stage 4 CKD and diabetes is prescribed gabapentin 300 mg three times daily for neuropathic pain. Two weeks later she is lethargic and confused. What is the most likely cause?", "options": {"A": "Gabapentin toxicity from accumulation due to reduced renal clearance.", "B": "Hypoglycemia from diabetic medication interaction with gabapentin.", "C": "Diabetic encephalopathy unrelated to gabapentin.", "D": "Gabapentin-induced hepatotoxicity causing encephalopathy."}, "correct": "A", "explanation": "Gabapentin is primarily renally cleared, and in stage 4 CKD with significantly reduced eGFR, the drug accumulates and reaches toxic levels, causing sedation and cognitive impairment such as the lethargy and confusion described. Hypoglycemia from drug interaction is not a recognized mechanism of gabapentin toxicity and would present differently from sedation and confusion. Diabetic encephalopathy typically presents in the context of severe uncontrolled hyperglycemia or renal failure, not specifically after starting a new medication like gabapentin."}, {"id": 644, "domain": "pharmacology", "question": "A 33-year-old woman is planning to conceive. She has been taking isotretinoin for cystic acne for three months. What is the most critical step before she attempts pregnancy?", "options": {"A": "Stop isotretinoin and wait at least one month before attempting conception.", "B": "Reduce the isotretinoin dose to the lowest effective level during conception attempts.", "C": "Continue isotretinoin with strict contraception as it is safe with precautions.", "D": "Switch to a topical retinoid as it is safer than systemic isotretinoin in pregnancy."}, "correct": "A", "explanation": "Isotretinoin is a potent teratogen in the FDA's iPLEDGE program; the drug must be stopped and the patient must wait at least one month before attempting conception because of its teratogenicity. Reducing the dose during conception attempts does not eliminate the teratogenic risk; the drug must be completely stopped before pregnancy. Continuing isotretinoin with contraception during the attempt period is not safe once pregnancy is desired because any pregnancy exposure could cause severe birth defects."}, {"id": 645, "domain": "pharmacology", "question": "A 55-year-old man on warfarin is started on rifampin for active tuberculosis. What pharmacokinetic interaction must be anticipated?", "options": {"A": "Rifampin induces CYP enzymes, dramatically reducing warfarin levels and lowering INR.", "B": "Rifampin inhibits CYP2C9, increasing warfarin levels and raising INR significantly.", "C": "Rifampin displaces warfarin from protein binding sites increasing free drug levels.", "D": "No significant interaction exists between rifampin and warfarin."}, "correct": "A", "explanation": "Rifampin is one of the most potent inducers of CYP enzymes and dramatically accelerates the metabolism of warfarin, which reduces warfarin's anticoagulant effect and lowers the INR; warfarin doses often need to be substantially increased. Rifampin does not inhibit CYP2C9; it strongly induces it and other CYP pathways, leading to faster breakdown of warfarin. Rifampin does not displace warfarin from protein binding sites as a primary mechanism; its main effect is on hepatic enzyme induction."}, {"id": 648, "domain": "pharmacology", "question": "A 72-year-old man with a history of BPH and hypertension is started on tamsulosin. He also takes sildenafil for erectile dysfunction. What is the most critical counseling point?", "options": {"A": "Co-administration can cause severe hypotension; use with extreme caution or avoid.", "B": "There is no clinically significant interaction between tamsulosin and sildenafil.", "C": "Sildenafil increases tamsulosin levels requiring dose reduction of tamsulosin.", "D": "Tamsulosin increases sildenafil bioavailability requiring sildenafil dose reduction."}, "correct": "A", "explanation": "Co-administration of tamsulosin and sildenafil can cause severe additive hypotension because both drugs reduce vascular tone through different mechanisms, and this combination should be used with extreme caution or avoided. Saying there is no clinically significant interaction between tamsulosin and sildenafil is incorrect; this is a well-documented interaction that can cause symptomatic hypotension and syncope. Sildenafil does not significantly increase tamsulosin levels through pharmacokinetic mechanisms; the interaction is pharmacodynamic through additive blood pressure lowering."}, {"id": 652, "domain": "pharmacology", "question": "A 35-year-old woman with bipolar disorder becomes pregnant while on lithium. Her psychiatrist is considering continuing lithium. What fetal risk must be counseled?", "options": {"A": "Lithium is completely safe in pregnancy and no specific fetal monitoring is needed.", "B": "Lithium is associated with Ebstein anomaly, a cardiac malformation, in early pregnancy.", "C": "Lithium causes neural tube defects similar to valproate in the first trimester.", "D": "The main risk of lithium in pregnancy is neonatal thyroid disease at delivery."}, "correct": "B", "explanation": "Lithium is associated with Ebstein anomaly, a rare congenital heart defect involving the tricuspid valve, when taken during the first trimester; the absolute risk is low but must be discussed as part of informed consent before continuing lithium in pregnancy. Lithium is not completely safe in pregnancy; the Ebstein anomaly risk, though small, is real and requires counseling and potential fetal cardiac monitoring. Lithium does not cause neural tube defects; that risk is primarily associated with valproate and carbamazepine, not lithium."}, {"id": 654, "domain": "pharmacology", "question": "A 50-year-old woman with rheumatoid arthritis is on methotrexate and is prescribed trimethoprim-sulfamethoxazole for a UTI. What is the most important drug-drug interaction concern?", "options": {"A": "TMP-SMX reduces methotrexate renal clearance increasing toxicity risk significantly.", "B": "TMP-SMX and methotrexate together increase the risk of crystalluria.", "C": "TMP-SMX reduces methotrexate efficacy by blocking folate metabolism differently.", "D": "There is no clinically significant interaction between TMP-SMX and methotrexate."}, "correct": "A", "explanation": "TMP-SMX reduces the renal tubular secretion of methotrexate, causing the drug to accumulate to toxic levels, which can result in severe bone marrow suppression, mucositis, and renal toxicity. TMP-SMX and methotrexate causing crystalluria is not a well-established interaction; the primary concern is methotrexate accumulation from impaired tubular secretion. TMP-SMX reducing methotrexate efficacy by blocking folate metabolism differently is incorrect; both drugs compete for folate pathways, which would increase methotrexate toxicity, not reduce its efficacy."}, {"id": 661, "domain": "pharmacology", "question": "A 40-year-old woman is started on an MAOI for refractory depression. She asks about dietary restrictions. What is the most critical instruction?", "options": {"A": "Avoid tyramine-rich foods such as aged cheeses and cured meats to prevent hypertensive crisis.", "B": "Avoid all fresh fruit as it interacts with MAOIs to cause serotonin syndrome.", "C": "No dietary restrictions are needed with newer reversible MAOIs such as phenelzine.", "D": "Avoid all caffeine as it triggers autonomic instability when combined with MAOIs."}, "correct": "A", "explanation": "MAOIs prevent the breakdown of tyramine in the gut and liver, so eating tyramine-rich foods such as aged cheeses, cured meats, and fermented products can cause a dangerous hypertensive crisis from tyramine-induced norepinephrine release. Avoiding all fresh fruit is not the relevant dietary restriction; tyramine-rich aged and fermented foods are the concern, not fresh produce. Newer reversible MAOIs like moclobemide have fewer dietary restrictions than older irreversible MAOIs, but phenelzine is an irreversible MAOI that does require strict tyramine avoidance."}, {"id": 666, "domain": "pharmacology", "question": "A patient calls reporting she accidentally took a double dose of her metformin 1,000 mg this morning. She feels fine. She has normal renal function. What is the most appropriate advice?", "options": {"A": "Go to the emergency department immediately as metformin overdose is life-threatening.", "B": "Skip the evening dose to compensate and increase hydration for 24 hours.", "C": "Take the next dose as scheduled and do not skip or adjust any future doses.", "D": "Monitor for nausea, diarrhea, or lightheadedness and call back if symptoms develop."}, "correct": "D", "explanation": "A single accidental double dose of metformin in a patient with normal renal function is unlikely to cause serious harm, but the patient should monitor for metformin's common side effects of nausea, diarrhea, and lightheadedness, and call back if symptoms develop. Going to the emergency department immediately is excessive for a single double dose in a patient with normal renal function; metformin overdose risk is primarily in those with impaired renal clearance. Taking the next dose as scheduled without any modification could result in excess metformin if the timing is too close to the accidental double dose; skipping the next scheduled dose is more appropriate."}, {"id": 667, "domain": "pharmacology", "question": "A 55-year-old man is on simvastatin 40 mg daily. He is prescribed amlodipine for hypertension. What medication interaction must be considered?", "options": {"A": "Amlodipine mildly increases simvastatin levels; consider limiting simvastatin to 20 mg.", "B": "Amlodipine and simvastatin have no interaction and can be used together freely.", "C": "Amlodipine reduces simvastatin absorption requiring dose increase of the statin.", "D": "Switch simvastatin to pravastatin as it has no interaction with calcium channel blockers."}, "correct": "A", "explanation": "Amlodipine mildly inhibits CYP3A4 and can moderately increase simvastatin plasma levels, raising the risk of myopathy; FDA guidelines recommend limiting simvastatin to 20 mg daily when co-administered with amlodipine. Saying amlodipine and simvastatin have no interaction is incorrect; this combination is recognized as clinically significant and the FDA has issued specific simvastatin dose limitations with amlodipine. Amlodipine reducing simvastatin absorption requiring dose increase is the opposite of the actual interaction; amlodipine increases, not decreases, simvastatin exposure."}, {"id": 677, "domain": "primary_care_medicine", "question": "A 29-year-old woman with Crohn's disease on azathioprine presents with a 3-week history of fever, bloody diarrhea 8 times daily, and 10-pound weight loss. C-reactive protein is 68 mg/L. Stool cultures are negative. Colonoscopy reveals continuous mucosal involvement from the rectum to the splenic flexure. Which reassessment of her diagnosis should be considered?", "options": {"A": "Increase azathioprine dose because her Crohn's disease is clearly inadequately controlled.", "B": "Add mesalamine for rectal disease given the distribution pattern seen on colonoscopy.", "C": "Consider reclassifying to ulcerative colitis based on continuous pattern from the rectum.", "D": "Start infliximab because the patient has refractory Crohn's disease on immunosuppression."}, "correct": "C", "explanation": "Crohn's disease classically involves discontinuous, transmural, skip lesions often in the terminal ileum, while ulcerative colitis begins at the rectum and spreads continuously and proximally with superficial mucosal involvement. Continuous involvement from rectum to splenic flexure on colonoscopy is more consistent with UC than Crohn's, and reclassifying the diagnosis changes management, particularly regarding use of mesalamine-based therapy and the applicability of colectomy as a curative option. Simply intensifying azathioprine or adding infliximab without reconsidering the diagnosis would be premature when the endoscopic pattern does not fit the original Crohn's classification."}, {"id": 680, "domain": "primary_care_medicine", "question": "A 48-year-old man with no prior cardiac history presents with pleuritic chest pain, fever of 38.6 degrees C, and a pericardial friction rub. ECG shows diffuse ST elevation in a saddle-shaped pattern with PR depression. He reports a viral illness 2 weeks ago. Troponin is mildly elevated at 0.18 ng/mL. Which management is most appropriate?", "options": {"A": "Start high-dose aspirin and colchicine and restrict activity for 3 months.", "B": "Admit for emergent cardiac catheterization given the ST elevation pattern.", "C": "Start ibuprofen alone because it is first-line therapy for acute pericarditis.", "D": "Start prednisone because the elevated troponin indicates myopericarditis."}, "correct": "A", "explanation": "The classic presentation of saddle-shaped ST elevation, PR depression, pleuritic chest pain, pericardial friction rub, and recent viral illness is acute viral pericarditis, treated with high-dose aspirin plus colchicine to reduce recurrence, along with activity restriction for at least 3 months. Emergent catheterization is not indicated because the ECG pattern is diffuse rather than the territorial distribution of STEMI. Corticosteroids are avoided in initial therapy because they increase recurrence rates and are reserved for cases refractory to NSAIDs and colchicine."}, {"id": 683, "domain": "primary_care_medicine", "question": "A 62-year-old man with type 2 diabetes and CKD stage 4 (eGFR 24 mL/min) presents with a potassium of 5.9 mEq/L. He is on lisinopril, spironolactone, and trimethoprim-sulfamethoxazole for a UTI. His creatinine is 3.4 mg/dL. Which is the most important intervention?", "options": {"A": "Discontinue lisinopril because ACE inhibitors are contraindicated in CKD stage 4.", "B": "Stop spironolactone and trimethoprim-sulfamethoxazole and reassess potassium.", "C": "Add sodium polystyrene sulfonate to lower potassium acutely.", "D": "Obtain an ECG and consider IV calcium gluconate if QRS changes are present."}, "correct": "D", "explanation": "A potassium of 5.9 mEq/L in a patient with CKD and three potassium-retaining agents is a medical urgency, and the first priority is an ECG to assess for cardiac conduction abnormalities such as peaked T waves or widened QRS, followed by IV calcium gluconate if changes are present to stabilize the myocardium. Simultaneously, the offending agents can be stopped, but cardiac protection takes precedence over medication adjustment when potassium is this high. Sodium polystyrene sulfonate works slowly over hours and is not the first priority when the cardiac risk from hyperkalemia has not yet been assessed."}, {"id": 687, "domain": "primary_care_medicine", "question": "A 59-year-old woman with no cardiac history presents with sudden onset crushing substernal chest pain radiating to the jaw, relieved partially by sublingual nitroglycerin. ECG shows 1 mm ST depression in leads V4 through V6. Initial troponin is negative. She has diabetes and chronic kidney disease. Which management strategy is most appropriate?", "options": {"A": "Discharge with a stress test scheduled within 72 hours given negative troponin.", "B": "Repeat troponin at 3 hours and 6 hours; treat as NSTEMI if either is elevated.", "C": "Admit to the CCU and initiate heparin, antiplatelet therapy, and cardiology referral.", "D": "Obtain echocardiogram to assess for wall motion abnormalities before deciding on admission."}, "correct": "C", "explanation": "Classic anginal symptoms with ST depression in a diabetic patient with CKD represent a high-risk acute coronary syndrome presentation requiring immediate admission, anticoagulation with heparin, dual antiplatelet therapy, and cardiology evaluation for possible early invasive strategy. A negative initial troponin does not exclude NSTEMI, as troponin release may be delayed up to 6 hours from symptom onset, and discharging this patient with outpatient stress testing is unsafe given the high-risk ECG changes and clinical context. Echocardiogram is not the next step in an unstable patient whose chest pain and ECG changes already indicate myocardial ischemia requiring inpatient management."}, {"id": 691, "domain": "primary_care_medicine", "question": "A 47-year-old man presents with a 6-month history of gradually worsening dyspnea on exertion. He has a history of hepatitis C cirrhosis. Echocardiogram shows right ventricular dilation and estimated pulmonary artery systolic pressure of 58 mmHg. Left ventricular function is normal. Six-minute walk distance is 310 meters. Which diagnosis does this presentation suggest?", "options": {"A": "Hepatopulmonary syndrome from intrapulmonary vascular dilation in cirrhosis.", "B": "Cardiac cirrhosis causing biventricular dysfunction and pulmonary congestion.", "C": "Portopulmonary hypertension requiring right heart catheterization for confirmation.", "D": "Group 3 pulmonary hypertension from occult hypoxia in decompensated cirrhosis."}, "correct": "C", "explanation": "Pulmonary hypertension occurring in a patient with portal hypertension from cirrhosis, with right ventricular dilation and elevated pulmonary artery pressures on echo, is portopulmonary hypertension until confirmed otherwise, and right heart catheterization is required to establish the diagnosis by measuring mean pulmonary artery pressure, pulmonary capillary wedge pressure, and pulmonary vascular resistance. Hepatopulmonary syndrome produces hypoxemia from intrapulmonary shunting and causes orthodeoxia, not exertional dyspnea with pulmonary hypertension on echo. Cardiac cirrhosis refers to liver damage from right heart failure, not pulmonary hypertension caused by liver disease."}, {"id": 700, "domain": "primary_care_medicine", "question": "A 58-year-old man with alcoholic cirrhosis presents with increasing abdominal girth and bilateral lower extremity edema. Serum sodium is 128 mEq/L and creatinine is 1.9 mg/dL (baseline 0.8). No hepatotoxins taken. Urine sodium is 8 mEq/L. Urine osmolarity is 620 mOsm/kg. Which diagnosis best fits this clinical picture?", "options": {"A": "Prerenal azotemia from diuretic overuse causing volume depletion and sodium retention.", "B": "Spontaneous bacterial peritonitis triggering cytokine-mediated acute kidney injury.", "C": "Acute tubular necrosis from hepatic toxin causing intrinsic kidney injury.", "D": "Hepatorenal syndrome type 1 caused by renal vasoconstriction from splanchnic dilation."}, "correct": "D", "explanation": "In a cirrhotic patient with worsening ascites, hyponatremia, rising creatinine without a nephrotoxic cause, very low urine sodium (below 10 mEq/L), and high urine osmolarity, the diagnosis is hepatorenal syndrome type 1, reflecting intense renal vasoconstriction driven by splanchnic dilation and reduced effective arterial blood volume. Prerenal azotemia from diuretic overuse would be excluded if diuretics were held and volume repleted without improvement in creatinine. Acute tubular necrosis typically shows granular casts and a urine sodium above 20 mEq/L, which is inconsistent with this low urine sodium pattern."}, {"id": 705, "domain": "primary_care_medicine", "question": "A 44-year-old woman with a history of inflammatory bowel disease on azathioprine presents with new-onset jaundice, right upper quadrant pain, and an elevated alkaline phosphatase of 480 U/L. AST and ALT are mildly elevated. MRCP shows multifocal biliary strictures. Which condition is most likely?", "options": {"A": "Primary sclerosing cholangitis, which is strongly associated with inflammatory bowel disease.", "B": "Azathioprine-induced hepatotoxicity causing a cholestatic pattern of liver injury.", "C": "Choledocholithiasis causing intermittent biliary obstruction and cholestasis.", "D": "Primary biliary cholangitis associated with positive anti-mitochondrial antibody."}, "correct": "A", "explanation": "Primary sclerosing cholangitis is strongly associated with inflammatory bowel disease, particularly ulcerative colitis but also Crohn's disease, and the MRCP pattern of multifocal biliary strictures is characteristic of PSC. Azathioprine hepatotoxicity typically causes transaminase elevation in a hepatocellular pattern, not the alkaline phosphatase-dominant cholestatic pattern with structuring seen here. Primary biliary cholangitis is associated with anti-mitochondrial antibodies and affects middle-aged women with gradual cholestasis, not the IBD-associated multifocal stricturing pattern seen on MRCP."}, {"id": 706, "domain": "primary_care_medicine", "question": "A 60-year-old man with CKD stage 3b and type 2 diabetes is found to have a hemoglobin of 9.8 g/dL. Iron studies show ferritin 280 ng/mL, transferrin saturation 28%, and reticulocyte count 1.2%. Vitamin B12 and folate are normal. Which is the most likely cause of his anemia?", "options": {"A": "Iron deficiency anemia from occult GI bleeding caused by diabetes-related gastroparesis.", "B": "Anemia of chronic disease related to diabetes causing inflammatory cytokine suppression.", "C": "Erythropoietin deficiency anemia of CKD with normal iron stores and low reticulocyte count.", "D": "Mixed iron and EPO deficiency requiring both IV iron and erythropoiesis-stimulating agent."}, "correct": "C", "explanation": "In CKD, the failing kidneys produce insufficient erythropoietin, leading to normocytic, normochromic anemia with a low reticulocyte count and normal iron stores, which matches this patient's ferritin and transferrin saturation in the absence of any other identifiable cause. Iron deficiency is characterized by low ferritin (typically below 30 ng/mL) and low transferrin saturation below 20%, neither of which is present here. Anemia of chronic inflammation from diabetes typically occurs with lower ferritin and in the context of active inflammatory markers, while this presentation is most consistent with isolated EPO deficiency from CKD."}, {"id": 708, "domain": "primary_care_medicine", "question": "A 72-year-old woman with type 2 diabetes, hypertension, and CKD stage 3 (eGFR 41) presents for medication review. She is on metformin 1000 mg twice daily. Her creatinine increased from 1.3 to 1.6 mg/dL (eGFR now 38) over the past 3 months. Which action regarding metformin is most appropriate?", "options": {"A": "Discontinue metformin because it is contraindicated when eGFR falls below 45 mL/min.", "B": "Reduce metformin to 500 mg twice daily and continue monitoring renal function.", "C": "Continue current dose because metformin is safe in CKD up to an eGFR of 30 mL/min.", "D": "Hold metformin temporarily until eGFR stabilizes, then reassess in 3 months."}, "correct": "B", "explanation": "Current FDA labeling allows metformin continuation when eGFR is 30 to 45 mL/min with dose reduction and close monitoring, and the threshold for discontinuation is an eGFR below 30 mL/min, not 45. At an eGFR of 38, the appropriate action is reducing the metformin dose to 500 mg twice daily and monitoring renal function every 3 months to detect further decline. Stopping metformin at an eGFR of 38 denies the patient a safe, effective medication that also provides cardiovascular benefit beyond glucose lowering."}, {"id": 711, "domain": "primary_care_medicine", "question": "A 48-year-old man presents with anterior chest pain that worsens on inspiration and is relieved when he leans forward. He had URI symptoms 10 days ago. He has no history of cardiac disease. ECG shows diffuse ST elevation with concave morphology and PR depression in multiple leads. Which intervention is contraindicated?", "options": {"A": "Colchicine to reduce recurrence risk in this first episode of pericarditis.", "B": "Aspirin 750 mg every 8 hours as anti-inflammatory first-line treatment.", "C": "Ibuprofen at anti-inflammatory doses for pain and inflammation control.", "D": "Corticosteroids as initial anti-inflammatory therapy for uncomplicated pericarditis."}, "correct": "D", "explanation": "Corticosteroids are contraindicated as initial anti-inflammatory therapy for acute pericarditis because they significantly increase the rate of recurrence and are associated with worse long-term outcomes when used in first episodes of non-immune pericarditis. First-line therapy consists of aspirin or NSAIDs plus colchicine, with corticosteroids reserved for cases refractory to first-line therapy or for specific indications such as autoinflammatory or connective tissue disease-related pericarditis. Both aspirin and ibuprofen are acceptable first-line options, and colchicine reduces the risk of recurrence when added to the NSAID regimen."}, {"id": 713, "domain": "primary_care_medicine", "question": "A 61-year-old woman presents with exertional dyspnea and a 6-month history of progressive fatigue. Echo shows a bicuspid aortic valve with peak velocity of 4.8 m/s and mean gradient of 48 mmHg. Her EF is 58%. She denies syncope or angina. Which management strategy is most appropriate?", "options": {"A": "Refer for aortic valve replacement because she meets hemodynamic criteria for severe AS.", "B": "Continue surveillance with annual echocardiography until symptoms develop.", "C": "Start digoxin to slow progression of aortic stenosis in asymptomatic patients.", "D": "Initiate transcatheter aortic valve replacement because she is a high surgical risk patient."}, "correct": "A", "explanation": "A peak aortic valve velocity above 4 m/s and a mean gradient above 40 mmHg define severe aortic stenosis, and exertional dyspnea in a patient with severe AS meets Class I guideline criteria for aortic valve replacement even with a preserved ejection fraction. Watchful waiting with annual echocardiography is appropriate for asymptomatic severe AS with normal EF, but this patient has developed symptoms, which is the critical threshold for intervention. Transcatheter AVR is typically reserved for patients at high or prohibitive surgical risk, and the default in this otherwise-described patient without high surgical risk is surgical AVR."}, {"id": 714, "domain": "primary_care_medicine", "question": "A 49-year-old woman with systemic lupus erythematosus presents with facial rash flare, arthritis, and serositis. Her creatinine has risen from 0.7 to 1.4 mg/dL over 4 weeks. Urinalysis shows RBC casts and 2+ proteinuria. Complement levels are low. Anti-dsDNA is 1:640. Which diagnosis requires urgent evaluation?", "options": {"A": "Lupus nephritis requiring renal biopsy to classify and guide immunosuppressive therapy.", "B": "Interstitial nephritis from NSAIDs she may be using for joint pain and serositis.", "C": "Thrombotic microangiopathy from antiphospholipid antibody syndrome in SLE patients.", "D": "Prerenal azotemia from serositis causing reduced effective circulating volume."}, "correct": "A", "explanation": "Active urinary sediment with RBC casts and rising creatinine in a patient with lupus flare, low complement, and high anti-dsDNA antibody indicates lupus nephritis, and renal biopsy is needed urgently to classify the histologic class because therapy, particularly the choice between mycophenolate mofetil and cyclophosphamide, is guided by the biopsy class. Interstitial nephritis from NSAIDs is possible but would not produce RBC casts, which are pathognomonic of glomerular inflammation. Thrombotic microangiopathy from antiphospholipid syndrome is a consideration, but RBC casts specifically point to glomerulonephritis, making biopsy the priority step."}, {"id": 717, "domain": "primary_care_medicine", "question": "A 65-year-old man with type 2 diabetes and known CKD stage 3a (eGFR 55) is scheduled for a cardiac catheterization. He is on metformin 500 mg twice daily. Which action regarding metformin is most appropriate perioperatively?", "options": {"A": "Continue metformin throughout the procedure because contrast nephropathy risk is low.", "B": "Hold metformin on the day of the procedure and 48 hours after contrast administration.", "C": "Permanently discontinue metformin because contrast dye permanently reduces eGFR.", "D": "Switch to insulin before the procedure because all oral agents must be held perioperatively."}, "correct": "B", "explanation": "The standard perioperative recommendation for patients on metformin who require iodinated contrast is to hold metformin on the day of the procedure and for 48 hours after contrast administration, then reassess renal function before resuming, because contrast-induced nephropathy can transiently reduce eGFR and precipitate metformin-associated lactic acidosis in the setting of acute kidney injury. Continuing metformin through the procedure ignores the real risk of contrast-induced AKI in a patient with CKD stage 3, even if baseline risk is moderate. Permanently discontinuing metformin is unnecessarily aggressive because contrast nephropathy is usually transient."}, {"id": 724, "domain": "primary_care_medicine", "question": "A 69-year-old woman presents with classic anginal symptoms and a positive stress test with imaging showing inferior wall ischemia. Coronary angiography reveals a 65% stenosis in the right coronary artery. Her EF is 62% and she has no other lesions. Which management is most appropriate?", "options": {"A": "Optimal medical therapy alone because PCI does not reduce events in stable CAD.", "B": "Percutaneous coronary intervention because the stenosis is causing symptoms.", "C": "Coronary artery bypass grafting because it provides superior long-term outcomes.", "D": "PCI with drug-eluting stent because FFR measurement would confirm hemodynamic significance."}, "correct": "A", "explanation": "The COURAGE and ISCHEMIA trials demonstrated that percutaneous coronary intervention does not reduce the risk of myocardial infarction, cardiovascular death, or stroke compared to optimal medical therapy alone in patients with stable coronary artery disease, and this 65% stenosis without high-risk features is managed conservatively. Surgery is even more aggressive and is reserved for left main or multivessel disease when benefit over PCI is established. While PCI may relieve symptoms more quickly, medical therapy should be optimized first in stable CAD before considering intervention."}, {"id": 725, "domain": "primary_care_medicine", "question": "A 60-year-old man with known peripheral artery disease, hypertension, and type 2 diabetes presents with resting pain in his right foot. ABI is 0.38 on the right. He has a 2 cm plantar ulcer with no signs of infection. Toe pressures are 28 mmHg. Which clinical term most accurately describes his condition?", "options": {"A": "Claudication stage PAD that can be managed with cilostazol and exercise rehabilitation.", "B": "Critical limb-threatening ischemia requiring urgent vascular surgery evaluation.", "C": "Diabetic neuropathic ulcer unrelated to ischemia despite the low ABI.", "D": "Charcot foot with neuropathic joint destruction causing the plantar ulcer."}, "correct": "B", "explanation": "Resting pain, an ABI below 0.4, toe pressures below 30 mmHg, and a non-healing ulcer define critical limb-threatening ischemia, a vascular emergency associated with high rates of major limb amputation and cardiovascular death if not treated urgently with revascularization. Claudication is an exertional symptom that resolves with rest and is associated with higher ABIs in the 0.4 to 0.9 range, not the resting pain and tissue loss described here. The combination of severely reduced ABI and low toe pressures confirms ischemia is the primary etiology requiring vascular surgery evaluation."}, {"id": 729, "domain": "primary_care_medicine", "question": "A 66-year-old woman with hypertension and type 2 diabetes presents with progressive dyspnea and an EF of 38% on echocardiogram. She is on enalapril, metoprolol succinate, and furosemide. Her blood pressure is 118/72 mmHg and heart rate is 58 bpm. Which evidence-based addition is most appropriate?", "options": {"A": "Switch enalapril to sacubitril-valsartan if she tolerates the ACE inhibitor without angioedema.", "B": "Add spironolactone 25 mg daily to further reduce mortality in HFrEF.", "C": "Add ivabradine because his heart rate is above 70 bpm while in sinus rhythm.", "D": "Add digoxin to improve functional class and reduce heart failure hospitalizations."}, "correct": "A", "explanation": "The PARADIGM-HF trial established that switching from an ACE inhibitor to sacubitril-valsartan in HFrEF patients reduces cardiovascular mortality and hospitalization by 20% compared to enalapril, making this switch the most evidence-based upgrade for a patient already on optimal doses of ACE inhibitor and beta-blocker. Spironolactone is an excellent additional agent in HFrEF, but the highest-impact change in a patient on enalapril and metoprolol is the ARNI switch. Ivabradine requires a heart rate above 70 bpm in sinus rhythm on maximally tolerated beta-blocker; at 58 bpm, it is not indicated."}, {"id": 731, "domain": "primary_care_medicine", "question": "A 55-year-old man with known obstructive sleep apnea presents with morning headaches, polycythemia (hematocrit 56%), and pulmonary hypertension on echocardiogram. He is not on CPAP therapy. Which intervention most directly addresses the pulmonary hypertension in this patient?", "options": {"A": "Start sildenafil for pulmonary arterial hypertension as the primary treatment.", "B": "Start supplemental oxygen because nocturnal desaturation drives pulmonary vasoconstriction.", "C": "Phlebotomy to reduce hematocrit below 45% to lower pulmonary vascular resistance.", "D": "Initiate CPAP therapy because OSA-related hypoxia is the underlying mechanism."}, "correct": "D", "explanation": "In obstructive sleep apnea, nocturnal hypoxia causes pulmonary vasoconstriction that over time leads to pulmonary hypertension, polycythemia from EPO stimulation, and right ventricular hypertrophy, and initiating CPAP therapy treats the root cause of all these complications by eliminating the hypoxic episodes. Sildenafil is indicated for pulmonary arterial hypertension (Group 1), not OSA-associated Group 3 pulmonary hypertension, and using it without treating the underlying OSA misses the etiology. Phlebotomy addresses polycythemia symptomatically but does not reduce pulmonary vascular resistance, and supplemental oxygen alone does not prevent apnea events or fully normalize pulmonary hemodynamics the way CPAP does."}, {"id": 735, "domain": "primary_care_medicine", "question": "A 68-year-old man presents for a follow-up visit. He was recently diagnosed with stage IIIA non-small cell lung cancer and wants to discuss his prognosis. He does not speak English well. His adult daughter is present and asks to translate because the medical interpreter is unavailable. Which approach is most appropriate?", "options": {"A": "Proceed with the daughter as interpreter because the patient consented to her presence.", "B": "Reschedule the visit until a professional medical interpreter is available.", "C": "Use a professional telephone interpreter to conduct the prognostic discussion.", "D": "Provide written materials in the patient's language and defer the discussion."}, "correct": "C", "explanation": "When a professional medical interpreter is unavailable in person, telephone interpreting services must be used to ensure accurate and unbiased communication, particularly for high-stakes conversations such as cancer prognosis disclosure. Using a family member as an interpreter, even with the patient's apparent consent, introduces risks of bias, emotional filtering, and incomplete translation that can compromise informed consent and patient autonomy. Rescheduling is also acceptable but telephone interpreting allows the visit to proceed without delay, which may be appropriate when the patient has traveled for the appointment and the discussion is time-sensitive."}, {"id": 736, "domain": "primary_care_medicine", "question": "A 57-year-old man with alcohol use disorder presents with acute pancreatitis. His lipase is 1,840 U/L, BUN is 24 mg/dL, creatinine is 1.8 mg/dL, hematocrit is 49%, and blood glucose is 248 mg/dL. His BISAP score is 3. Which initial management strategy is most critical?", "options": {"A": "Initiate NPO status with total parenteral nutrition to rest the inflamed pancreas.", "B": "Start aggressive IV crystalloid resuscitation with lactated Ringer's solution.", "C": "Administer IV antibiotics prophylactically to prevent pancreatic necrosis infection.", "D": "Order MRCP immediately to assess for choledocholithiasis as the etiology."}, "correct": "B", "explanation": "In acute pancreatitis, aggressive early IV fluid resuscitation with lactated Ringer's solution is the most critical initial intervention, as it maintains pancreatic microcirculatory perfusion and reduces the risk of necrotizing pancreatitis; this recommendation is supported by multiple guidelines and applies regardless of etiology. NPO with total parenteral nutrition is outdated, as early enteral nutrition is now preferred over TPN when feasible. Prophylactic antibiotics have not been shown to prevent infectious pancreatic necrosis and are not recommended, and MRCP is appropriate to evaluate for biliary obstruction but is not the highest priority before resuscitation is underway."}, {"id": 739, "domain": "primary_care_medicine", "question": "A 61-year-old woman with controlled hypertension and prior bilateral knee replacements presents with a PSA of 0.8 ng/mL at her annual exam. She asks about cervical and breast cancer screening. She had a normal mammogram 14 months ago and a normal Pap with HPV cotesting 3 years ago (HPV negative). Which screening recommendation is most appropriate?", "options": {"A": "Mammogram now and Pap with cotesting next year per annual screening guidelines.", "B": "No breast or cervical screening needed now; mammogram due in 1 year, Pap in 2 years.", "C": "Mammogram due now and Pap with cotesting not due for another 2 years.", "D": "Refer to gynecology because prior bilateral joint replacements alter cancer screening schedules."}, "correct": "C", "explanation": "USPSTF guidelines recommend mammography every 1 to 2 years for women aged 50 to 74, so a normal mammogram 14 months ago is not yet due for repeat per biennial screening; the next mammogram would be due in approximately 10 months. For cervical cancer screening, a negative Pap test and negative HPV co-test allows a 5-year interval, so her next Pap is not due for 2 more years. Bilateral knee replacements have no effect on cancer screening schedules, and no gynecology referral is needed for routine preventive care decisions."}, {"id": 745, "domain": "primary_care_medicine", "question": "A 53-year-old man is brought in by police after being found confused on the street. He smells of alcohol and his blood glucose is 38 mg/dL. He receives IV dextrose and becomes alert. He then refuses further evaluation and wants to leave. He has previously been admitted for alcohol-related pancreatitis. Which action is most appropriate?", "options": {"A": "Allow him to leave because adults have the right to refuse treatment.", "B": "Contact family members to obtain surrogate consent for continued treatment.", "C": "Assess decision-making capacity; if impaired, initiate psychiatric hold.", "D": "Administer thiamine and discharge with alcohol treatment resources."}, "correct": "C", "explanation": "When a patient has been treated for hypoglycemia and appears alert, decision-making capacity must be formally assessed before honoring a refusal of further care, because capacity fluctuates with acute metabolic states and a patient who was confused from hypoglycemia may not yet have fully recovered the cognitive function needed to make an autonomous, informed decision. If capacity is determined to be absent, a psychiatric or emergency hold is appropriate to protect the patient from self-harm by premature discharge. Simply allowing him to leave without assessing capacity ignores the responsibility to evaluate whether his apparent alertness represents genuine cognitive recovery."}, {"id": 749, "domain": "primary_care_medicine", "question": "A 44-year-old man with newly diagnosed hypertension and a blood pressure of 162/104 mmHg on two readings is also found to have a serum glucose of 128 mg/dL fasting and a BMI of 36. He smokes one pack per day and his LDL is 148 mg/dL. Which approach best addresses his overall cardiovascular risk?", "options": {"A": "Address all risk factors simultaneously with antihypertensive, statin, and diabetes workup.", "B": "Start antihypertensive therapy now and defer glucose and lipid management to the next visit.", "C": "Focus first on weight loss and smoking cessation before initiating any pharmacotherapy.", "D": "Start lisinopril only because it benefits both hypertension and potential early diabetic nephropathy."}, "correct": "A", "explanation": "A patient with newly diagnosed hypertension, impaired fasting glucose, dyslipidemia, and active smoking has multiple concurrent cardiovascular risk factors that collectively multiply ASCVD risk, and addressing all of them simultaneously with antihypertensive medication, statin therapy, diabetes workup, and smoking cessation counseling provides the greatest overall risk reduction. Deferring glucose and lipid management to future visits creates a window of preventable cardiovascular harm in a high-risk patient. Lifestyle-only approaches in a patient with blood pressure of 162/104 mmHg and a fasting glucose above 126 mg/dL are insufficient and delay necessary pharmacotherapy."}, {"id": 750, "domain": "primary_care_medicine", "question": "A 67-year-old man on atorvastatin 80 mg presents with muscle pain. CK is 12,500 U/L. His creatinine is 1.3 mg/dL (baseline 0.9). Urinalysis shows large blood but no RBCs on microscopy. Which diagnosis is most consistent with this presentation?", "options": {"A": "Statin-induced myopathy without rhabdomyolysis requiring statin dose reduction.", "B": "Rhabdomyolysis with myoglobinuria requiring IV fluid resuscitation and statin discontinuation.", "C": "Acute glomerulonephritis from immune complex deposition triggered by statin use.", "D": "Renal infarction causing hematuria and rising creatinine in a high-risk patient."}, "correct": "B", "explanation": "A CK above 10 times the upper limit of normal combined with a positive urine dipstick for blood but absent RBCs on microscopy is the classic presentation of myoglobinuria from rhabdomyolysis, and the appropriate management is discontinuing the causative statin, aggressive IV crystalloid resuscitation to maintain urine output above 200 to 300 mL/hour, and monitoring for acute kidney injury. Statin myopathy without rhabdomyolysis causes myalgias with CK below 10 times the upper limit of normal and does not require immediate IV hydration. Acute glomerulonephritis and renal infarction do not produce CK elevations of this magnitude or myoglobinuria."}, {"id": 751, "domain": "primary_care_medicine", "question": "A 36-year-old woman presents with a 3-month history of fatigue, joint pain, butterfly rash, and pleuritic chest pain. ANA is positive at 1:640 with anti-dsDNA and anti-Sm antibodies. Complement C3 and C4 are low. Urinalysis shows 3+ protein and microscopic hematuria. CBC shows hemoglobin 9.4 g/dL, platelets 88,000/mcL, and WBC 3,200/mcL. Which aspect of her presentation requires the most urgent evaluation?", "options": {"A": "The pleuritic chest pain suggesting lupus serositis requiring anti-inflammatory therapy.", "B": "The hematologic abnormalities suggesting lupus-related cytopenias requiring steroids.", "C": "The proteinuria and hematuria suggesting lupus nephritis requiring renal biopsy.", "D": "The ANA titer because a titer above 1:640 indicates severe systemic lupus erythematosus."}, "correct": "C", "explanation": "Active urinary sediment with RBC casts and 3+ proteinuria in a patient with clinical and serologic evidence of lupus flare indicates lupus nephritis, the manifestation that carries the greatest risk of irreversible organ damage and requires the most urgent evaluation with renal biopsy to guide immunosuppressive therapy selection. The cytopenias from lupus are important but rarely immediately life-threatening at these cell counts and can be managed while the nephrology workup proceeds. ANA titer alone does not determine disease severity; it is the combination of active renal disease with rising creatinine and urinary casts that mandates urgent biopsy."}, {"id": 753, "domain": "primary_care_medicine", "question": "A 58-year-old woman presents with a 6-month history of progressive symmetric proximal muscle weakness. She has difficulty rising from a chair and lifting her arms overhead. CK is 4,200 U/L. EMG shows myopathic changes. Aldolase is elevated. ANA is positive and anti-Jo-1 antibody is positive. Which diagnosis does this constellation suggest?", "options": {"A": "Polymyalgia rheumatica causing proximal muscle pain with elevated ESR.", "B": "Statin-induced myopathy causing proximal weakness with elevated CK.", "C": "Inflammatory myopathy with antisynthetase syndrome from anti-Jo-1 antibody positivity.", "D": "Systemic lupus erythematosus causing myositis as an extravascular manifestation."}, "correct": "C", "explanation": "Proximal muscle weakness with elevated CK and aldolase, myopathic changes on EMG, positive ANA, and positive anti-Jo-1 antibody defines inflammatory myopathy with antisynthetase syndrome, a subset of polymyositis or dermatomyositis associated with interstitial lung disease, mechanic's hands, Raynaud phenomenon, and arthritis in addition to the myositis. Polymyalgia rheumatica causes proximal muscle pain without true weakness, elevated ESR without significantly elevated CK, and responds dramatically to low-dose prednisone. Statin myopathy does not produce ANA or anti-Jo-1 antibody positivity, and the autoantibody pattern here clearly points to an immune-mediated inflammatory myopathy."}, {"id": 756, "domain": "primary_care_medicine", "question": "A 72-year-old man with systolic heart failure is taking carvedilol, sacubitril-valsartan, and spironolactone. His resting heart rate is 78 bpm while in sinus rhythm. His EF remains at 28% on repeat echo 3 months after optimizing therapy. Which additional evidence-based therapy should be considered?", "options": {"A": "Add digoxin to reduce heart failure hospitalizations and improve functional class.", "B": "Add ivabradine because his heart rate is above 70 bpm in sinus rhythm on beta-blocker.", "C": "Switch carvedilol to bisoprolol because it has superior evidence in HFrEF at this EF.", "D": "Add an SGLT2 inhibitor to further reduce heart failure hospitalization and mortality."}, "correct": "D", "explanation": "SGLT2 inhibitors such as empagliflozin and dapagliflozin reduce heart failure hospitalization and cardiovascular mortality in HFrEF independently of diabetes status, and in a patient already on optimal triple therapy (ARNI, beta-blocker, MRA), adding an SGLT2 inhibitor completes the four-pillar guideline-directed medical therapy for HFrEF. Ivabradine requires a resting heart rate above 70 bpm in sinus rhythm while on maximally tolerated beta-blocker, and 78 bpm does meet this threshold; however, the SGLT2 inhibitor provides superior mortality benefit and is the highest-priority addition before considering ivabradine. Digoxin reduces hospitalizations but does not reduce mortality and is not preferred over completing guideline-directed four-pillar therapy."}, {"id": 760, "domain": "primary_care_medicine", "question": "A 52-year-old man with alcohol use disorder presents with hematemesis. He is tachycardic at 112 bpm and his blood pressure is 98/60 mmHg. EGD shows three columns of grade 3 esophageal varices with active oozing. Which pharmacologic intervention must be started before endoscopy?", "options": {"A": "IV vasopressin to reduce portal venous pressure and control variceal bleeding.", "B": "IV octreotide to reduce splanchnic blood flow before and after endoscopic treatment.", "C": "IV propranolol to reduce portal pressure during active variceal hemorrhage.", "D": "IV terlipressin because it is preferred over octreotide in active variceal bleeding."}, "correct": "B", "explanation": "IV octreotide is the vasoactive agent of choice in acute variceal hemorrhage because it reduces splanchnic blood flow and portal pressure, improving the effectiveness of endoscopic therapy and reducing rebleeding rates when started as early as possible, ideally before endoscopy. Vasopressin is effective but causes significant systemic vasoconstriction including coronary ischemia and is not preferred over octreotide when octreotide is available. IV propranolol is not used during active hemorrhage, and terlipressin is used in Europe but is not the standard US recommendation."}, {"id": 761, "domain": "primary_care_medicine", "question": "A 44-year-old woman with hypothyroidism on levothyroxine 100 mcg daily is 8 weeks pregnant. TSH is 3.8 mIU/L (previously 1.4 mIU/L before pregnancy). She has no history of thyroid cancer. Which adjustment is most appropriate?", "options": {"A": "Increase levothyroxine by 25 to 30% and recheck TSH in 4 weeks to achieve target below 2.5.", "B": "No adjustment needed because TSH of 3.8 is within the normal non-pregnant reference range.", "C": "Refer to endocrinology because hypothyroidism in early pregnancy is a high-risk condition.", "D": "Reduce the dose because increased TBG in pregnancy falsely elevates measured TSH values."}, "correct": "A", "explanation": "Pregnancy dramatically increases thyroxine requirements, typically by 25 to 50%, because rising estrogen increases thyroxine-binding globulin and the placenta degrades T4, and the TSH target in the first trimester of pregnancy is below 2.5 mIU/L. A TSH of 3.8 mIU/L in early pregnancy represents inadequate replacement requiring immediate dose increase and recheck in 4 weeks to protect fetal neurodevelopment. Making no adjustment ignores the well-established physiologic demand for higher thyroid hormone in pregnancy, and reducing the dose would further suppress thyroid levels at the most critical window for fetal brain development."}, {"id": 763, "domain": "primary_care_medicine", "question": "A 73-year-old man with stable angina and CKD stage 3 (eGFR 44) presents for discussion of coronary angiography. His provider wants to use iodinated contrast. Which intervention most reduces his risk of contrast-induced nephropathy?", "options": {"A": "Pretreat with N-acetylcysteine 600 mg twice daily for 2 days before the procedure.", "B": "Administer IV isotonic saline before and after contrast administration.", "C": "Pretreat with sodium bicarbonate infusion because it alkalinizes the tubular urine.", "D": "Use iso-osmolar contrast media and hold nephrotoxic medications beforehand."}, "correct": "B", "explanation": "The most effective and evidence-based intervention to prevent contrast-induced nephropathy in a patient with CKD is preprocedural and postprocedural IV isotonic saline hydration, which maintains renal tubular flow and reduces tubular concentration of nephrotoxic contrast media. N-acetylcysteine was once popular but multiple large trials, including PRESERVE, found it provided no benefit over IV fluids alone. Sodium bicarbonate infusion showed initial promise but also failed to show benefit over normal saline in adequately powered trials, and while using iso-osmolar contrast is a best practice, the cornerstone intervention is IV fluid hydration."}, {"id": 764, "domain": "primary_care_medicine", "question": "A 58-year-old woman is referred for evaluation of a serum calcium of 11.4 mg/dL discovered incidentally. She has no symptoms of hypercalcemia. PTH is 92 pg/mL (elevated). Her 24-hour urine calcium is 380 mg/day. DXA shows a T-score of -2.6 at the lumbar spine. eGFR is 64 mL/min. Which management is indicated?", "options": {"A": "Monitor with annual calcium and renal function because she has no symptoms.", "B": "Bisphosphonate to treat the osteoporosis without addressing the primary hyperparathyroidism.", "C": "Cinacalcet to lower PTH and calcium while deferring surgery until symptomatic.", "D": "Parathyroid surgery because she meets at least one criterion for operative management."}, "correct": "D", "explanation": "Primary hyperparathyroidism with a T-score of -2.6 at the lumbar spine meets one of the four established surgical criteria (T-score below -2.5 at any site), and parathyroidectomy is the recommended treatment that normalizes calcium, lowers PTH, and prevents further bone loss. The other surgical criteria include age below 50, calcium more than 1 mg/dL above the upper limit of normal, creatinine clearance below 60 mL/min, or symptomatic nephrolithiasis. Watchful waiting and cinacalcet are appropriate when surgical criteria are not met, but this patient has met the bone density criterion, making referral for parathyroidectomy the appropriate next step."}, {"id": 769, "domain": "specialty_systems", "question": "A 45-year-old woman presents with bilateral symmetric joint stiffness in her hands and wrists lasting more than 2 hours each morning, fatigue, and bilateral metacarpophalangeal swelling for 4 months. CRP is 68 mg/L and ESR is 82 mm/hr. Rheumatoid factor is positive. X-rays show periarticular osteopenia without erosions. Which diagnosis is most likely and what is the next best step?", "options": {"A": "Osteoarthritis of the hands; begin scheduled acetaminophen and topical diclofenac.", "B": "Psoriatic arthritis; order nail exam and skin evaluation before starting DMARDs.", "C": "Early rheumatoid arthritis; begin methotrexate within 3 months of symptom onset.", "D": "Reactive arthritis; test for Chlamydia and recent GI infection before treating."}, "correct": "C", "explanation": "Symmetric MCP joint swelling with over 1 hour of morning stiffness, positive rheumatoid factor, elevated inflammatory markers, and periarticular osteopenia on X-rays in a woman of this age meets criteria for early rheumatoid arthritis, and initiating methotrexate within 3 months of symptom onset is recommended by ACR guidelines to slow joint destruction and achieve remission. Osteoarthritis typically involves DIP and PIP joints with minimal inflammation and no systemic features, and psoriatic arthritis would require skin or nail findings. Delaying DMARD therapy is not appropriate when the clinical picture strongly supports early RA and the window of opportunity for preventing erosion is narrow."}, {"id": 771, "domain": "specialty_systems", "question": "A 28-year-old woman with known migraine with aura presents with acute onset right-sided headache with scintillating scotoma. She also has right arm weakness that persists for 40 minutes after the headache begins. Neurological exam is normal when you see her 2 hours later. Which management decision is most critical?", "options": {"A": "Prescribe sumatriptan for the headache; migraine with aura and weakness is a known variant.", "B": "Reassure her that hemiplegic migraine is common and no further workup is needed today.", "C": "Obtain carotid ultrasound to evaluate for thromboembolic source of the motor symptoms.", "D": "Order urgent MRI brain with and without contrast to exclude ischemic or hemorrhagic event."}, "correct": "D", "explanation": "Focal neurological deficits lasting more than 60 minutes, even in a patient with known migraine with aura, must be evaluated with urgent MRI brain to exclude an ischemic or hemorrhagic cause before attributing the episode to hemiplegic migraine, because motor deficits of this duration significantly overlap with TIA or stroke presentation. Sumatriptan and other triptans are contraindicated in patients with hemiplegic migraine and during events with motor aura due to potential vasoconstrictive effects. Hemiplegic migraine is a rare diagnosis of exclusion that requires ruling out vascular causes, and no reassurance should be given until imaging confirms no acute intracranial pathology."}, {"id": 774, "domain": "specialty_systems", "question": "A 38-year-old woman with relapsing-remitting MS on natalizumab for 3 years presents in July with new bilateral arm weakness and fatigue that she initially attributed to the heat. Brain MRI shows a new large demyelinating lesion that appears active on gadolinium. She had a similar heat-related episode last July. Which distinction is most important?", "options": {"A": "Both scenarios are identical because heat sensitivity and relapses present the same way.", "B": "Heat exposure cannot unmask pre-existing lesions; this presentation must be a new relapse.", "C": "Natalizumab breakthrough activity is expected and should not change management.", "D": "Uhthoff phenomenon causes transient symptom worsening without new MRI lesions."}, "correct": "D", "explanation": "Uhthoff phenomenon refers to transient worsening of pre-existing MS symptoms with heat or fever, caused by slowing of conduction through already demyelinated axons at higher temperatures, and critically, it occurs without new MRI lesions or gadolinium enhancement because no new inflammatory activity is taking place. This patient's new gadolinium-enhancing lesion confirms new inflammatory demyelination, which cannot be explained by Uhthoff phenomenon and represents a true MS relapse requiring treatment escalation evaluation. The distinction matters clinically because Uhthoff phenomenon requires only cooling and symptom management, while a true relapse in a patient on natalizumab may require a change in disease-modifying therapy."}, {"id": 780, "domain": "specialty_systems", "question": "A 55-year-old woman presents with a painful, warm, erythematous left lower leg. Temperature is 37.9 degrees C. She has no fluctuance, crepitus, or bullae. Blood glucose is normal. She has no wound or portal of entry. CRP is 88 mg/L. Which management decision best matches the likely pathogen?", "options": {"A": "Start cephalexin or dicloxacillin targeting streptococcal and staphylococcal cellulitis.", "B": "Start trimethoprim-sulfamethoxazole to cover community-acquired MRSA cellulitis.", "C": "Start amoxicillin-clavulanate because polymicrobial coverage is needed for most cellulitis.", "D": "Start doxycycline because most community cellulitis in adults is caused by gram-negative rods."}, "correct": "A", "explanation": "Non-purulent cellulitis without immunocompromise, wound, or MRSA risk factors is most commonly caused by beta-hemolytic streptococci and methicillin-sensitive S. aureus, making cephalexin or dicloxacillin the appropriate first-line agents. Trimethoprim-sulfamethoxazole covers community-acquired MRSA but has poor streptococcal coverage, making it suboptimal for typical cellulitis."}, {"id": 782, "domain": "specialty_systems", "question": "A 50-year-old man with a history of stage IIIA melanoma presents with a new pigmented lesion on his back. It is 10 mm in diameter, asymmetric, has irregular borders, multiple colors including blue-black and red, and has evolved over 6 weeks. Which feature most strongly predicts malignancy over benign seborrheic keratosis?", "options": {"A": "The multiple colors with blue-black component suggesting deep dermal melanin deposition.", "B": "The evolution over 6 weeks because seborrheic keratoses are typically stable lesions.", "C": "The irregular asymmetric borders differentiating melanoma from benign pigmented lesions.", "D": "The diameter exceeding 6 mm in a patient with a prior melanoma diagnosis."}, "correct": "A", "explanation": "The presence of multiple colors including a blue-black component in a pigmented lesion indicates deep dermal melanin deposition from invasion into the reticular dermis, a finding that is highly specific for melanoma and not seen in seborrheic keratosis. Seborrheic keratoses are typically uniformly brown or black without the blue-black coloration associated with deep melanocytic invasion. In a patient with prior stage IIIA melanoma, any blue-black pigmented lesion requires urgent biopsy to exclude recurrence or a new primary."}, {"id": 784, "domain": "specialty_systems", "question": "A 44-year-old woman presents with acute sinusitis symptoms for 12 days including fever, purulent nasal discharge, facial pain, and maxillary tenderness. She also reports new periorbital swelling and erythema with restricted eye movement. Vision is normal. Which action is most appropriate?", "options": {"A": "Start amoxicillin-clavulanate and arrange follow-up in 72 hours to assess improvement.", "B": "Obtain CT of the orbits with contrast to evaluate for orbital cellulitis or abscess.", "C": "Refer urgently to ophthalmology for evaluation of proptosis and restricted motility.", "D": "Admit for IV antibiotics and emergent CT because orbital involvement is a complication."}, "correct": "D", "explanation": "Periorbital swelling with restricted eye movement in the setting of sinusitis indicates orbital cellulitis or a subperiosteal/orbital abscess, which is a sight- and life-threatening complication requiring immediate IV antibiotics and CT imaging with contrast. Orbital involvement can lead to optic nerve compression, cavernous sinus thrombosis, and intracranial extension if not treated urgently. Outpatient amoxicillin-clavulanate and follow-up in 72 hours is appropriate for uncomplicated sinusitis but is inadequate when orbital signs are present."}, {"id": 785, "domain": "specialty_systems", "question": "A 29-year-old woman with no prior neurological history presents with a 2-week history of double vision, right eyelid drooping, and fatigue that worsens throughout the day. She reports her voice becomes nasal by afternoon. Ice pack test improves the ptosis. Repetitive nerve stimulation shows a decremental response. Anti-AChR antibodies are positive. Which condition does this represent?", "options": {"A": "Lambert-Eaton myasthenic syndrome from pre-synaptic calcium channel antibody dysfunction.", "B": "Botulism from ingestion of preformed toxin blocking acetylcholine release at the synapse.", "C": "Myasthenia gravis from autoimmune destruction of post-synaptic acetylcholine receptors.", "D": "Ocular myopathy from mitochondrial dysfunction causing bilateral ptosis and ophthalmoplegia."}, "correct": "C", "explanation": "Myasthenia gravis is caused by autoantibodies against post-synaptic acetylcholine receptors, resulting in fatigable weakness that worsens with activity and improves with rest. The positive ice pack test (improvement of ptosis with cooling), decremental response on repetitive nerve stimulation, and positive anti-AChR antibodies confirm the diagnosis. Lambert-Eaton syndrome involves pre-synaptic calcium channel antibodies, shows incremental response on high-frequency stimulation, and is associated with malignancy, none of which match this presentation."}, {"id": 786, "domain": "specialty_systems", "question": "A 65-year-old man presents with a 3-cm hyperpigmented pearly lesion on his temple with irregular rolled borders and telangiectasias. It has been present for 2 years and occasionally bleeds. Which of the following concerning features of this lesion most requires tissue diagnosis?", "options": {"A": "The pearly appearance which is typical of basal cell carcinoma on sun-exposed skin.", "B": "The rolled borders with telangiectasias consistent with nodular basal cell carcinoma pattern.", "C": "The 2-year history suggesting slow growth consistent with a low-grade malignant process.", "D": "The location on the temple, which is a high-risk area for aggressive BCC subtypes."}, "correct": "B", "explanation": "The rolled pearly borders with overlying telangiectasias on a lesion from a sun-exposed area are the hallmark features of nodular basal cell carcinoma, the most common subtype, and distinguish it from benign growths. These morphologic features combined with a 2-year history and occasional bleeding provide sufficient clinical suspicion to mandate tissue biopsy for definitive diagnosis. While the temple is a higher-risk location for aggressive BCC subtypes, the characteristic rolled border with telangiectasias is the feature most directly requiring histopathologic confirmation."}, {"id": 791, "domain": "specialty_systems", "question": "A 35-year-old woman presents with worsening low back pain for 8 weeks. She is a nurse who stands all day. MRI shows an L4-L5 disc herniation with moderate left L5 nerve root compression. She has left foot drop and decreased ankle dorsiflexion strength graded 3/5. She has tried physical therapy and NSAIDs without improvement. Which management is most appropriate?", "options": {"A": "Epidural corticosteroid injection because foot drop in a young patient will resolve spontaneously.", "B": "Continue conservative care for 3 more months before considering surgical referral.", "C": "Urgent surgical referral because progressive motor deficit from disc herniation warrants evaluation.", "D": "Start gabapentin and increase NSAID dose because this is neuropathic pain from the compression."}, "correct": "C", "explanation": "A progressive motor deficit graded 3/5 or worse from a lumbar disc herniation represents a significant neurological compromise that warrants urgent surgical evaluation regardless of duration or prior conservative measures. Foot drop indicates compromise of the L5 nerve root, and failure to decompress this root in a timely manner can result in permanent motor loss. Continuing conservative care for additional months or relying on epidural injections is inappropriate once progressive motor weakness is established, as the window for meaningful neurological recovery narrows with continued compression."}, {"id": 794, "domain": "specialty_systems", "question": "A 48-year-old woman presents with a 6-month history of progressive fatigue, dry eyes, dry mouth, parotid gland swelling, and bilateral painful joints. ANA is positive. Anti-SSA and anti-SSB antibodies are positive. Schirmer test shows 4 mm of wetting in 5 minutes. Lip biopsy shows focal lymphocytic sialadenitis with a focus score greater than 1. Which diagnosis does this presentation confirm?", "options": {"A": "Systemic lupus erythematosus with secondary Sjogren overlap causing sicca symptoms.", "B": "Primary Sjogren syndrome based on the clinical features and serologic findings.", "C": "Systemic sclerosis presenting with sicca symptoms and positive ANA in middle-aged women.", "D": "IgG4-related disease causing parotid enlargement and dry eye symptoms."}, "correct": "B", "explanation": "Primary Sjogren syndrome is defined by sicca symptoms (dry eyes and mouth), positive anti-SSA (Ro) and anti-SSB (La) antibodies, a positive Schirmer test (less than 5 mm wetting in 5 minutes), and a lip biopsy showing focal lymphocytic sialadenitis with a focus score greater than 1. The clinical presentation, serology, objective tests, and biopsy findings together fulfill the 2016 ACR/EULAR classification criteria for primary Sjogren syndrome. Secondary Sjogren syndrome occurs in the context of another systemic autoimmune disease such as SLE or RA, but the absence of other diagnostic criteria for those conditions makes primary Sjogren the correct diagnosis here."}, {"id": 798, "domain": "specialty_systems", "question": "A 30-year-old man presents with acute left testicular pain and swelling. The testis is high-riding with a horizontal lie. Cremasteric reflex is absent on the left. Doppler ultrasound is ordered but the radiologist is unavailable for 2 hours. Which action is most appropriate?", "options": {"A": "Wait for the Doppler ultrasound result before performing any intervention.", "B": "Start IV antibiotics for epididymo-orchitis while awaiting confirmatory imaging.", "C": "Attempt manual detorsion while arranging urgent urology consultation for surgical repair.", "D": "Order nuclear testicular scan as it is more sensitive than Doppler for testicular torsion."}, "correct": "C", "explanation": "Testicular torsion with the classic triad of high-riding testicle, horizontal lie, and absent cremasteric reflex is a surgical emergency with a narrow window for salvage: orchiectomy rates approach 100% after 24 hours but are very low within 6 hours. When Doppler ultrasound is unavailable or will cause unacceptable delays, manual detorsion (rotating the testicle outward, like opening a book) can temporarily restore blood flow while urgent urology consultation is arranged for definitive surgical repair. Waiting for imaging or starting antibiotics for a misdiagnosis of epididymo-orchitis causes unacceptable delay that risks permanent testicular loss."}, {"id": 800, "domain": "specialty_systems", "question": "A 42-year-old woman presents with a 3-week history of progressive weakness in the right hand. She is unable to extend the wrist and fingers. She recently started wearing a tight watchband. On exam, she has wrist drop with intact sensation over the dorsal thumb-index web space. Which nerve is involved?", "options": {"A": "Median nerve compressed at the carpal tunnel causing weakness and sensory changes.", "B": "Ulnar nerve compressed at the elbow causing hand intrinsic muscle weakness.", "C": "Radial nerve at the spiral groove causing wrist drop with spared sensation.", "D": "Posterior interosseous nerve causing finger drop without wrist drop or sensory loss."}, "correct": "C", "explanation": "The radial nerve at the spiral groove of the humerus gives off the superficial radial nerve (sensory to dorsal hand and thumb-index web space) distally, and in some spiral groove lesions this sensory branch is spared, explaining intact dorsal hand sensation despite complete wrist drop. Wrist drop is the hallmark of radial nerve palsy at or proximal to the spiral groove, and the classic cause is external compression such as a tight watchband or prolonged pressure over the lateral arm. The posterior interosseous nerve is a purely motor branch arising below the spiral groove that causes finger drop without complete wrist drop or sensory loss, which does not match the complete wrist drop seen here."}, {"id": 801, "domain": "specialty_systems", "question": "A 58-year-old woman presents with a slow-growing raised brown-black lesion with a stuck-on appearance, sharp demarcation, and waxy texture on her back. She has multiple similar lesions on her torso. They have been present for years without change. Which finding most suggests this is NOT melanoma?", "options": {"A": "The stuck-on waxy appearance and sharp demarcation characteristic of seborrheic keratosis.", "B": "The brown-black color suggesting melanin deposition typical of a benign keratosis.", "C": "The multiple lesions because melanoma is typically solitary at initial presentation.", "D": "The years of stability because melanoma would have grown significantly over that time."}, "correct": "A", "explanation": "The characteristic stuck-on, waxy, verrucous texture and sharply demarcated border of seborrheic keratoses are the features most specific for this benign diagnosis, distinguishing them from melanoma even when pigmentation is dark. Unlike melanoma, seborrheic keratoses are not invasive and do not arise from melanocytes, so dark pigmentation in SK results from epidermal pigment accumulation rather than deep dermal melanin deposition. The presence of multiple similar lesions over years of stability further supports a benign diagnosis, but the morphologic stuck-on appearance is the single most defining feature separating SK from melanoma."}, {"id": 805, "domain": "specialty_systems", "question": "A 62-year-old man presents with a 6-month history of progressively worsening symmetric distal leg weakness. He also has burning pain in his feet and has noticed he is tripping on curbs. He has type 2 diabetes for 12 years and takes metformin 1000 mg twice daily. Nerve conduction studies show axonal sensorimotor neuropathy. B12 level is 180 pg/mL (low normal). Which etiology must be considered beyond diabetic neuropathy?", "options": {"A": "Alcoholic neuropathy because diabetes and alcohol use disorder commonly co-occur.", "B": "Metformin-induced B12 deficiency contributing to or causing the neuropathy.", "C": "Hypothyroid neuropathy because thyroid disease is common in older diabetic patients.", "D": "CIDP mimicking diabetic neuropathy because it is treatable with immunotherapy."}, "correct": "B", "explanation": "Metformin inhibits vitamin B12 absorption in the terminal ileum by interfering with calcium-dependent binding to the intrinsic factor-B12 complex, and this mechanism can cause or contribute to peripheral neuropathy distinct from diabetic neuropathy. A B12 level of 180 pg/mL is in the low-normal range where functional deficiency can still occur, and this etiology must be excluded before attributing the neuropathy solely to diabetes. Supplementing B12 is a simple and potentially curative intervention if metformin-induced deficiency is confirmed, making this consideration clinically critical in any diabetic patient on long-term metformin presenting with neuropathy."}, {"id": 806, "domain": "specialty_systems", "question": "A 55-year-old man with known ankylosing spondylitis on naproxen and adalimumab presents with 6 months of worsening morning stiffness, chest tightness, and a new aortic regurgitation murmur on exam. Echo shows mild AR with a dilated aortic root. Which cardiac manifestation is most associated with ankylosing spondylitis?", "options": {"A": "Mitral valve prolapse from connective tissue disease causing mitral regurgitation.", "B": "Aortic root dilation and aortic regurgitation from aortitis in ankylosing spondylitis.", "C": "Pericarditis from systemic inflammation causing chest pain and a friction rub.", "D": "Constrictive pericarditis from fibrosis in a long-standing inflammatory arthritis patient."}, "correct": "B", "explanation": "Ankylosing spondylitis is associated with aortitis affecting the aortic root, which leads to aortic root dilation and aortic regurgitation in up to 10% of patients with long-standing disease. The inflammation extends to the aortic valve commissures and causes regurgitation by preventing proper leaflet coaptation rather than from primary valvular disease. Mitral valve involvement, pericarditis, and constrictive pericarditis are not the characteristic cardiac manifestations of ankylosing spondylitis, making aortic root dilation with AR the most associated and clinically relevant finding."}, {"id": 813, "domain": "specialty_systems", "question": "A 40-year-old man presents with a rash on his palms and soles that appeared 2 weeks after resolution of a painless penile ulcer. He also has low-grade fever, lymphadenopathy, and copper-colored papules on his trunk. Which stage of syphilis is this and what is the treatment?", "options": {"A": "Primary syphilis presenting atypically on the trunk; treat with penicillin G benzathine 1 dose.", "B": "Tertiary syphilis; treat with IV penicillin G for neurological and cardiovascular protection.", "C": "Early latent syphilis without symptoms; treat with penicillin G benzathine 3 weekly doses.", "D": "Secondary syphilis presenting with classic features; treat with penicillin G benzathine 2.4 million units."}, "correct": "D", "explanation": "Secondary syphilis occurs 6 to 8 weeks after the primary chancre resolves and represents hematogenous dissemination of T. pallidum, classically presenting with the triad of palmar-plantar rash, generalized lymphadenopathy, and constitutional symptoms. The macular or maculopapular copper-colored rash on the trunk and extremities including the palms and soles is nearly pathognomonic for secondary syphilis and does not occur in primary syphilis."}, {"id": 815, "domain": "specialty_systems", "question": "A 34-year-old man presents with acute severe right lower quadrant abdominal pain, fever of 38.9 degrees C, nausea, and rebound tenderness at McBurney's point. WBC is 18,400/mcL. CT shows a 9 mm appendix with periappendiceal fat stranding and free fluid. Which management is most appropriate?", "options": {"A": "IV antibiotics with ciprofloxacin and metronidazole as definitive non-surgical treatment.", "B": "Observe in the ED for 6 hours and repeat CT to confirm progression before surgery.", "C": "Urgent surgical consultation for appendectomy as the definitive treatment for acute appendicitis.", "D": "CT-guided drain placement to decompress the appendiceal abscess before delayed surgery."}, "correct": "C", "explanation": "Acute appendicitis with CT confirmation (9 mm appendix with periappendiceal fat stranding and free fluid), fever, rebound tenderness, and leukocytosis is best managed with urgent surgical consultation for appendectomy, which remains the definitive treatment. While recent data show antibiotics alone can be successful in uncomplicated appendicitis, a 9 mm appendix with free fluid suggests possible microperforation or advanced inflammation, making surgery the more appropriate choice. Observation for 6 hours and CT-guided drainage are appropriate for appendiceal abscess with a well-defined phlegmon, not for acute appendicitis without a mature abscess."}, {"id": 817, "domain": "specialty_systems", "question": "A 47-year-old woman presents with pain and swelling at the base of her right thumb for 6 months. Pain radiates up the radial aspect of the forearm. Finkelstein test is positive. She is a hairdresser and uses scissors and clippers all day. X-rays show no joint space narrowing. Which diagnosis and initial management is most appropriate?", "options": {"A": "Carpal tunnel syndrome; splint the wrist in neutral position and refer to occupational therapy.", "B": "De Quervain tenosynovitis; inject corticosteroid into the first dorsal compartment.", "C": "First CMC arthritis from chronic occupational use; order MRI to assess for cartilage damage.", "D": "Intersection syndrome; prescribe oral NSAIDs and modify work activity."}, "correct": "B", "explanation": "De Quervain tenosynovitis is inflammation of the abductor pollicis longus and extensor pollicis brevis tendons in the first dorsal compartment, presenting with radial-sided wrist pain and tenderness at the radial styloid with a positive Finkelstein test. Corticosteroid injection into the first dorsal compartment sheath provides significant symptom relief with success rates exceeding 70%, making it the preferred treatment over oral NSAIDs alone in a patient with occupational exposure and established disease. Carpal tunnel syndrome causes volar wrist and finger symptoms rather than radial wrist pain at the anatomical snuffbox, and MRI is not indicated when the clinical diagnosis is clear."}, {"id": 823, "domain": "specialty_systems", "question": "A 56-year-old man with longstanding ankylosing spondylitis on adalimumab presents with new onset productive cough, fever, and night sweats for 6 weeks. CXR shows upper lobe infiltrate with hilar lymphadenopathy. QuantiFERON-TB Gold is positive. He had a negative test before starting adalimumab 3 years ago. What is the most likely explanation?", "options": {"A": "False-positive QuantiFERON due to cross-reactivity with non-tuberculous mycobacteria.", "B": "TNF-alpha inhibitor therapy allowing reactivation of latent tuberculosis infection.", "C": "New TB exposure requiring prophylactic isoniazid without disrupting adalimumab.", "D": "Non-specific immune activation from adalimumab causing a positive interferon release assay."}, "correct": "B", "explanation": "TNF-alpha plays a central role in maintaining granuloma integrity around latent Mycobacterium tuberculosis, and adalimumab (a TNF-alpha inhibitor) disrupts this containment, allowing reactivation of previously dormant latent TB infection. The conversion from a negative QuantiFERON before starting adalimumab to a positive test with active pulmonary disease 3 years later is the classic presentation of TNF-inhibitor-induced TB reactivation. Standard management requires stopping the TNF inhibitor, initiating multi-drug anti-tuberculosis treatment for active disease, and delaying resumption of biologic therapy until TB is adequately treated."}, {"id": 824, "domain": "specialty_systems", "question": "A 28-year-old woman presents with fever, severe headache, stiff neck, and photophobia. She is lethargic. Lumbar puncture shows WBC 2,400/mcL (90% neutrophils), glucose 28 mg/dL (serum glucose 98), and protein 280 mg/dL. Gram stain shows gram-negative diplococci. Which empiric antibiotic is most critical to give immediately?", "options": {"A": "Vancomycin and ceftriaxone to cover both gram-positive and gram-negative organisms.", "B": "Ceftriaxone alone because it covers Neisseria meningitidis and resistant S. pneumoniae.", "C": "Penicillin G alone because gram-negative diplococci confirm meningococcal meningitis.", "D": "Ceftriaxone, vancomycin, ampicillin, and dexamethasone for this age group and presentation."}, "correct": "D", "explanation": "Empiric therapy for bacterial meningitis must be initiated immediately without waiting for culture results and should cover the most common pathogens: S. pneumoniae (ceftriaxone and vancomycin for resistant strains), N. meningitidis (ceftriaxone), and Listeria monocytogenes (ampicillin), which is included in full empiric regimens until the organism is confirmed on culture."}, {"id": 825, "domain": "specialty_systems", "question": "A 45-year-old woman with rheumatoid arthritis on methotrexate 20 mg weekly and folic acid presents with a new dry cough and dyspnea over 4 weeks. High-resolution CT shows bilateral ground-glass opacities and reticular infiltrates. Her RA disease activity is low. Which diagnosis must be prioritized?", "options": {"A": "Methotrexate-induced pneumonitis requiring immediate drug cessation and corticosteroids.", "B": "RA-associated interstitial lung disease from chronic systemic inflammation in seropositive RA.", "C": "Community-acquired pneumonia requiring antibiotic therapy given the bilateral infiltrates.", "D": "Opportunistic infection such as PCP from methotrexate-induced immunosuppression."}, "correct": "A", "explanation": "Methotrexate pneumonitis is an idiosyncratic, dose-independent hypersensitivity reaction that can occur at any point during treatment, presenting with subacute onset dyspnea, dry cough, and bilateral ground-glass opacities on high-resolution CT. Immediate discontinuation of methotrexate is the most critical first step, and systemic corticosteroids are typically added to reduce ongoing inflammation and promote recovery. RA-associated ILD and opportunistic infections are important differentials, but methotrexate pneumonitis must be excluded first and the drug stopped pending further evaluation because continuing it risks life-threatening respiratory failure."}, {"id": 828, "domain": "women_s_health", "question": "A 32-year-old woman with migraine with aura, hypertension (BP 138/88 mmHg on amlodipine), and type 2 diabetes presents for contraception. She smokes 8 cigarettes per day. She wants highly effective reversible contraception. Which method is safest given her comorbidities?", "options": {"A": "Combined oral contraceptive pill because low-dose formulations are safe in all diabetics.", "B": "Levonorgestrel intrauterine device providing effective non-hormonal option with progestin only.", "C": "Progestin-only pill because it avoids the estrogen-related stroke risk in migraine with aura.", "D": "Depot medroxyprogesterone acetate as a reliable injection with no estrogen component."}, "correct": "B", "explanation": "Combined hormonal contraceptives containing estrogen are contraindicated in women with migraine with aura due to increased stroke risk, and this patient has additional estrogen-related contraindications including hypertension and active smoking. The levonorgestrel intrauterine device delivers progestin locally with minimal systemic absorption, making it safe in women with migraine with aura, hypertension, and diabetes, while providing highly effective long-acting reversible contraception. DMPA (depot medroxyprogesterone acetate) is another option but may worsen cardiometabolic risk factors in a patient already with hypertension and diabetes, making the LNG-IUD the preferred choice."}, {"id": 829, "domain": "women_s_health", "question": "A 24-year-old woman at 7 weeks gestation presents with vaginal bleeding and mild right lower quadrant pain. Serum beta-hCG is 1,800 mIU/mL. Transvaginal ultrasound shows an empty uterus and no adnexal mass. Which next step is most appropriate?", "options": {"A": "Diagnose ectopic pregnancy and administer methotrexate based on the empty uterus finding.", "B": "Perform emergent dilation and curettage for presumed incomplete miscarriage.", "C": "Repeat beta-hCG in 48 hours; if it does not rise 53%, evaluate further for ectopic pregnancy.", "D": "Diagnose threatened miscarriage and provide reassurance with close outpatient follow-up."}, "correct": "C", "explanation": "At a beta-hCG of 1,800 mIU/mL, the discriminatory zone for visualization of an intrauterine pregnancy on transvaginal ultrasound is borderline, and the empty uterus could represent a very early viable intrauterine pregnancy, a failed intrauterine pregnancy, or an ectopic pregnancy. Serial beta-hCG measurement in 48 hours allows assessment of the rise pattern: a 53% rise over 48 hours suggests a viable IUP, while a plateau or decline suggests failed pregnancy, and levels that fail to rise appropriately with continued empty uterus mandate further evaluation for ectopic pregnancy. Administering methotrexate or performing D&C without confirming ectopic location is dangerous because the pregnancy has not yet been definitively localized."}, {"id": 830, "domain": "women_s_health", "question": "A 28-year-old woman with PCOS presents requesting contraception. She has irregular periods, hirsutism, and acne. She is not currently trying to conceive. BMI is 34. She has no cardiovascular risk factors and does not smoke. Which contraceptive choice addresses both her family planning and PCOS-related symptoms?", "options": {"A": "Combined oral contraceptive pill to regulate periods, reduce androgens, and prevent pregnancy.", "B": "Progestin-only implant because it avoids estrogen and provides 3 years of contraception.", "C": "Copper IUD as the most effective non-hormonal reversible contraceptive available.", "D": "Levonorgestrel IUD because it reduces menstrual bleeding in PCOS patients with heavy periods."}, "correct": "A", "explanation": "Combined oral contraceptive pills treat the hormonal imbalances of PCOS by suppressing LH and reducing androgen production from the ovaries, which addresses both hirsutism and acne while simultaneously regulating menstrual cycles and providing contraception. Progestin-only methods such as the implant or LNG-IUD do not adequately reduce androgen levels and do not reliably regularize cycles in PCOS patients with anovulation. The copper IUD provides contraception but has no hormonal benefit on PCOS-related androgen excess, and in a woman without current cardiovascular risk factors who does not smoke, combined OCP is safe and addresses all of her treatment goals."}, {"id": 834, "domain": "women_s_health", "question": "A 25-year-old woman has a Pap test showing ASCUS. High-risk HPV cotesting is positive. She has never had an abnormal Pap test. Which management is most appropriate per current guidelines?", "options": {"A": "Colposcopy now because ASCUS with positive high-risk HPV warrants immediate evaluation.", "B": "Repeat Pap with cotesting in 1 year because ASCUS resolves spontaneously in most women.", "C": "Colposcopy now because her age group has a higher risk of CIN 2 or 3 with this result.", "D": "Loop electrosurgical excision procedure because treating ASCUS prevents cancer progression."}, "correct": "A", "explanation": "Per ASCCP 2019 guidelines, ASCUS with concurrent positive high-risk HPV in women 25 and older warrants colposcopy at the time of diagnosis rather than repeat testing in one year, because the combination identifies a clinically significant risk of CIN 2 or 3 that requires histologic evaluation. Colposcopy allows direct visualization and targeted biopsy of abnormal cervical transformation zones to either confirm or rule out high-grade dysplasia. Repeating Pap with cotesting in one year is appropriate for HPV-negative ASCUS, and LEEP would be inappropriate without histologic confirmation of a lesion requiring excision."}, {"id": 835, "domain": "women_s_health", "question": "A 62-year-old postmenopausal woman has a Pap test showing ASCUS with positive high-risk HPV. She has had routine negative Pap tests annually for 20 years. Which management differs from a 25-year-old with the same result and why?", "options": {"A": "Management is identical because HPV-positive ASCUS always requires colposcopy regardless of age.", "B": "Repeat Pap in 3 years because postmenopausal women with ASCUS have a benign prognosis.", "C": "Colposcopy is recommended because older women rarely clear HPV and have higher cancer risk.", "D": "Return to routine 5-year co-testing because postmenopausal ASCUS is always estrogen-related."}, "correct": "C", "explanation": "In postmenopausal women, HPV clearance rates decline significantly compared to younger women, and persistent high-risk HPV in the setting of ASCUS cytology carries a higher absolute risk of CIN 2 or 3 in this age group. Per ASCCP guidelines, ASCUS with positive high-risk HPV in any woman 25 or older warrants colposcopy, and postmenopausal status does not lower the threshold because of the lower HPV clearance rates in older women. The assumption that ASCUS in postmenopausal women is related to estrogen deficiency does not apply when HPV cotesting is positive, as the risk of significant dysplasia remains clinically meaningful."}, {"id": 839, "domain": "women_s_health", "question": "A 44-year-old woman with hysterectomy (uterus removed, ovaries intact) at age 38 now reports hot flashes, mood changes, and sleep disruption. FSH is 68 mIU/mL. She has no VTE history and no cardiovascular risk factors. She asks about hormone replacement. Which HRT approach is most appropriate?", "options": {"A": "Estrogen-only therapy because she has no uterus and progestin is not required.", "B": "Estrogen plus progesterone because she needs both hormones even without a uterus.", "C": "Progesterone-only therapy to manage vasomotor symptoms without estrogen exposure.", "D": "No HRT because she still has ovaries and cannot be in true menopause at age 44."}, "correct": "A", "explanation": "A woman who has had a hysterectomy does not require concurrent progestogen therapy because there is no endometrium to protect from estrogen-stimulated hyperplasia, which is the sole indication for adding progestogen to estrogen in postmenopausal women. Estrogen-only HRT is associated with fewer risks than combined estrogen-progestogen therapy and is the appropriate and effective treatment for vasomotor symptoms and menopausal quality of life in women without a uterus. Intact ovaries do not preclude menopausal symptoms when FSH is elevated to 68 mIU/mL, as this level confirms ovarian insufficiency and menopause at age 44."}, {"id": 841, "domain": "women_s_health", "question": "A 22-year-old woman at 28 weeks gestation presents with severe itching predominantly on her palms and soles that is worse at night. She has no rash. Liver enzymes are mildly elevated. Total serum bile acids are 24 micromol/L. Which diagnosis requires close fetal monitoring?", "options": {"A": "Atopic eruption of pregnancy causing pruritus without bile acid elevation.", "B": "Intrahepatic cholestasis of pregnancy associated with increased risk of stillbirth.", "C": "PUPPP rash presenting in the third trimester with intense pruritus in a primigravida.", "D": "Pemphigoid gestationis from autoimmune blistering causing pruritus without rash initially."}, "correct": "B", "explanation": "Intrahepatic cholestasis of pregnancy is diagnosed by pruritus predominantly on the palms and soles without rash, elevated serum bile acids (greater than 10 micromol/L, with levels above 40 indicating severe disease), and mild transaminase elevation, typically in the second or third trimester. ICP is associated with significantly increased risk of stillbirth, preterm labor, and fetal cardiac arrhythmia, and management includes ursodeoxycholic acid to reduce bile acid levels and close fetal monitoring with consideration of early delivery for severe cases. PUPPP rash presents with a characteristic eruption in abdominal striae, not isolated pruritus on palms and soles without visible lesions."}, {"id": 843, "domain": "women_s_health", "question": "A 36-year-old woman with high-grade squamous intraepithelial lesion (HSIL) on Pap test is referred for colposcopy. She declines the procedure after reviewing the information and says she wants to wait and repeat the Pap test next year. She understands the risk. Which is the most appropriate clinical and ethical response?", "options": {"A": "Respect her decision, provide thorough counseling, and document her informed refusal.", "B": "Perform the colposcopy without her consent because HSIL poses an imminent cancer risk.", "C": "Reschedule her colposcopy in 3 months without discussing the refusal with her further.", "D": "Contact her next of kin to help persuade her because the decision is clinically unreasonable."}, "correct": "A", "explanation": "Patient autonomy is a fundamental principle of medical ethics that gives competent adults the right to refuse recommended medical interventions after receiving complete information about the risks of not proceeding. The clinician's responsibility is to make sure the patient fully understands the risk of untreated HSIL (a 20 to 30% risk of progression to cervical carcinoma in situ or invasive cancer over 10 years) and to document this informed refusal clearly in the medical record. Performing a procedure without consent is battery, and contacting family members to override a competent patient's decision violates both autonomy and confidentiality."}, {"id": 849, "domain": "women_s_health", "question": "A 45-year-old woman with migraine with aura is requesting emergency contraception after unprotected sex 36 hours ago. She currently takes topiramate for migraine prevention. Which emergency contraceptive is most effective and appropriate for her?", "options": {"A": "Combined levonorgestrel-ethinyl estradiol pill because it is the most commonly prescribed option.", "B": "Levonorgestrel pill but note that topiramate may reduce its efficacy through enzyme induction.", "C": "Copper IUD insertion as the most effective emergency contraceptive regardless of comorbidities.", "D": "Ulipristal acetate because migraine with aura is a contraindication to levonorgestrel."}, "correct": "C", "explanation": "The copper IUD is the most effective form of emergency contraception (greater than 99% effective) when inserted within 5 days of unprotected intercourse, and its efficacy is not affected by body weight, enzyme-inducing medications, or comorbidities such as migraine with aura. Topiramate is a CYP3A4 enzyme inducer that reduces the serum concentrations of both levonorgestrel and ulipristal acetate, making hormonal emergency contraceptive pills less reliable in women taking this medication. The copper IUD also provides ongoing highly effective long-term contraception for up to 10 years if the patient chooses to keep it, making it the optimal choice for this patient at 36 hours post-exposure."}, {"id": 851, "domain": "women_s_health", "question": "A 31-year-old woman presents with primary infertility for 18 months. She has regular 28-day cycles, a midluteal progesterone of 12 ng/mL, and a normal hysterosalpingogram. Her partner's semen analysis is normal. Which diagnosis is most likely and what is the appropriate next step?", "options": {"A": "Unexplained infertility; refer to reproductive endocrinology for IUI or IVF workup.", "B": "Ovulatory dysfunction despite regular cycles; start clomiphene and monitor with ultrasound.", "C": "Endometriosis-related infertility; perform diagnostic laparoscopy to confirm and treat.", "D": "Tubal factor infertility; repeat hysterosalpingogram because first test may have false negatives."}, "correct": "A", "explanation": "After 18 months of unprotected intercourse without pregnancy, with documented ovulation (midluteal progesterone 12 ng/mL), normal fallopian tube patency on hysterosalpingogram, and normal semen analysis, the diagnosis is unexplained infertility, which accounts for approximately 15 to 30% of infertility cases. Referral to reproductive endocrinology is appropriate for discussion of superovulation with intrauterine insemination (IUI) as a first-line empiric treatment, with IVF reserved for cases where IUI fails or in older patients with time-sensitive fertility concerns. Empiric clomiphene and diagnostic laparoscopy are not the first recommended steps when the evaluation is complete and entirely normal."}, {"id": 859, "domain": "women_s_health", "question": "A 42-year-old woman presents with 6 months of pelvic pain, dysmenorrhea, dyspareunia, and heavy menstrual bleeding. Transvaginal ultrasound shows a 9 cm right ovarian cyst with ground-glass echogenicity. CA-125 is 68 U/mL. She has not completed childbearing. Which diagnosis and management is most appropriate?", "options": {"A": "Ovarian cancer; refer to gynecologic oncology for staging and surgical management.", "B": "Endometrioma; refer to gynecology for laparoscopic cystectomy preserving ovarian tissue.", "C": "Functional ovarian cyst; repeat ultrasound in 8 weeks to assess for spontaneous resolution.", "D": "Corpus luteum cyst; no treatment needed because CA-125 elevation is nonspecific in premenopausal women."}, "correct": "B", "explanation": "An ovarian cyst with homogeneous ground-glass echogenicity (the ultrasound appearance of old blood) in a premenopausal woman with dysmenorrhea, dyspareunia, and chronic pelvic pain is highly characteristic of an endometrioma. CA-125 is mildly elevated in endometriosis and is non-specific in premenopausal women with pelvic inflammation, making it insufficient to diagnose ovarian cancer without other imaging features of malignancy such as solid components, ascites, or bilateral disease. Laparoscopic ovarian cystectomy with preservation of ovarian cortex is the preferred surgical approach in a woman who has not completed childbearing because it treats symptoms and confirms the diagnosis histologically while minimizing ovarian reserve loss."}, {"id": 864, "domain": "women_s_health", "question": "A 30-year-old woman with chronic hypertension managed with nifedipine throughout pregnancy delivers at 38 weeks. Newborn exam reveals normal limbs and no dysmorphic features. Which antihypertensive medication commonly used in pregnancy carries the highest teratogenic risk in early pregnancy?", "options": {"A": "Labetalol causing fetal bradycardia and growth restriction when used throughout pregnancy.", "B": "Methyldopa causing fetal hemolytic anemia from antibody production in late pregnancy.", "C": "Nifedipine causing premature closure of the ductus arteriosus in the third trimester.", "D": "ACE inhibitors causing fetal renal dysgenesis, oligohydramnios, and limb contractures."}, "correct": "D", "explanation": "ACE inhibitors and ARBs are strongly contraindicated after the first trimester of pregnancy because they inhibit fetal renin-angiotensin-aldosterone system development, leading to fetal renal tubular dysgenesis, oligohydramnios, anhydramnios, fetal growth restriction, skull ossification defects, and limb contractures from oligohydramnios sequence. First-trimester ACE inhibitor exposure has also been associated with increased risk of cardiovascular and CNS malformations, making avoidance throughout pregnancy the recommended practice. Labetalol, methyldopa, and nifedipine are the antihypertensives of choice in pregnancy with well-established safety profiles, and nifedipine does not cause premature closure of the ductus arteriosus, which is a risk specific to NSAIDs and COX inhibitors."}, {"id": 866, "domain": "women_s_health", "question": "A 66-year-old postmenopausal woman presents with vulvar itching and a 1 cm raised white plaque on the right labia majora. Biopsy confirms lichen sclerosus without atypia. She is concerned about cancer risk. Which management provides both symptom relief and cancer risk reduction?", "options": {"A": "Topical estrogen cream applied to the vulva to restore normal vulvar architecture.", "B": "Oral hydroxychloroquine for its anti-inflammatory effects in lichen sclerosus management.", "C": "Referral for vulvectomy because lichen sclerosus always progresses to vulvar cancer.", "D": "Ultra-potent topical corticosteroid such as clobetasol as the primary treatment for LS."}, "correct": "D", "explanation": "Lichen sclerosus is treated with ultra-potent topical corticosteroids such as clobetasol propionate 0.05% applied to the affected vulvar tissue, which reduces inflammation, improves symptoms, and has been shown in long-term observational studies to reduce the risk of progression to vulvar squamous cell carcinoma compared to inadequately treated LS. Topical estrogen does not effectively treat lichen sclerosus because LS is not an estrogen-dependent condition, though it may be used as an adjunct for associated vaginal atrophy. Vulvectomy is not appropriate management for LS without evidence of malignant transformation, and the lifetime risk of invasive vulvar cancer in LS is approximately 3 to 5%, which is further reduced with consistent treatment."}, {"id": 867, "domain": "women_s_health", "question": "A 23-year-old woman presents with vaginal discharge described as cottage cheese-like, severe vulvar itching, and redness. KOH preparation shows pseudohyphae. She has been on amoxicillin for 5 days for a dental abscess. She is not pregnant and has no other conditions. Which treatment is most appropriate?", "options": {"A": "Oral fluconazole 150 mg single dose as effective first-line treatment for VVC.", "B": "Topical clotrimazole cream because oral fluconazole is not first-line for initial VVC.", "C": "Complete the antibiotics first then treat the candidiasis after the course finishes.", "D": "Topical boric acid because antibiotic-associated candidiasis is often resistant to azoles."}, "correct": "A", "explanation": "Antibiotic-associated vulvovaginal candidiasis is a common complication of broad-spectrum antibiotic therapy, which disrupts the vaginal lactobacillus flora and allows Candida albicans overgrowth, and the finding of pseudohyphae on KOH preparation confirms candidal infection. Oral fluconazole 150 mg as a single dose is an effective, convenient, and evidence-based first-line treatment for uncomplicated VVC with cure rates exceeding 90% for azole-susceptible C. albicans."}, {"id": 869, "domain": "mental_health", "question": "A 42-year-old man with PTSD from combat trauma presents with nightmares, hypervigilance, avoidance, and a 6-month history of increasing alcohol use. He drinks 6 to 8 beers nightly to sleep. AUDIT score is 22. Which sequence of treatment is most appropriate?", "options": {"A": "Treat PTSD first with prolonged exposure therapy before addressing the alcohol use.", "B": "Address the alcohol use disorder first because it interferes with PTSD treatment efficacy.", "C": "Provide integrated treatment addressing both PTSD and AUD simultaneously.", "D": "Start prazosin for nightmares and then refer to substance use treatment when stabilized."}, "correct": "C", "explanation": "Research demonstrates that PTSD and alcohol use disorder are neurobiologically intertwined and mutually reinforcing conditions in which untreated AUD impairs PTSD treatment engagement and untreated PTSD drives continued alcohol use as avoidance behavior. Integrated treatments such as Seeking Safety and concurrent exposure-based therapy with AUD pharmacotherapy have been shown to be more effective than sequential treatment of either condition alone in veterans with comorbid PTSD and AUD. Prazosin effectively reduces PTSD-related nightmares but does not address the alcohol use disorder, and any approach that treats only one condition while ignoring the other is likely to produce incomplete and unsustained response."}, {"id": 872, "domain": "mental_health", "question": "A 45-year-old man presents with marked weight loss, early morning awakening, anhedonia, and passive suicidal ideation. He denies a plan or intent. PHQ-9 score is 24. He has a strong family history of cardiovascular disease and is worried about cardiac safety of antidepressants. Which antidepressant choice best balances efficacy and cardiac safety?", "options": {"A": "Amitriptyline because tricyclics are most effective for severe depression with neurovegetative features.", "B": "Sertraline because it has the best cardiovascular safety profile among antidepressants.", "C": "Bupropion because it has no cardiac effects and also suppresses appetite to address weight loss.", "D": "Paroxetine because it is the most sedating SSRI and will improve his early morning awakening."}, "correct": "B", "explanation": "Sertraline has the most extensively studied and favorable cardiovascular safety profile among antidepressants, demonstrated in the SADHART trial for patients with acute coronary syndrome and major depression, and it does not prolong the QTc interval at therapeutic doses. Amitriptyline and other tricyclic antidepressants carry significant cardiac risks including QTc prolongation, torsades de pointes, and conduction abnormalities, and are associated with excess mortality in patients with cardiovascular disease, making them inappropriate in this patient with a strong cardiac family history. Bupropion can increase heart rate and blood pressure, and paroxetine has anticholinergic properties and the highest discontinuation syndrome risk among SSRIs."}, {"id": 875, "domain": "mental_health", "question": "A 30-year-old man is brought in by his partner after 3 days of no sleep, excessive spending, sexual indiscretion, and grandiose claims that he has invented a new fuel source. He has a prior diagnosis of major depressive disorder and was started on fluoxetine 4 weeks ago. Mental status shows pressured speech and flight of ideas. Which diagnosis must be considered?", "options": {"A": "Major depressive disorder with atypical features presenting with mood elevation.", "B": "Antidepressant-induced manic switch in a patient with undiagnosed bipolar disorder.", "C": "Schizoaffective disorder presenting with grandiosity and disorganized thinking.", "D": "Stimulant or substance intoxication mimicking a manic episode in this patient."}, "correct": "B", "explanation": "Antidepressant medications, particularly SSRIs and SNRIs, can precipitate manic or hypomanic episodes (manic switch) in patients with undiagnosed bipolar disorder who present initially with depressive symptoms, and fluoxetine initiation 4 weeks prior provides a clear temporal association. The presentation of decreased sleep need, grandiosity, excessive spending, hypersexuality, and pressured speech with flight of ideas constitutes a full manic episode meeting DSM-5 criteria for bipolar I disorder, with the prior diagnosis of MDD likely representing an unrecognized depressive phase. The antidepressant should be discontinued and a mood stabilizer or atypical antipsychotic should be initiated as the cornerstone of bipolar I treatment."}, {"id": 878, "domain": "mental_health", "question": "A 38-year-old man with opioid use disorder on buprenorphine 8 mg daily presents for induction day 2. He has 12 mg of sublingual buprenorphine remaining and reports he is still in mild withdrawal (COWS score 8). He last used fentanyl 36 hours ago. He denies precipitated withdrawal. Which action is most appropriate?", "options": {"A": "Administer an additional 4 mg buprenorphine today and continue dosing adjustment as needed.", "B": "Hold all buprenorphine until his COWS score reaches 12 or greater before next dose.", "C": "Switch to methadone because his withdrawal symptoms indicate buprenorphine is inadequate.", "D": "Add clonidine and loperamide for comfort and continue buprenorphine at the same dose."}, "correct": "A", "explanation": "On buprenorphine induction day 2 with a COWS score of 8 (mild withdrawal), the appropriate management is to supplement with additional buprenorphine doses (4 mg increments) until withdrawal symptoms resolve, as COWS scores of 5 to 12 indicate mild withdrawal that benefits from further dose titration rather than discontinuation or switching agents. Standard buprenorphine induction protocols allow flexible dosing adjustments in the first several days to achieve an adequate dose that eliminates withdrawal symptoms, typically targeting a total daily dose of 16 to 24 mg. Holding all buprenorphine until COWS reaches 12 is appropriate only for giving the very first dose to avoid precipitated withdrawal; once induction has begun, continued dose titration is the goal."}, {"id": 882, "domain": "mental_health", "question": "A 29-year-old woman with borderline personality disorder presents to the ED after cutting her forearms superficially. She denies suicidal intent and states the cutting relieves her emotional distress. She refuses hospitalization. She has outpatient DBT appointments scheduled for next week. Which action is most appropriate?", "options": {"A": "Hospitalize involuntarily because any self-harm is an imminent psychiatric emergency.", "B": "Withhold outpatient referral until she agrees to contract for safety in writing.", "C": "Discharge with safety plan, wound care, and confirmation of her outpatient DBT appointment.", "D": "Admit voluntarily and start an antipsychotic to prevent further self-harm behavior."}, "correct": "C", "explanation": "Non-suicidal self-injury in the context of borderline personality disorder serves as an emotion regulation strategy rather than a suicidal behavior, and this patient explicitly denies suicidal intent, has a clear affective trigger (emotional distress), and has established outpatient DBT treatment already in place. Involuntary hospitalization for NSSI without suicidal intent is not ethically justified and can be countertherapeutic for patients with BPD, as repeated hospitalizations can reinforce self-harm behavior as a means of obtaining care. Providing wound care, constructing a collaborative safety plan, and confirming the existing DBT appointment addresses the immediate medical need and supports continuity of the only evidence-based treatment for BPD."}, {"id": 889, "domain": "mental_health", "question": "A 72-year-old man with Parkinson disease on carbidopa-levodopa develops vivid auditory and visual hallucinations. His family is distressed and requests medication. Cognitive function is intact. His motor control is adequate. Which antipsychotic is safest for treating psychosis in a patient with Parkinson disease?", "options": {"A": "Pimavanserin because it reduces psychosis without dopaminergic motor effects.", "B": "Olanzapine because it has a low EPS profile compared to typical antipsychotics.", "C": "Risperidone because it is better tolerated than haloperidol in the elderly population.", "D": "Quetiapine because it has a lower EPS risk than other second-generation antipsychotics."}, "correct": "A", "explanation": "Pimavanserin is a selective serotonin 5-HT2A inverse agonist/antagonist that is FDA-approved specifically for Parkinson disease psychosis, and because it has no dopaminergic activity, it reduces psychotic symptoms without worsening the motor symptoms of Parkinson disease. All other available antipsychotics (including quetiapine, which has a relatively lower EPS profile) carry some degree of dopamine receptor blockade that can exacerbate parkinsonism, with risperidone and olanzapine being particularly problematic in PD patients due to high D2 affinity. Pimavanserin represents a mechanistically distinct and safer option for Parkinson disease psychosis that should be preferred over conventional or atypical antipsychotics in this clinical context."}, {"id": 895, "domain": "mental_health", "question": "A 68-year-old man with dementia (MMSE 16/30) in a nursing home is observed striking staff and other residents when agitated. Behavioral interventions have been tried for 4 weeks without success. His family requests medication. Which pharmacologic approach is most evidence-based and carries the least mortality risk?", "options": {"A": "Start haloperidol 1 mg twice daily because typical antipsychotics are safer in dementia than atypicals.", "B": "Start risperidone 0.5 mg daily because it has the most evidence for agitation in dementia.", "C": "Start quetiapine 25 mg at bedtime because it is the safest antipsychotic for elderly dementia patients.", "D": "Start citalopram 10 mg daily because SSRIs are preferred over antipsychotics for dementia agitation."}, "correct": "D", "explanation": "Citalopram has been studied in randomized trials for agitation in dementia and does not carry the FDA black box warning for increased mortality that applies to all antipsychotics, making it the option with the best balance of evidence and safety. Antipsychotics including risperidone, quetiapine, and haloperidol all carry a class-wide black box warning for increased mortality in elderly patients with dementia-related psychosis. When behavioral interventions have been tried and medication is needed, guidelines now prefer SSRIs over antipsychotics as the first-line pharmacologic approach."}, {"id": 899, "domain": "mental_health", "question": "A 26-year-old man presents for opioid use disorder treatment. He is currently taking heroin several times daily and is in moderate withdrawal (COWS 14). He wants to start buprenorphine today. He took heroin 8 hours ago. Which action is most appropriate for initiating buprenorphine?", "options": {"A": "Wait 24 additional hours to ensure he is in adequate withdrawal before starting buprenorphine.", "B": "Start buprenorphine 2 to 4 mg now given his moderate COWS score and monitor for precipitated withdrawal.", "C": "Administer naloxone first to accelerate withdrawal before starting buprenorphine.", "D": "Start methadone 40 mg today because buprenorphine has too high a risk of precipitated withdrawal."}, "correct": "B", "explanation": "A COWS score of 14 indicates moderate opioid withdrawal, which meets the threshold for initiating buprenorphine induction, and starting at 2 to 4 mg with close monitoring is the standard approach. Waiting an additional 24 hours is unnecessary and prolongs suffering when the patient is already in adequate withdrawal for safe induction. Administering naloxone to accelerate withdrawal is not a standard protocol and could precipitate severe precipitated withdrawal, and methadone requires enrollment in a specialized opioid treatment program and cannot be started in a typical office setting."}, {"id": 902, "domain": "mental_health", "question": "A 70-year-old man presents for evaluation of memory concerns. His wife reports he misplaces things, forgets appointments, and repeats himself. MMSE is 24/30 with errors on recall and delayed memory. He has hypertension, diabetes, and a history of two TIAs. MRI shows periventricular white matter changes. Which type of dementia is most consistent with his history and imaging?", "options": {"A": "Alzheimer disease presenting with early memory impairment and normal brain imaging.", "B": "Vascular dementia from cumulative ischemic injury related to his TIA history and risk factors.", "C": "Lewy body dementia presenting with early visuospatial deficits and REM sleep disorder.", "D": "Frontotemporal dementia presenting with memory loss as the predominant early symptom."}, "correct": "B", "explanation": "Vascular dementia is the most consistent diagnosis given this patient's history of two TIAs, vascular risk factors including hypertension and diabetes, and MRI showing periventricular white matter changes, which reflect cumulative ischemic injury. Alzheimer disease typically presents with early memory impairment but is not associated with TIA history and white matter lesions on imaging. Lewy body dementia features early visuospatial deficits and REM sleep behavior disorder, and frontotemporal dementia presents primarily with behavioral changes or language difficulties rather than memory loss."}, {"id": 904, "domain": "mental_health", "question": "A 32-year-old woman presents with recurrent depressive episodes that are exclusively in the winter, with full remission in spring. She has hypersomnia, carbohydrate cravings, and fatigue from October through March each year. She has had 4 such episodes. Which is the most appropriate first-line treatment?", "options": {"A": "Start an antidepressant in September each year and taper in April for seasonal pattern MDD.", "B": "Start melatonin at bedtime because seasonal depression is caused by circadian rhythm disruption.", "C": "Refer for cognitive behavioral therapy adapted for seasonal affective disorder.", "D": "Light therapy with 10,000 lux lamp for 30 minutes each morning as first-line treatment."}, "correct": "D", "explanation": "Bright light therapy using a 10,000-lux lamp for 20 to 30 minutes each morning is the established first-line treatment for seasonal affective disorder, with response rates comparable to antidepressants and a rapid onset of action within 1 to 2 weeks. Melatonin addresses circadian rhythm timing but has limited evidence as a primary treatment for seasonal depression. Prophylactic antidepressants started in the fall are an alternative for patients who cannot tolerate or do not respond to light therapy, but light therapy is preferred as the initial intervention."}, {"id": 905, "domain": "mental_health", "question": "A 55-year-old man with major depressive disorder on sertraline 100 mg daily for 6 months presents with residual fatigue and poor concentration despite improved mood. He reports these symptoms interfere with his work. PHQ-9 is 8 (was 22 at presentation). Which next step is most appropriate?", "options": {"A": "Add bupropion because it targets norepinephrine and dopamine pathways addressing energy and focus.", "B": "Increase sertraline to 200 mg to achieve full symptom remission.", "C": "Switch to venlafaxine because the residual symptoms suggest SSRI treatment failure.", "D": "Augment with atypical antipsychotic because residual symptoms indicate treatment resistance."}, "correct": "A", "explanation": "Adding bupropion to sertraline is a well-supported augmentation strategy for residual fatigue and poor concentration because bupropion acts on norepinephrine and dopamine pathways that are not targeted by SSRIs, specifically addressing energy and cognitive symptoms. Increasing sertraline to 200 mg is above the standard maximum dose and unlikely to improve residual symptoms when the mood has already responded at 100 mg. Switching to venlafaxine or augmenting with an atypical antipsychotic is appropriate for patients who do not respond to primary SSRI therapy, which is not the case here given the PHQ-9 improvement from 22 to 8."}, {"id": 906, "domain": "mental_health", "question": "A 44-year-old veteran with PTSD presents with insomnia, nightmares occurring nightly, and significant distress. He has tried sertraline without adequate benefit. He is resistant to formal trauma therapy. Which pharmacologic option specifically targets trauma nightmares with the best evidence?", "options": {"A": "Add prazosin because it reduces noradrenergic activity associated with PTSD nightmares.", "B": "Add quetiapine at bedtime because it reduces sleep disturbance and nightmares in PTSD.", "C": "Add trazodone because it improves sleep architecture and reduces nightmare frequency.", "D": "Start clonazepam for nightmares because benzodiazepines effectively suppress REM sleep."}, "correct": "A", "explanation": "Prazosin, an alpha-1 adrenergic antagonist, reduces noradrenergic hyperactivation during sleep and has the strongest evidence base for specifically reducing trauma-related nightmares in PTSD, particularly in veterans. Trazodone improves sleep architecture and continuity but has less specific evidence for nightmare reduction compared to prazosin. Benzodiazepines suppress REM sleep acutely but are not recommended for PTSD nightmares due to dependence risk, rebound effects, and lack of long-term efficacy for this symptom."}, {"id": 907, "domain": "mental_health", "question": "A 28-year-old woman with anorexia nervosa, restrictive type presents after 3 months of inpatient treatment. Her BMI has risen from 14.1 to 16.8. She will be discharged next week. Her team plans outpatient follow-up every 2 weeks. Which lab abnormality is most important to monitor during the refeeding process?", "options": {"A": "Serum phosphate because hypophosphatemia is the hallmark complication of refeeding syndrome.", "B": "Serum magnesium because hypomagnesemia precipitates cardiac arrhythmias during refeeding.", "C": "Serum potassium because hypokalemia is more common than phosphate abnormalities in AN.", "D": "Blood glucose because hypoglycemia is the leading cause of mortality during AN refeeding."}, "correct": "A", "explanation": "Hypophosphatemia is the hallmark electrolyte disturbance of refeeding syndrome and occurs because insulin secretion triggered by carbohydrate intake drives phosphate into cells, depleting an already low total body phosphate in malnourished patients. Serum phosphate must be closely monitored during the refeeding process and supplemented proactively to prevent life-threatening complications including respiratory failure, hemolytic anemia, and cardiac arrhythmias. While hypokalemia and hypomagnesemia also occur during refeeding, phosphate monitoring is the defining and most critical concern in this syndrome."}, {"id": 908, "domain": "pediatric_care", "question": "A 16-day-old male infant presents with a temperature of 38.2 degrees C, poor feeding, and irritability. He was born at 39 weeks via uncomplicated vaginal delivery. His CBC shows WBC of 18,400/mcL. Urinalysis is unremarkable. He appears ill and lethargic on exam. Which management approach is most appropriate for this age group?", "options": {"A": "Urine culture only and watchful waiting because febrile infants often have viral illness.", "B": "Full sepsis workup including blood culture, urine culture, and LP, then empiric IV antibiotics.", "C": "Oral amoxicillin empirically because this age does not require IV antibiotic therapy.", "D": "Discharge with next-day follow-up because temperature of 38.2 is a low-risk fever in neonates."}, "correct": "B", "explanation": "A 16-day-old infant with fever is considered a neonate and requires a full sepsis evaluation including blood culture, urine culture, and lumbar puncture, followed by empiric IV antibiotics covering group B streptococcus, gram-negative organisms, and Listeria until cultures result. Neonates lack the immunological maturity to localize infection, and fever in this age group carries significant risk of bacterial meningitis that cannot be excluded without cerebrospinal fluid analysis. Watchful waiting, oral antibiotics, or discharge without evaluation are not acceptable for this age group given the high morbidity and mortality of untreated neonatal sepsis."}, {"id": 924, "domain": "pediatric_care", "question": "A 6-month-old boy is brought in for a well-child visit. He was born at 32 weeks gestation and spent 4 weeks in the NICU. He has not received any vaccines yet. His mother asks which vaccines he should receive today. Which statement about premature infant vaccination is most accurate?", "options": {"A": "All standard vaccines should be given at the usual chronological age, not corrected age.", "B": "Vaccines should be delayed 3 months beyond chronological age in all preterm infants.", "C": "Only inactivated vaccines are safe for preterm infants under 6 months of age.", "D": "Preterm infants require reduced vaccine doses until they reach normal term equivalent weight."}, "correct": "A", "explanation": "ACIP recommends that preterm infants receive all standard vaccines at their chronological age, not their corrected gestational age, because immunological readiness and disease exposure risk are determined by time since birth rather than gestational maturity. Delaying vaccines in preterm infants leaves them unprotected during the period of highest vulnerability, particularly for diseases such as pertussis and Hib that are most dangerous in young infants. Reduced doses or restriction to inactivated vaccines only are not part of standard ACIP guidance for preterm infants who are otherwise medically stable at the time of vaccination."}, {"id": 929, "domain": "pediatric_care", "question": "A 13-year-old boy is brought in by his mother after a school nurse noted he was purging in the bathroom. He denies it but appears underweight (BMI 15.8) and has bilateral parotid swelling and erosion of the lingual surface of his upper front teeth. His potassium is 2.9 mEq/L. Which condition does this presentation most likely represent?", "options": {"A": "Anorexia nervosa, purging type presenting in a male adolescent with significant restriction.", "B": "Bulimia nervosa with purging causing parotid hypertrophy, dental erosion, and hypokalemia.", "C": "GERD causing dental erosion and parotid swelling from esophageal acid exposure.", "D": "Functional dyspepsia causing involuntary regurgitation and weight loss in an adolescent."}, "correct": "B", "explanation": "Bulimia nervosa is characterized by recurrent binge-purge cycles, parotid gland hypertrophy from repeated vomiting, dental enamel erosion on the lingual surfaces from gastric acid, and hypokalemia from chronic purging, all of which are present in this patient. The normal or elevated BMI distinguishes bulimia nervosa from anorexia nervosa, where low body weight is a defining diagnostic criterion. GERD does not cause parotid swelling or the pattern of dental erosion seen specifically on the lingual surfaces of the upper teeth, which is a distinctive finding from self-induced vomiting."}, {"id": 930, "domain": "pediatric_care", "question": "A 2-year-old boy is brought in with high fever, unilateral cervical swelling, drooling, and muffled voice. He holds his neck in a position of comfort. He is febrile at 39.4 degrees C and drooling. CT neck shows a posterior pharyngeal fluid collection with rim enhancement. Which diagnosis is most likely and what is the immediate concern?", "options": {"A": "Peritonsillar abscess requiring needle aspiration in the clinic setting.", "B": "Bacterial lymphadenitis requiring oral antibiotics and close outpatient follow-up.", "C": "Retropharyngeal abscess with risk of airway compromise requiring urgent ENT evaluation.", "D": "Epiglottitis presenting with drooling and muffled voice requiring immediate intubation."}, "correct": "C", "explanation": "CT neck showing a posterior pharyngeal fluid collection with rim enhancement in a febrile young child with drooling, muffled voice, and neck positioning confirms a retropharyngeal abscess, and the primary concern is impending airway compromise requiring urgent ENT evaluation and likely surgical drainage. Peritonsillar abscess is located in the peritonsillar space and would not produce posterior pharyngeal changes on CT, and epiglottitis typically requires a different imaging approach and clinical presentation. Bacterial lymphadenitis does not produce the posterior pharyngeal CT findings seen here and would not explain the degree of airway risk."}, {"id": 932, "domain": "pediatric_care", "question": "A 10-year-old girl presents with a 4-week history of excessive thirst, frequent urination, fatigue, and abdominal pain. Blood glucose is 620 mg/dL. Arterial pH is 7.18, bicarbonate is 8 mEq/L, and anion gap is 26. She is lethargic and dehydrated. Which electrolyte requires monitoring and replacement despite its serum concentration appearing initially elevated?", "options": {"A": "Sodium because DKA causes dilutional hyponatremia requiring aggressive sodium repletion.", "B": "Magnesium because insulin therapy causes hypomagnesemia through cellular uptake.", "C": "Potassium because total body potassium is depleted despite an initially elevated or normal level.", "D": "Calcium because acidosis falsely elevates ionized calcium masking true hypocalcemia."}, "correct": "C", "explanation": "Total body potassium is depleted in DKA from urinary losses, vomiting, and osmotic diuresis, but serum potassium appears normal or elevated initially because acidosis shifts potassium out of cells and into the plasma. Once insulin therapy is started and the acidosis corrects, potassium rapidly shifts back into cells, and serum potassium can fall dangerously low, causing cardiac arrhythmias if not replaced proactively. Potassium must be added to IV fluids and monitored closely throughout DKA treatment even when the initial level appears normal or high, and the paradox of a high serum level masking total body depletion is the key teaching point."}, {"id": 934, "domain": "pediatric_care", "question": "A 15-year-old boy is brought in by his mother after she found a suicide note in his room. He denies current suicidal ideation and says the note was from 2 months ago during a breakup. He has no plan currently and no access to weapons. PHQ-A score is 16. He smokes cannabis weekly. Which action is most appropriate?", "options": {"A": "Discharge home with the mother and schedule outpatient mental health in 2 weeks.", "B": "Comprehensive suicide risk assessment and safety planning with same-day mental health referral.", "C": "Hospitalize involuntarily because the prior note indicates high ongoing lethality risk.", "D": "Address the cannabis use only because substance use is the main driver of the depression."}, "correct": "B", "explanation": "A discovery of a prior suicide note combined with a current PHQ-A of 16 and ongoing depression requires a comprehensive suicide risk assessment, a collaborative safety plan, and a same-day referral to mental health rather than scheduling a routine outpatient appointment weeks away. While the patient denies current ideation and the note was from 2 months ago, the severity of depression and prior written suicidal communication require thorough risk stratification before concluding he is safe to discharge. Involuntary hospitalization may not be warranted without imminent intent or plan, but routing him home without a mental health evaluation today is insufficient given the risk indicators present."}, {"id": 936, "domain": "pediatric_care", "question": "A 3-day-old male neonate born at 38 weeks is jaundiced. Total serum bilirubin is 22.4 mg/dL. He is breastfed and had good latch initially but has lost 11% of birth weight. Coombs test is negative. Mother's blood type is O-positive and baby is B-positive. Which intervention is most appropriate?", "options": {"A": "Continue breastfeeding support and reassess in 24 hours because jaundice is common in neonates.", "B": "Start phototherapy immediately because the bilirubin level exceeds the treatment threshold.", "C": "Administer IVIG because ABO incompatibility is the likely cause of the elevated bilirubin.", "D": "Exchange transfusion as the first-line intervention for bilirubin of 22.4 mg/dL at 38 weeks."}, "correct": "B", "explanation": "A total serum bilirubin of 22.4 mg/dL in a 38-week gestation neonate at 3 days of life exceeds the phototherapy threshold according to the Bhutani nomogram and requires immediate initiation of phototherapy to prevent progression to acute bilirubin encephalopathy. Continuing breastfeeding support is important but cannot replace phototherapy when the bilirubin is at treatment levels, and the Coombs-negative result with O-positive mother and B-positive baby does not exclude ABO incompatibility, which can occur even with a negative direct Coombs. Exchange transfusion is reserved for bilirubin levels approaching or exceeding the exchange threshold, which is higher than 22.4 mg/dL for a 38-weeker at this age."}, {"id": 939, "domain": "pediatric_care", "question": "A 4-year-old boy with known sickle cell disease (HbSS) presents with fever of 39.1 degrees C. He is on hydroxyurea and penicillin prophylaxis. His spleen is not palpable. WBC is 19,200/mcL with 84% neutrophils. Blood culture is pending. He appears ill but is hemodynamically stable. Which action is most appropriate?", "options": {"A": "Admit and administer IV ceftriaxone empirically because fever in SCD may indicate bacteremia.", "B": "Discharge with oral amoxicillin-clavulanate and outpatient follow-up in 24 hours.", "C": "Observe for 4 hours in the ED because he is hemodynamically stable and vaccinated.", "D": "Obtain chest X-ray and complete metabolic panel but only treat if culture turns positive."}, "correct": "A", "explanation": "Fever in a child with sickle cell disease is a medical emergency requiring hospital admission and empiric IV ceftriaxone because these patients are functionally asplenic and at high risk for rapid overwhelming bacteremia from encapsulated organisms, particularly Streptococcus pneumoniae. Even in patients on prophylactic penicillin and hydroxyurea, fever cannot be managed outpatient because the WBC elevation and ill appearance increase the probability of bacteremia. Blood cultures must be obtained before antibiotics when possible, but treatment should not be delayed pending results, and observation alone without antibiotics is inappropriate when sepsis cannot be excluded."}, {"id": 940, "domain": "pediatric_care", "question": "A 16-year-old girl presents with her mother who is concerned about her eating. She has been admitted for dehydration twice in the past year. She admits to binge eating followed by self-induced vomiting 4 to 5 times per week. Her BMI is 19.2. Which feature distinguishes this presentation from anorexia nervosa purging type?", "options": {"A": "The presence of binge eating because anorexia does not involve episodes of overeating.", "B": "The normal BMI because anorexia nervosa purging type always presents with low body weight.", "C": "The frequency of purging because anorexia purging occurs less than once per week.", "D": "The admission for dehydration because anorexia patients do not present with dehydration."}, "correct": "B", "explanation": "The key clinical distinction between bulimia nervosa and anorexia nervosa purging type is body weight: patients with bulimia nervosa typically have a normal or above-normal BMI, while anorexia nervosa by definition requires significantly low body weight as a diagnostic criterion. Both conditions can involve binge eating and purging behaviors, so the presence of these behaviors alone does not distinguish them. Frequency of purging is not a distinguishing feature between the two diagnoses, as both can involve multiple purging episodes per week."}, {"id": 945, "domain": "professional_practice", "question": "A nurse practitioner is presented with a claim form requesting a higher complexity level (level 5) for an office visit in which the provider documented a 15-minute visit with two chronic stable problems. Which billing principle most applies to this scenario?", "options": {"A": "Level 5 is appropriate because the patient has two chronic conditions requiring ongoing management.", "B": "The visit level should reflect the medical decision-making complexity or time documented accurately.", "C": "Duration alone is insufficient to determine a level 5 visit regardless of number of problems.", "D": "Billing level 5 for two stable chronic problems without complexity documentation constitutes upcoding."}, "correct": "D", "explanation": "Billing a level 5 visit for a 15-minute encounter with two stable chronic conditions that lack documentation of high medical decision-making complexity constitutes upcoding, which is a form of billing fraud that exposes the provider and practice to regulatory penalties and payer audits. Under 2021 AMA E/M guidelines, the visit level must reflect either total time or medical decision-making complexity as documented, and neither 15 minutes of time nor two stable chronic problems without complexity reaches the level 5 threshold. Billing accuracy requires that the coded level correspond precisely to what is documented in the chart, not to the number of diagnoses managed."}, {"id": 947, "domain": "professional_practice", "question": "A nurse practitioner is conducting a quality improvement project using a Plan-Do-Study-Act cycle to reduce missed hypertension diagnoses in a primary care practice. After the first PDSA cycle, the diagnosis rate improved from 62% to 71%. Which action should follow based on the PDSA framework?", "options": {"A": "The improvement is sufficient; implement the change permanently across the practice.", "B": "Run a second PDSA cycle to test the change in a broader context before spreading it.", "C": "Publish the results in a journal before making any permanent changes to the process.", "D": "Conclude the project because a 9% improvement exceeds acceptable quality targets."}, "correct": "B", "explanation": "In the PDSA quality improvement framework, after a first cycle demonstrates improvement, the next step is to run a second PDSA cycle to test the change in a broader context, with a larger sample or different setting, before spreading it across the entire practice. A single successful cycle demonstrates proof of concept but is not sufficient evidence to justify permanent system-wide implementation without further testing for sustainability and generalizability. Publishing results before making any permanent change is not part of the PDSA cycle and would inappropriately delay beneficial improvement for an extended period."}, {"id": 950, "domain": "professional_practice", "question": "A nurse practitioner is reviewing a performance dashboard and notices that her practice's A1c testing rate for diabetic patients is 54%, compared to a benchmark of 82%. She wants to implement a quality improvement intervention. Which approach best identifies the root cause before designing a solution?", "options": {"A": "Send reminder letters to all diabetic patients asking them to schedule their A1c testing.", "B": "Conduct a workflow analysis and use a fishbone diagram to identify why A1c testing is missed.", "C": "Hire a care coordinator to follow up on all diabetic patients between visits.", "D": "Implement a standing order for A1c at every diabetic visit without further analysis."}, "correct": "B", "explanation": "A workflow analysis combined with a fishbone diagram, also called a cause-and-effect or Ishikawa diagram, is the appropriate quality improvement tool for systematically identifying the root causes of a performance gap before designing a solution. Implementing interventions such as reminder letters, standing orders, or additional staffing without first understanding why A1c testing is being missed risks targeting the wrong cause and wasting resources. Root cause analysis must precede solution design in any evidence-based quality improvement approach to ensure that the intervention addresses the actual barrier rather than a superficial symptom."}, {"id": 964, "domain": "professional_practice", "question": "A 60-year-old woman with diabetes, hypertension, and depression is seen for a complex visit addressing all three conditions. The total face-to-face time is 38 minutes including counseling about medication adherence and lifestyle. Which CPT evaluation and management level is most appropriate using 2021 AMA guidelines?", "options": {"A": "Level 3 (99213) because she has three chronic conditions managed at this visit.", "B": "Level 4 (99214) based on moderate-complexity medical decision-making with multiple chronic conditions.", "C": "Level 5 (99215) based on 38 minutes of total face-to-face time under the 2021 time-based guidelines.", "D": "Level 4 (99214) based on time because 38 minutes meets the threshold for a level 4 visit."}, "correct": "D", "explanation": "Under the 2021 AMA E/M guidelines, a level 4 office visit (99214) can be billed based on total time, and 30 to 39 minutes of face-to-face time qualifies for this level, making the 38-minute visit correctly coded as a level 4 visit based on time. A level 5 visit (99215) requires 40 to 54 minutes of total time, which was not met in this encounter, so coding it as level 5 would be inaccurate. The provider may choose to code based on time or medical decision-making complexity, whichever best reflects the visit, and for a 38-minute encounter, time-based coding produces an accurate level 4 designation."}, {"id": 973, "domain": "professional_practice", "question": "A nurse practitioner partner in a group practice wants to open a concierge medicine model charging patients a monthly membership fee in addition to insurance billing. Which ethical and regulatory concern requires evaluation before implementing this model?", "options": {"A": "Billing both a membership fee and insurance for the same service may constitute double billing.", "B": "Concierge medicine is illegal under Medicare fraud and abuse statutes in all circumstances.", "C": "The model is fully legal as long as the membership fee is disclosed to insurers.", "D": "Membership fees reduce access to care for low-income patients but carry no legal concern."}, "correct": "A", "explanation": "Charging a monthly membership fee for enhanced access while simultaneously billing insurance for services rendered during that access creates a potential double-billing problem when the fee covers services that are also being submitted to insurers, particularly Medicare, which has specific anti-balance billing and fraud and abuse provisions. Concierge medicine is not categorically illegal but must be structured carefully to ensure that the membership fee covers only services not billed to insurance, such as extended access time, after-hours calls, and care coordination rather than the clinical services themselves. Failing to properly structure the fee arrangement to avoid billing the same service twice exposes the practice to False Claims Act liability and payer fraud investigations."}, {"id": 974, "domain": "pharmacology", "question": "A 72-year-old man on warfarin for atrial fibrillation is prescribed ciprofloxacin for a complicated UTI. His INR 3 days later is 6.8. He has no active bleeding. Which mechanism explains the supratherapeutic INR?", "options": {"A": "Ciprofloxacin inhibits CYP1A2, reducing warfarin clearance and raising its anticoagulant effect.", "B": "Ciprofloxacin inhibits CYP2C9, reducing S-warfarin metabolism and potentiating anticoagulation.", "C": "Ciprofloxacin eradicates gut flora that produce vitamin K, reducing clotting factor synthesis.", "D": "Ciprofloxacin displaces warfarin from plasma protein binding sites, increasing free drug levels."}, "correct": "C", "explanation": "Fluoroquinolones such as ciprofloxacin reduce gut flora that produce vitamin K2 through bacterial synthesis in the colon, which decreases the availability of vitamin K for clotting factor synthesis and potentiates the anticoagulant effect of warfarin. This mechanism is particularly relevant for patients on warfarin because any reduction in vitamin K production shifts the balance toward anticoagulation and can rapidly elevate the INR. When a patient on warfarin starts a fluoroquinolone, INR should be checked within 3 to 5 days and the warfarin dose may need to be reduced to maintain therapeutic range."}, {"id": 977, "domain": "pharmacology", "question": "A 44-year-old woman with rheumatoid arthritis is on methotrexate 20 mg weekly. She develops a new productive cough and dyspnea over 3 weeks. Chest X-ray shows bilateral interstitial infiltrates. She has no fever and sputum culture is negative. Which action is most appropriate?", "options": {"A": "Start azithromycin because atypical pneumonia is the most common cause of bilateral infiltrates.", "B": "Immediately discontinue methotrexate and initiate corticosteroids for suspected pneumonitis.", "C": "Add trimethoprim-sulfamethoxazole for PCP prophylaxis because the infiltrates indicate opportunistic infection.", "D": "Order BAL bronchoscopy first before stopping methotrexate to confirm the diagnosis."}, "correct": "B", "explanation": "Methotrexate pneumonitis is a serious drug-induced lung toxicity presenting as bilateral interstitial infiltrates, dyspnea, and cough without fever or infectious etiology, and the cornerstone of management is immediate discontinuation of methotrexate combined with systemic corticosteroids to suppress the inflammatory response. Continuing methotrexate while pursuing additional workup risks progression to respiratory failure, and the clinical and radiographic picture in this patient is sufficiently characteristic to act without awaiting bronchoscopy results. Atypical pneumonia is unlikely without fever and with a negative sputum culture in a patient on an immunosuppressive agent known to cause pulmonary toxicity."}, {"id": 978, "domain": "pharmacology", "question": "A 30-year-old woman with isotretinoin therapy for severe nodulocystic acne presents for her monthly visit. Her last two urine pregnancy tests were negative. She informs you she had unprotected intercourse 5 days ago. Her next menstrual period is due in 2 weeks. Which action is required under the iPLEDGE program?", "options": {"A": "Continue isotretinoin and retest pregnancy in 4 weeks at her next scheduled appointment.", "B": "Discontinue isotretinoin immediately and refer to obstetrics for pregnancy counseling.", "C": "Provide emergency contraception and retest for pregnancy in 4 weeks before dispensing refill.", "D": "Order serum beta-hCG now and hold the refill until results confirm she is not pregnant."}, "correct": "C", "explanation": "Under the iPLEDGE program, when a patient on isotretinoin reports unprotected intercourse, the clinician should provide or recommend emergency contraception to prevent pregnancy and schedule a repeat pregnancy test at the next monthly visit (approximately 4 weeks later) before dispensing the next prescription refill. Isotretinoin is a Category X teratogen, and the iPLEDGE requirements mandate two forms of contraception and monthly pregnancy testing with a negative result before each prescription fill. Continuing the prescription without addressing the contraception gap or ordering an immediate serum hCG alone does not fully satisfy the protocol requirements for preventing fetal exposure."}, {"id": 981, "domain": "pharmacology", "question": "A 68-year-old man with type 2 diabetes controlled on metformin is started on prednisone 40 mg daily for a COPD exacerbation. His morning fasting glucose is 142 mg/dL but afternoon readings consistently exceed 280 mg/dL. Which insulin strategy best addresses the steroid-induced hyperglycemia pattern?", "options": {"A": "Add NPH insulin in the morning because its action profile matches the afternoon glucose peak.", "B": "Start a basal insulin at bedtime to control the overnight fasting glucose elevation.", "C": "Add a rapid-acting insulin at breakfast only to blunt the post-prandial glucose rise.", "D": "Switch metformin to a sulfonylurea because it stimulates insulin release throughout the day."}, "correct": "A", "explanation": "Prednisone causes hyperglycemia that peaks in the afternoon and evening because its glucocorticoid effect on hepatic glucose production and insulin resistance is maximal 4 to 8 hours after a morning dose, and NPH insulin given in the morning matches this pharmacodynamic profile with its action peak at 4 to 8 hours. A bedtime basal insulin would address overnight fasting glucose, not the afternoon hyperglycemia that is the predominant pattern in steroid-induced diabetes from morning prednisone dosing. Switching to a sulfonylurea would not provide targeted coverage for the predictable afternoon glucose peak that characterizes morning corticosteroid use."}, {"id": 984, "domain": "pharmacology", "question": "A 66-year-old man with atrial fibrillation on apixaban 5 mg twice daily needs urgent hip fracture surgery in 8 hours. He took his last dose 6 hours ago. Renal function is normal (eGFR 72). Which is the most appropriate management of his anticoagulation perioperatively?", "options": {"A": "Administer andexanet alfa to reverse apixaban before surgery proceeds in 8 hours.", "B": "Proceed with surgery after 24 hours because apixaban has an 8 to 12 hour half-life.", "C": "Administer vitamin K to reverse the anticoagulant effect of apixaban before surgery.", "D": "Proceed with surgery now with anesthesia and surgical team aware of anticoagulation status."}, "correct": "B", "explanation": "Apixaban has a half-life of approximately 8 to 12 hours in patients with normal renal function, and with the last dose taken 6 hours before the decision point, waiting a total of 24 hours from the last dose allows for approximately two half-lives of drug clearance, substantially reducing the bleeding risk for a hip fracture repair procedure. Andexanet alfa is an option for emergent reversal when surgery cannot be safely delayed, but for a fracture repair that can reasonably be deferred several hours, allowing pharmacological clearance is preferable. Vitamin K has no role in reversing direct oral anticoagulants, as it only addresses vitamin K-dependent factor deficiency caused by warfarin."}, {"id": 988, "domain": "pharmacology", "question": "A 44-year-old man with a DOAC (rivaroxaban 20 mg daily) needs emergency appendectomy in 2 hours. He took his last dose 14 hours ago. Which perioperative management is most appropriate?", "options": {"A": "Administer andexanet alfa immediately because any DOAC level increases bleeding risk intraoperatively.", "B": "Proceed with surgery while informing the surgical team because most emergencies require operating despite anticoagulation.", "C": "Reverse with 4-factor PCC (prothrombin complex concentrate) if rapid reversal is required.", "D": "Delay surgery to 48 hours because rivaroxaban has an 18-hour half-life and must clear fully."}, "correct": "C", "explanation": "For emergency surgery requiring rapid anticoagulation reversal in a patient on rivaroxaban, four-factor prothrombin complex concentrate is the recommended reversal agent because it rapidly replaces the coagulation factors inhibited by rivaroxaban and restores hemostasis within minutes. Andexanet alfa is FDA-approved specifically for factor Xa inhibitor reversal but is not universally available, is more expensive, and carries a risk of thrombotic complications, making 4-factor PCC the more accessible first-line reversal option in urgent surgical settings. Delaying surgery for 48 hours is not appropriate for emergency appendectomy, and proceeding without any reversal when the patient took rivaroxaban 14 hours ago with residual drug activity would increase intraoperative and postoperative bleeding risk."}, {"id": 993, "domain": "pharmacology", "question": "A 55-year-old man on clozapine for treatment-resistant schizophrenia is prescribed ciprofloxacin for a complicated UTI. His psychiatrist requests monitoring. Which interaction warrants close attention in this patient?", "options": {"A": "Ciprofloxacin inhibits CYP1A2, increasing clozapine plasma levels and risk of seizure and agranulocytosis.", "B": "Ciprofloxacin and clozapine both prolong the QTc interval, increasing the risk of arrhythmia.", "C": "Ciprofloxacin causes bone marrow suppression that adds to clozapine's agranulocytosis risk.", "D": "Ciprofloxacin reduces clozapine efficacy through competitive serotonin receptor blockade."}, "correct": "A", "explanation": "Ciprofloxacin is a significant inhibitor of CYP1A2, which is the primary enzyme responsible for clozapine metabolism, and co-administration can raise clozapine plasma levels by 50 to 100 percent, dramatically increasing the risk of clozapine toxicity including sedation, seizures, and agranulocytosis. This interaction requires close monitoring of clozapine levels and symptoms during any course of ciprofloxacin, and the clozapine dose should be reduced prophylactically or an alternative antibiotic should be selected when possible. Clozapine's narrow therapeutic index makes pharmacokinetic interactions through CYP1A2 inhibition particularly dangerous compared to drugs with wider safety margins."}, {"id": 996, "domain": "pharmacology", "question": "A 52-year-old woman with bipolar I disorder stable on lithium is found to have a new DVT. Her nephrologist wants to start anticoagulation. She has CKD stage 3 (eGFR 44 mL/min). Which anticoagulant consideration is most important in this patient?", "options": {"A": "Start warfarin because lithium interacts with most DOACs through renal transporter competition.", "B": "Use rivaroxaban but reduce to 15 mg daily because the eGFR requires dose adjustment for DVT.", "C": "Avoid all anticoagulants because lithium increases bleeding risk through platelet inhibition.", "D": "Use apixaban at standard DVT dosing and monitor lithium levels because NSAIDs for pain may affect both."}, "correct": "D", "explanation": "Apixaban at standard DVT dosing does not require dose adjustment at an eGFR of 44 mL/min, as dose reduction is only considered when two of three criteria are met (age 80 or older, weight 60 kg or less, or creatinine 1.5 mg/dL or greater), and this patient meets none of those criteria. Lithium levels should be monitored carefully during anticoagulation therapy because any NSAIDs used for pain management can increase lithium levels by reducing renal clearance, creating a secondary drug interaction concern. Warfarin's INR management in a patient also requiring mood stabilization and potential NSAID use creates additional complexity compared to apixaban, which has fewer drug-drug interactions in this clinical context."}];
